//! SIMD math kernels for the gnosis Rust mesh: f16 conversion, dequantization
//! of llama.cpp k-quants (Q4_K, Q6_K, Q8_0, …) and quantized matvec routines.
//!
//! References:
//!   - GGUF k-quant block formats: github.com/ggerganov/llama.cpp
//!     (Q4_K / Q6_K dequantize_q*_row, mat_vec_q*_*).
//!   - GGUF spec: github.com/ggerganov/ggml.

use gnosis_frf::prelude::*;
#[cfg(target_arch = "aarch64")]
use std::arch::aarch64::*;

const RAYON_THRESHOLD: usize = 256;
const Q4K_PAR_CHUNK_ROWS: usize = 32;
#[cfg(target_arch = "aarch64")]
const Q5_HIGH_BIT_MASKS_LO: [u16; 8] = [1, 2, 4, 8, 16, 32, 64, 128];
#[cfg(target_arch = "aarch64")]
const Q5_HIGH_BIT_MASKS_HI: [u16; 8] = [256, 512, 1024, 2048, 4096, 8192, 16384, 32768];

#[inline(always)]
fn active_mask_block(block_mask: &[u8], block: usize) -> bool {
    block_mask.get(block).copied().unwrap_or(1) != 0
}

#[inline(always)]
fn block_mask_has_skips(block_mask: &[u8], blocks_per_row: usize) -> bool {
    (0..blocks_per_row).any(|block| !active_mask_block(block_mask, block))
}

pub fn f16_to_f32(h: u16) -> f32 {
    let s = (h as u32 & 0x8000) << 16;
    let e = (h as u32 & 0x7c00) >> 10;
    let f = h as u32 & 0x03ff;
    if e == 0 {
        if f == 0 {
            return f32::from_bits(s);
        }
        let mut f = f;
        let mut e_off = 0;
        while f & 0x400 == 0 {
            f <<= 1;
            e_off += 1;
        }
        return f32::from_bits(s | (((127 - 15 - e_off + 1) as u32) << 23) | ((f & 0x3ff) << 13));
    }
    if e == 31 {
        return f32::from_bits(s | 0x7f800000 | (f << 13));
    }
    f32::from_bits(s | ((e + 127 - 15) << 23) | (f << 13))
}

fn get_scale_min_k4(j: usize, scales: &[u8]) -> (f32, f32) {
    if j < 4 {
        ((scales[j] & 63) as f32, (scales[j + 4] & 63) as f32)
    } else {
        (
            ((scales[j + 4] & 0xf) | ((scales[j - 4] >> 6) << 4)) as f32,
            ((scales[j + 4] >> 4) | ((scales[j] >> 6) << 4)) as f32,
        )
    }
}

/// Public alias for `get_scale_min_k4`. Exposes the K-quant scale/min
/// unpacking helper so sibling modules (model_phi3 Q5_K dequantizer)
/// can reuse it without duplicating the bit-twiddling.
#[inline]
pub fn get_scale_min_k4_pub(j: usize, scales: &[u8]) -> (f32, f32) {
    get_scale_min_k4(j, scales)
}

pub fn dequantize_q4k_row(out: &mut [f32], w: &[u8], row_idx: usize, d: usize) {
    let bpr = d / 256;
    let row_ptr = unsafe { w.as_ptr().add(row_idx * bpr * 144) };
    for b in 0..bpr {
        let bp = unsafe { row_ptr.add(b * 144) };
        let o = b * 256;
        let d_val = unsafe { f16_to_f32(u16::from_le_bytes([*bp, *bp.add(1)])) };
        let dmin = unsafe { f16_to_f32(u16::from_le_bytes([*bp.add(2), *bp.add(3)])) };
        let scales = unsafe { std::slice::from_raw_parts(bp.add(4), 12) };
        let qs = unsafe { std::slice::from_raw_parts(bp.add(16), 128) };
        for j in (0..256).step_by(64) {
            let (sc1, m1) = get_scale_min_k4(j / 32, scales);
            let (sc2, m2) = get_scale_min_k4(j / 32 + 1, scales);
            let qb = (j / 64) * 32;
            for l in 0..32 {
                out[o + j + l] = d_val * sc1 * (qs[qb + l] & 0xf) as f32 - dmin * m1;
                out[o + j + 32 + l] = d_val * sc2 * (qs[qb + l] >> 4) as f32 - dmin * m2;
            }
        }
    }
}

pub fn dequantize_q6k_row(out: &mut [f32], w: &[u8], row_idx: usize, d: usize) {
    let bpr = d / 256;
    let row_ptr = unsafe { w.as_ptr().add(row_idx * bpr * 210) };
    for b in 0..bpr {
        let bp = unsafe { row_ptr.add(b * 210) };
        let o = b * 256;
        let ql = unsafe { std::slice::from_raw_parts(bp, 128) };
        let qh = unsafe { std::slice::from_raw_parts(bp.add(128), 64) };
        let sc = unsafe { std::slice::from_raw_parts(bp.add(192) as *const i8, 16) };
        let d_val = unsafe { f16_to_f32(u16::from_le_bytes([*bp.add(208), *bp.add(209)])) };
        for group in 0..2 {
            let ns = group * 128;
            let qls = &ql[group * 64..(group + 1) * 64];
            let qhs = &qh[group * 32..(group + 1) * 32];
            let scs = &sc[group * 8..(group + 1) * 8];
            for l in 0..32 {
                let is = l / 16;
                let q1 = ((qls[l] & 0xf) | ((qhs[l] & 3) << 4)) as i32 - 32;
                let q2 = ((qls[l + 32] & 0xf) | (((qhs[l] >> 2) & 3) << 4)) as i32 - 32;
                let q3 = ((qls[l] >> 4) | (((qhs[l] >> 4) & 3) << 4)) as i32 - 32;
                let q4 = ((qls[l + 32] >> 4) | (((qhs[l] >> 6) & 3) << 4)) as i32 - 32;
                out[o + ns + l] = d_val * (scs[is] as f32) * (q1 as f32);
                out[o + ns + l + 32] = d_val * (scs[is + 2] as f32) * (q2 as f32);
                out[o + ns + l + 64] = d_val * (scs[is + 4] as f32) * (q3 as f32);
                out[o + ns + l + 96] = d_val * (scs[is + 6] as f32) * (q4 as f32);
            }
        }
    }
}

pub fn dequantize_q5_0_row(out: &mut [f32], w: &[u8], row_idx: usize, d: usize) {
    let blocks_per_row = d.div_ceil(32);
    let row_ptr = unsafe { w.as_ptr().add(row_idx * blocks_per_row * 22) };
    for b in 0..blocks_per_row {
        let bp = unsafe { row_ptr.add(b * 22) };
        let o = b * 32;
        let d_val = unsafe { f16_to_f32(u16::from_le_bytes([*bp, *bp.add(1)])) };
        let qh = unsafe {
            (*bp.add(2) as u32)
                | ((*bp.add(3) as u32) << 8)
                | ((*bp.add(4) as u32) << 16)
                | ((*bp.add(5) as u32) << 24)
        };
        let qs = unsafe { std::slice::from_raw_parts(bp.add(6), 16) };
        for j in 0..16 {
            let idx0 = o + j;
            let idx1 = o + j + 16;
            let xh0 = (((qh >> j) << 4) & 0x10) as i32;
            let xh1 = (((qh >> (j + 16)) << 4) & 0x10) as i32;
            let q = qs[j];
            if idx0 < d {
                out[idx0] = d_val * (((q & 0x0f) as i32 | xh0) - 16) as f32;
            }
            if idx1 < d {
                out[idx1] = d_val * (((q >> 4) as i32 | xh1) - 16) as f32;
            }
        }
    }
}

/// Dequantize a Q8_0 tensor packed as a SINGLE flat stream of 32-element blocks
/// (34 bytes/block: f16 scale + 32 i8 quants), with NO per-row padding. Blocks
/// may span logical row boundaries. Returns the first `total` dequantized values.
pub fn dequantize_q8_0_flat(w: &[u8], total: usize) -> Vec<f32> {
    let mut out = vec![0.0f32; total];
    let blocks = total.div_ceil(32);
    for b in 0..blocks {
        let bp = b * 34;
        if bp + 34 > w.len() {
            break;
        }
        let d_val = f16_to_f32(u16::from_le_bytes([w[bp], w[bp + 1]]));
        for j in 0..32 {
            let idx = b * 32 + j;
            if idx < total {
                out[idx] = d_val * (w[bp + 2 + j] as i8) as f32;
            }
        }
    }
    out
}

pub fn dequantize_q8_0_row(out: &mut [f32], w: &[u8], row_idx: usize, d: usize) {
    let blocks_per_row = d.div_ceil(32);
    let row_ptr = unsafe { w.as_ptr().add(row_idx * blocks_per_row * 34) };
    for b in 0..blocks_per_row {
        let bp = unsafe { row_ptr.add(b * 34) };
        let o = b * 32;
        let d_val = unsafe { f16_to_f32(u16::from_le_bytes([*bp, *bp.add(1)])) };
        let qs = unsafe { std::slice::from_raw_parts(bp.add(2) as *const i8, 32) };
        for j in 0..32 {
            let idx = o + j;
            if idx < d {
                out[idx] = d_val * qs[j] as f32;
            }
        }
    }
}

// ── NEON dot product ─────────────────────────────────────────────────

#[cfg(target_arch = "aarch64")]
#[inline(always)]
pub fn dot_product(a: &[f32], b: &[f32]) -> f32 {
    let n = a.len();
    let chunks = n / 16;
    let rem = n % 16;
    unsafe {
        let mut acc0 = vdupq_n_f32(0.0);
        let mut acc1 = vdupq_n_f32(0.0);
        let mut acc2 = vdupq_n_f32(0.0);
        let mut acc3 = vdupq_n_f32(0.0);
        let ap = a.as_ptr();
        let bp = b.as_ptr();
        for i in 0..chunks {
            let off = i * 16;
            acc0 = vfmaq_f32(acc0, vld1q_f32(ap.add(off)), vld1q_f32(bp.add(off)));
            acc1 = vfmaq_f32(acc1, vld1q_f32(ap.add(off + 4)), vld1q_f32(bp.add(off + 4)));
            acc2 = vfmaq_f32(acc2, vld1q_f32(ap.add(off + 8)), vld1q_f32(bp.add(off + 8)));
            acc3 = vfmaq_f32(
                acc3,
                vld1q_f32(ap.add(off + 12)),
                vld1q_f32(bp.add(off + 12)),
            );
        }
        let sum_vec = vaddq_f32(vaddq_f32(acc0, acc1), vaddq_f32(acc2, acc3));
        let mut s = vaddvq_f32(sum_vec);
        let base = chunks * 16;
        for i in 0..rem {
            s += *ap.add(base + i) * *bp.add(base + i);
        }
        s
    }
}

// ── wasm32 SIMD dot product ──────────────────────────────────────────
// Mirrors the NEON path: 4× f32x4 accumulators with 16-wide unroll,
// horizontal reduction at the end. Split-a Fix A (post-SIMD
// bottleneck investigation): this single function accounts for ~16.8M
// scalar FLOPs per layer at pos=1024 on gemma4-31b.
#[cfg(target_arch = "wasm32")]
#[inline(always)]
pub fn dot_product(a: &[f32], b: &[f32]) -> f32 {
    use std::arch::wasm32::*;
    let n = a.len();
    let chunks = n / 16;
    let rem = n % 16;
    unsafe {
        let mut acc0 = f32x4_splat(0.0);
        let mut acc1 = f32x4_splat(0.0);
        let mut acc2 = f32x4_splat(0.0);
        let mut acc3 = f32x4_splat(0.0);
        let ap = a.as_ptr();
        let bp = b.as_ptr();
        for i in 0..chunks {
            let off = i * 16;
            let a0 = v128_load(ap.add(off) as *const v128);
            let b0 = v128_load(bp.add(off) as *const v128);
            acc0 = f32x4_add(acc0, f32x4_mul(a0, b0));
            let a1 = v128_load(ap.add(off + 4) as *const v128);
            let b1 = v128_load(bp.add(off + 4) as *const v128);
            acc1 = f32x4_add(acc1, f32x4_mul(a1, b1));
            let a2 = v128_load(ap.add(off + 8) as *const v128);
            let b2 = v128_load(bp.add(off + 8) as *const v128);
            acc2 = f32x4_add(acc2, f32x4_mul(a2, b2));
            let a3 = v128_load(ap.add(off + 12) as *const v128);
            let b3 = v128_load(bp.add(off + 12) as *const v128);
            acc3 = f32x4_add(acc3, f32x4_mul(a3, b3));
        }
        let sum_v = f32x4_add(f32x4_add(acc0, acc1), f32x4_add(acc2, acc3));
        let mut s = f32x4_extract_lane::<0>(sum_v)
            + f32x4_extract_lane::<1>(sum_v)
            + f32x4_extract_lane::<2>(sum_v)
            + f32x4_extract_lane::<3>(sum_v);
        let base = chunks * 16;
        for i in 0..rem {
            s += *ap.add(base + i) * *bp.add(base + i);
        }
        s
    }
}

// ── x86_64 SIMD dot product (AVX2+FMA, runtime-detected) ─────────────
// LLVM will NOT auto-vectorize the sequential f32 reduction below (FP add is
// non-associative), so even `-C target-cpu=x86-64-v3` leaves it scalar — the
// single biggest cost in every mat_vec on the CPU mesh nodes. This explicit
// AVX2 path (8-wide ×2 accumulators, 16-wide unroll mirroring the NEON path)
// is gated by runtime feature detection, so non-AVX2 x86 still runs the exact
// scalar fallback (no SIGILL). The aarch64/wasm SIMD paths already reassociate;
// this matches that numerically (cosine ~0.9999 vs the reference).
#[cfg(target_arch = "x86_64")]
#[inline(always)]
pub fn dot_product(a: &[f32], b: &[f32]) -> f32 {
    if is_x86_feature_detected!("avx2") && is_x86_feature_detected!("fma") {
        unsafe { dot_product_avx2(a, b) }
    } else {
        a.iter().zip(b.iter()).map(|(a, b)| a * b).sum()
    }
}

#[cfg(target_arch = "x86_64")]
#[target_feature(enable = "avx2,fma")]
unsafe fn dot_product_avx2(a: &[f32], b: &[f32]) -> f32 {
    use std::arch::x86_64::*;
    let n = a.len();
    let chunks = n / 32;
    let rem16 = (n % 32) / 16;
    let ap = a.as_ptr();
    let bp = b.as_ptr();
    // Four independent accumulators: FMA latency is 4-5 cycles at 2/cycle
    // throughput, so 2 chains left the pipes >2× under-fed. 32-wide body.
    let mut acc0 = _mm256_setzero_ps();
    let mut acc1 = _mm256_setzero_ps();
    let mut acc2 = _mm256_setzero_ps();
    let mut acc3 = _mm256_setzero_ps();
    for i in 0..chunks {
        let off = i * 32;
        acc0 = _mm256_fmadd_ps(_mm256_loadu_ps(ap.add(off)), _mm256_loadu_ps(bp.add(off)), acc0);
        acc1 = _mm256_fmadd_ps(
            _mm256_loadu_ps(ap.add(off + 8)),
            _mm256_loadu_ps(bp.add(off + 8)),
            acc1,
        );
        acc2 = _mm256_fmadd_ps(
            _mm256_loadu_ps(ap.add(off + 16)),
            _mm256_loadu_ps(bp.add(off + 16)),
            acc2,
        );
        acc3 = _mm256_fmadd_ps(
            _mm256_loadu_ps(ap.add(off + 24)),
            _mm256_loadu_ps(bp.add(off + 24)),
            acc3,
        );
    }
    if rem16 == 1 {
        let off = chunks * 32;
        acc0 = _mm256_fmadd_ps(_mm256_loadu_ps(ap.add(off)), _mm256_loadu_ps(bp.add(off)), acc0);
        acc1 = _mm256_fmadd_ps(
            _mm256_loadu_ps(ap.add(off + 8)),
            _mm256_loadu_ps(bp.add(off + 8)),
            acc1,
        );
    }
    // horizontal sum of the 8 lanes of (acc0 + acc1 + acc2 + acc3)
    let sum = _mm256_add_ps(_mm256_add_ps(acc0, acc1), _mm256_add_ps(acc2, acc3));
    let lo = _mm256_castps256_ps128(sum);
    let hi = _mm256_extractf128_ps(sum, 1);
    let q = _mm_add_ps(lo, hi);
    let shuf = _mm_movehdup_ps(q);
    let sums = _mm_add_ps(q, shuf);
    let shuf2 = _mm_movehl_ps(shuf, sums);
    let sums = _mm_add_ss(sums, shuf2);
    let mut s = _mm_cvtss_f32(sums);
    let base = chunks * 32 + rem16 * 16;
    for i in 0..(n % 16) {
        s += *ap.add(base + i) * *bp.add(base + i);
    }
    s
}

#[cfg(not(any(target_arch = "aarch64", target_arch = "wasm32", target_arch = "x86_64")))]
#[inline(always)]
pub fn dot_product(a: &[f32], b: &[f32]) -> f32 {
    a.iter().zip(b.iter()).map(|(a, b)| a * b).sum()
}

pub fn cosine_similarity(a: &[f32], b: &[f32]) -> f32 {
    let mut dot = 0.0;
    let mut norm_a = 0.0;
    let mut norm_b = 0.0;
    for i in 0..a.len() {
        dot += a[i] * b[i];
        norm_a += a[i] * a[i];
        norm_b += b[i] * b[i];
    }
    if norm_a == 0.0 || norm_b == 0.0 {
        return 0.0;
    }
    dot / (norm_a.sqrt() * norm_b.sqrt())
}

// ── NEON accumulate weighted ─────────────────────────────────────────

#[cfg(target_arch = "aarch64")]
#[inline(always)]
pub fn accumulate_weighted(out: &mut [f32], src: &[f32], weight: f32) {
    let n = out.len();
    unsafe {
        let w = vdupq_n_f32(weight);
        let mut i = 0usize;
        while i + 16 <= n {
            let o0 = vld1q_f32(out.as_ptr().add(i));
            let o1 = vld1q_f32(out.as_ptr().add(i + 4));
            let o2 = vld1q_f32(out.as_ptr().add(i + 8));
            let o3 = vld1q_f32(out.as_ptr().add(i + 12));
            vst1q_f32(
                out.as_mut_ptr().add(i),
                vfmaq_f32(o0, vld1q_f32(src.as_ptr().add(i)), w),
            );
            vst1q_f32(
                out.as_mut_ptr().add(i + 4),
                vfmaq_f32(o1, vld1q_f32(src.as_ptr().add(i + 4)), w),
            );
            vst1q_f32(
                out.as_mut_ptr().add(i + 8),
                vfmaq_f32(o2, vld1q_f32(src.as_ptr().add(i + 8)), w),
            );
            vst1q_f32(
                out.as_mut_ptr().add(i + 12),
                vfmaq_f32(o3, vld1q_f32(src.as_ptr().add(i + 12)), w),
            );
            i += 16;
        }
        while i < n {
            *out.get_unchecked_mut(i) += weight * *src.get_unchecked(i);
            i += 1;
        }
    }
}

// ── wasm32 SIMD accumulate weighted ─────────────────────────────────
// Mirrors the NEON path: splat weight into f32x4, then 16-wide FMA
// unroll. Split-a Fix A: this function accounts for ~16.8M scalar
// FLOPs per layer at pos=1024 on gemma4-31b (the A@V accumulation).
#[cfg(target_arch = "wasm32")]
#[inline(always)]
pub fn accumulate_weighted(out: &mut [f32], src: &[f32], weight: f32) {
    use std::arch::wasm32::*;
    let n = out.len();
    unsafe {
        let w = f32x4_splat(weight);
        let mut i = 0usize;
        while i + 16 <= n {
            let o0 = v128_load(out.as_ptr().add(i) as *const v128);
            let s0 = v128_load(src.as_ptr().add(i) as *const v128);
            v128_store(
                out.as_mut_ptr().add(i) as *mut v128,
                f32x4_add(o0, f32x4_mul(s0, w)),
            );
            let o1 = v128_load(out.as_ptr().add(i + 4) as *const v128);
            let s1 = v128_load(src.as_ptr().add(i + 4) as *const v128);
            v128_store(
                out.as_mut_ptr().add(i + 4) as *mut v128,
                f32x4_add(o1, f32x4_mul(s1, w)),
            );
            let o2 = v128_load(out.as_ptr().add(i + 8) as *const v128);
            let s2 = v128_load(src.as_ptr().add(i + 8) as *const v128);
            v128_store(
                out.as_mut_ptr().add(i + 8) as *mut v128,
                f32x4_add(o2, f32x4_mul(s2, w)),
            );
            let o3 = v128_load(out.as_ptr().add(i + 12) as *const v128);
            let s3 = v128_load(src.as_ptr().add(i + 12) as *const v128);
            v128_store(
                out.as_mut_ptr().add(i + 12) as *mut v128,
                f32x4_add(o3, f32x4_mul(s3, w)),
            );
            i += 16;
        }
        while i < n {
            *out.get_unchecked_mut(i) += weight * *src.get_unchecked(i);
            i += 1;
        }
    }
}

// ── x86_64 accumulate weighted (AVX2+FMA, runtime-detected) ─────────
// Mirrors the NEON path. This is the decode A·V accumulation — per past
// position per head per layer — and it ran scalar on Cloud Run (x86)
// while aarch64/wasm were both vectorized.
#[cfg(target_arch = "x86_64")]
#[inline(always)]
pub fn accumulate_weighted(out: &mut [f32], src: &[f32], weight: f32) {
    if is_x86_feature_detected!("avx2") && is_x86_feature_detected!("fma") {
        unsafe { accumulate_weighted_avx2(out, src, weight) }
    } else {
        for i in 0..out.len() {
            out[i] += weight * src[i];
        }
    }
}

#[cfg(target_arch = "x86_64")]
#[target_feature(enable = "avx2,fma")]
unsafe fn accumulate_weighted_avx2(out: &mut [f32], src: &[f32], weight: f32) {
    use std::arch::x86_64::*;
    let n = out.len();
    let w = _mm256_set1_ps(weight);
    let op = out.as_mut_ptr();
    let sp = src.as_ptr();
    let mut i = 0usize;
    while i + 16 <= n {
        let o0 = _mm256_loadu_ps(op.add(i));
        let o1 = _mm256_loadu_ps(op.add(i + 8));
        _mm256_storeu_ps(op.add(i), _mm256_fmadd_ps(_mm256_loadu_ps(sp.add(i)), w, o0));
        _mm256_storeu_ps(
            op.add(i + 8),
            _mm256_fmadd_ps(_mm256_loadu_ps(sp.add(i + 8)), w, o1),
        );
        i += 16;
    }
    while i < n {
        *out.get_unchecked_mut(i) += weight * *src.get_unchecked(i);
        i += 1;
    }
}

#[cfg(not(any(target_arch = "aarch64", target_arch = "wasm32", target_arch = "x86_64")))]
#[inline(always)]
pub fn accumulate_weighted(out: &mut [f32], src: &[f32], weight: f32) {
    for i in 0..out.len() {
        out[i] += weight * src[i];
    }
}

// ── Q4_K mat-vec with NEON ───────────────────────────────────────────

#[inline(always)]
#[allow(clippy::not_unsafe_ptr_arg_deref)]
pub fn mat_vec_q4k_row_batch(
    xs: &[&[f32]],
    row_ptr: *const u8,
    blocks_per_row: usize,
    results: &mut [f32],
) {
    let n_batch = xs.len();
    #[cfg(target_arch = "aarch64")]
    unsafe {
        use std::arch::aarch64::*;
        // 64 accumulators matches BATCH_CAPACITY in model_gemma4.rs
        // (native). Pre-fix this was 16, which silently zeroed tokens
        // 16+ in the chunk — `mat_vec_dispatch_batch` would call with
        // n_batch=18 (full prompt prefill), the inner kernel only
        // updated `acc_vs[0..16]`, and tokens [16,17] got `results[i] =
        // 0`. Layer outputs for the last tokens were dropped to zero
        // every layer, so batch_x for those positions stayed at the
        // embedding throughout — gemma4 smoke #6 with seq_len=18
        // showed unchanged residual stats across all 60 layers.
        // MUST cover model.rs BATCH_CAPACITY (128). History: capped at 16
        // (silently zeroed tokens 16+, gemma4 smoke #6), then at 64
        // (silently zeroed positions 64+ for lm_head_all_positions,
        // 2026-07-10, ppl=9.4M garbage). Silent .min() truncation is the
        // trap — assert instead so the next capacity raise fails LOUDLY.
        assert!(
            n_batch <= 128,
            "mat_vec_q4k_row_batch: n_batch {n_batch} exceeds accumulator capacity 128"
        );
        let mut acc_vs = [vdupq_n_f32(0.0); 128];
        let n_acc = n_batch;

        for b in 0..blocks_per_row {
            let bp = row_ptr.add(b * 144);
            let xo = b * 256;
            let d_val = f16_to_f32(u16::from_le_bytes([*bp, *bp.add(1)]));
            let dmin = f16_to_f32(u16::from_le_bytes([*bp.add(2), *bp.add(3)]));
            let scales = std::slice::from_raw_parts(bp.add(4), 12);
            let qs = std::slice::from_raw_parts(bp.add(16), 128);

            for j in (0..256).step_by(64) {
                let (sc1, m1) = get_scale_min_k4(j / 32, scales);
                let (sc2, m2) = get_scale_min_k4(j / 32 + 1, scales);
                let s1v = vdupq_n_f32(d_val * sc1);
                let b1v = vdupq_n_f32(-dmin * m1);
                let s2v = vdupq_n_f32(d_val * sc2);
                let b2v = vdupq_n_f32(-dmin * m2);
                let mask_lo = vdupq_n_u8(0x0f);
                let qb = (j / 64) * 32;

                for l in (0..32).step_by(8) {
                    let raw = vld1_u8(qs.as_ptr().add(qb + l));
                    let lo_u8 = vand_u8(raw, vget_low_u8(mask_lo));
                    let hi_u8 = vshr_n_u8(raw, 4);

                    let lo_u16 = vmovl_u8(lo_u8);
                    let lo0_f32 = vcvtq_f32_u32(vmovl_u16(vget_low_u16(lo_u16)));
                    let lo1_f32 = vcvtq_f32_u32(vmovl_u16(vget_high_u16(lo_u16)));
                    let w1_0 = vfmaq_f32(b1v, s1v, lo0_f32);
                    let w1_1 = vfmaq_f32(b1v, s1v, lo1_f32);

                    let hi_u16 = vmovl_u8(hi_u8);
                    let hi0_f32 = vcvtq_f32_u32(vmovl_u16(vget_low_u16(hi_u16)));
                    let hi1_f32 = vcvtq_f32_u32(vmovl_u16(vget_high_u16(hi_u16)));
                    let w2_0 = vfmaq_f32(b2v, s2v, hi0_f32);
                    let w2_1 = vfmaq_f32(b2v, s2v, hi1_f32);

                    for i in 0..n_acc {
                        let xi = xs[i].as_ptr().add(xo + j + l);
                        let acc0 = vld1q_f32(xi);
                        let acc1 = vld1q_f32(xi.add(4));
                        acc_vs[i] = vfmaq_f32(acc_vs[i], acc0, w1_0);
                        acc_vs[i] = vfmaq_f32(acc_vs[i], acc1, w1_1);

                        let xi2 = xs[i].as_ptr().add(xo + j + 32 + l);
                        let acc2 = vld1q_f32(xi2);
                        let acc3 = vld1q_f32(xi2.add(4));
                        acc_vs[i] = vfmaq_f32(acc_vs[i], acc2, w2_0);
                        acc_vs[i] = vfmaq_f32(acc_vs[i], acc3, w2_1);
                    }
                }
            }
        }
        for i in 0..n_acc {
            results[i] = vaddvq_f32(acc_vs[i]);
        }
    }
    // WASM hot path (the LIVE CF-Workers transformer mesh): the fused matvec above
    // is aarch64 NEON-only, so before this every fleet ran the scalar fallback on
    // wasm. Vectorize the FLOP-heavy multiply-accumulate 4-wide in simd128 (nibble
    // extract stays scalar — cheap mask/shift). Dequant math is identical to the
    // scalar fallback below (w = scale·nibble − dmin·m); sound but reassociated, so
    // certified by the native parity tests (scalar ref) + multi-token qspec golden.
    #[cfg(target_arch = "wasm32")]
    {
        use std::arch::wasm32::*;
        for bi in 0..n_batch {
            let xptr = xs[bi].as_ptr();
            let mut acc = f32x4_splat(0.0);
            for b in 0..blocks_per_row {
                let bp = unsafe { row_ptr.add(b * 144) };
                let xo = b * 256;
                let d_val = unsafe { f16_to_f32(u16::from_le_bytes([*bp, *bp.add(1)])) };
                let dmin = unsafe { f16_to_f32(u16::from_le_bytes([*bp.add(2), *bp.add(3)])) };
                let scales = unsafe { std::slice::from_raw_parts(bp.add(4), 12) };
                let qs = unsafe { bp.add(16) };
                for j in (0..256).step_by(64) {
                    let (sc1, m1) = get_scale_min_k4(j / 32, scales);
                    let (sc2, m2) = get_scale_min_k4(j / 32 + 1, scales);
                    let s1 = f32x4_splat(d_val * sc1);
                    let b1 = f32x4_splat(-dmin * m1);
                    let s2 = f32x4_splat(d_val * sc2);
                    let b2 = f32x4_splat(-dmin * m2);
                    let qb = (j / 64) * 32;
                    let mut l = 0usize;
                    while l < 32 {
                        let q0 = unsafe { *qs.add(qb + l) };
                        let q1 = unsafe { *qs.add(qb + l + 1) };
                        let q2 = unsafe { *qs.add(qb + l + 2) };
                        let q3 = unsafe { *qs.add(qb + l + 3) };
                        // nibble → f32x4 (scalar extract; v128_load from stack array)
                        let lo_a = [(q0 & 0xf) as f32, (q1 & 0xf) as f32, (q2 & 0xf) as f32, (q3 & 0xf) as f32];
                        let hi_a = [(q0 >> 4) as f32, (q1 >> 4) as f32, (q2 >> 4) as f32, (q3 >> 4) as f32];
                        let lo = unsafe { v128_load(lo_a.as_ptr() as *const v128) };
                        let hi = unsafe { v128_load(hi_a.as_ptr() as *const v128) };
                        let w1 = f32x4_add(f32x4_mul(s1, lo), b1);
                        let w2 = f32x4_add(f32x4_mul(s2, hi), b2);
                        let x1 = unsafe { v128_load(xptr.add(xo + j + l) as *const v128) };
                        let x2 = unsafe { v128_load(xptr.add(xo + j + 32 + l) as *const v128) };
                        acc = f32x4_add(acc, f32x4_mul(x1, w1));
                        acc = f32x4_add(acc, f32x4_mul(x2, w2));
                        l += 4;
                    }
                }
            }
            results[bi] += f32x4_extract_lane::<0>(acc) + f32x4_extract_lane::<1>(acc)
                + f32x4_extract_lane::<2>(acc) + f32x4_extract_lane::<3>(acc);
        }
    }
    // x86_64 (Cloud Run CPU / Linux dev): the fused matvec above is aarch64-only,
    // so x86 ran the scalar fallback. Route AVX2+FMA hosts (every modern x86 server)
    // through the 8-wide kernel; non-AVX2 x86 keeps the scalar reference. Runtime
    // detection (not compile-time) so a generic x86 build is portable.
    #[cfg(target_arch = "x86_64")]
    {
        let _ = n_batch;
        if std::is_x86_feature_detected!("avx2") && std::is_x86_feature_detected!("fma") {
            unsafe { q4k_batch_avx2(xs, row_ptr, blocks_per_row, results) }
        } else {
            q4k_batch_scalar(xs, row_ptr, blocks_per_row, results)
        }
    }
    #[cfg(not(any(target_arch = "aarch64", target_arch = "wasm32", target_arch = "x86_64")))]
    {
        let _ = n_batch;
        q4k_batch_scalar(xs, row_ptr, blocks_per_row, results)
    }
}

/// Scalar Q4_K batch matvec — the portable reference, and the runtime fallback for
/// x86 hosts without AVX2/FMA. Dequant `w = scale·nibble − dmin·m` accumulated into
/// pre-zeroed `results`. The numeric source of truth for `q4k_row_matches_kernel`.
/// Only compiled where it's actually called (x86 + the generic fallback); aarch64
/// uses NEON and wasm32 uses simd128 inline.
#[cfg(not(any(target_arch = "aarch64", target_arch = "wasm32")))]
fn q4k_batch_scalar(
    xs: &[&[f32]],
    row_ptr: *const u8,
    blocks_per_row: usize,
    results: &mut [f32],
) {
    let n_batch = xs.len();
    for b in 0..blocks_per_row {
        let bp = unsafe { row_ptr.add(b * 144) };
        let xo = b * 256;
        let d_val = unsafe { f16_to_f32(u16::from_le_bytes([*bp, *bp.add(1)])) };
        let dmin = unsafe { f16_to_f32(u16::from_le_bytes([*bp.add(2), *bp.add(3)])) };
        let scales = unsafe { std::slice::from_raw_parts(bp.add(4), 12) };
        let qs = unsafe { std::slice::from_raw_parts(bp.add(16), 128) };

        for j in (0..256).step_by(64) {
            let (sc1, m1) = get_scale_min_k4(j / 32, scales);
            let (sc2, m2) = get_scale_min_k4(j / 32 + 1, scales);
            let s1 = d_val * sc1;
            let b1 = -dmin * m1;
            let s2 = d_val * sc2;
            let b2 = -dmin * m2;
            let qb = (j / 64) * 32;

            for l in 0..32 {
                let qv = unsafe { *qs.get_unchecked(qb + l) };
                let w1 = s1 * (qv & 0xf) as f32 + b1;
                let w2 = s2 * (qv >> 4) as f32 + b2;
                for i in 0..n_batch {
                    unsafe {
                        results[i] += *xs[i].get_unchecked(xo + j + l) * w1;
                        results[i] += *xs[i].get_unchecked(xo + j + 32 + l) * w2;
                    }
                }
            }
        }
    }
}

/// AVX2+FMA Q4_K batch matvec (x86_64) — 8-wide FMA over `dequant · x`, mirroring the
/// NEON path. Nibbles are extracted scalar into a stack array then `loadu`'d (cheap vs
/// the FLOP-heavy accumulate); dequant math is identical to `q4k_batch_scalar`
/// (`w = scale·nibble − dmin·m`). Sound but reassociated — certified by the native
/// `q4k_row_matches_kernel` parity test (which runs this path on an AVX2 host).
#[cfg(target_arch = "x86_64")]
#[target_feature(enable = "avx2,fma")]
unsafe fn q4k_batch_avx2(
    xs: &[&[f32]],
    row_ptr: *const u8,
    blocks_per_row: usize,
    results: &mut [f32],
) {
    use std::arch::x86_64::*;
    let n_batch = xs.len();
    // See the NEON twin above: silent truncation at 16 then 64 caused two
    // real silent-corruption bugs. Assert loudly instead.
    assert!(
        n_batch <= 128,
        "mat_vec_q4k_row_batch(avx2): n_batch {n_batch} exceeds accumulator capacity 128"
    );
    let n_acc = n_batch;
    let mut acc = [_mm256_setzero_ps(); 128];

    for b in 0..blocks_per_row {
        let bp = row_ptr.add(b * 144);
        let xo = b * 256;
        let d_val = f16_to_f32(u16::from_le_bytes([*bp, *bp.add(1)]));
        let dmin = f16_to_f32(u16::from_le_bytes([*bp.add(2), *bp.add(3)]));
        let scales = std::slice::from_raw_parts(bp.add(4), 12);
        let qs = std::slice::from_raw_parts(bp.add(16), 128);

        for j in (0..256).step_by(64) {
            let (sc1, m1) = get_scale_min_k4(j / 32, scales);
            let (sc2, m2) = get_scale_min_k4(j / 32 + 1, scales);
            let s1v = _mm256_set1_ps(d_val * sc1);
            let b1v = _mm256_set1_ps(-dmin * m1);
            let s2v = _mm256_set1_ps(d_val * sc2);
            let b2v = _mm256_set1_ps(-dmin * m2);
            let qb = (j / 64) * 32;

            let mut l = 0usize;
            while l < 32 {
                let mut lo_a = [0.0f32; 8];
                let mut hi_a = [0.0f32; 8];
                for k in 0..8 {
                    let qv = *qs.get_unchecked(qb + l + k);
                    lo_a[k] = (qv & 0x0f) as f32;
                    hi_a[k] = (qv >> 4) as f32;
                }
                let lo = _mm256_loadu_ps(lo_a.as_ptr());
                let hi = _mm256_loadu_ps(hi_a.as_ptr());
                let w1 = _mm256_fmadd_ps(s1v, lo, b1v);
                let w2 = _mm256_fmadd_ps(s2v, hi, b2v);
                for i in 0..n_acc {
                    let x1 = _mm256_loadu_ps(xs[i].as_ptr().add(xo + j + l));
                    acc[i] = _mm256_fmadd_ps(x1, w1, acc[i]);
                    let x2 = _mm256_loadu_ps(xs[i].as_ptr().add(xo + j + 32 + l));
                    acc[i] = _mm256_fmadd_ps(x2, w2, acc[i]);
                }
                l += 8;
            }
        }
    }
    for i in 0..n_acc {
        let mut t = [0.0f32; 8];
        _mm256_storeu_ps(t.as_mut_ptr(), acc[i]);
        results[i] = t[0] + t[1] + t[2] + t[3] + t[4] + t[5] + t[6] + t[7];
    }
}

#[cfg(target_arch = "aarch64")]
#[inline(always)]
fn mat_vec_q4k_row(x: &[f32], row_ptr: *const u8, blocks_per_row: usize) -> f32 {
    use std::arch::aarch64::*;
    unsafe {
        // Four independent accumulators: each of the 4 FMAs per inner
        // iteration lands in its own chain, so the loop is bounded by FMA
        // throughput (4 pipes on Apple M-series) instead of FMA latency.
        let mut sum_v0 = vdupq_n_f32(0.0);
        let mut sum_v1 = vdupq_n_f32(0.0);
        let mut sum_v2 = vdupq_n_f32(0.0);
        let mut sum_v3 = vdupq_n_f32(0.0);
        for b in 0..blocks_per_row {
            let block_ptr = row_ptr.add(b * 144);
            let x_offset = b * 256;
            let d_val = f16_to_f32(u16::from_le_bytes([*block_ptr, *block_ptr.add(1)]));
            let dmin = f16_to_f32(u16::from_le_bytes([*block_ptr.add(2), *block_ptr.add(3)]));
            let scales = std::slice::from_raw_parts(block_ptr.add(4), 12);
            let qs = std::slice::from_raw_parts(block_ptr.add(16), 128);

            for j in (0..256).step_by(64) {
                let (sc1, m1) = get_scale_min_k4(j / 32, scales);
                let (sc2, m2) = get_scale_min_k4(j / 32 + 1, scales);
                let s1v = vdupq_n_f32(d_val * sc1);
                let b1v = vdupq_n_f32(-dmin * m1);
                let s2v = vdupq_n_f32(d_val * sc2);
                let b2v = vdupq_n_f32(-dmin * m2);

                let qb = (j / 64) * 32;
                let xp = x.as_ptr().add(x_offset + j);

                for l in (0..32).step_by(8) {
                    let q_raw = vld1_u8(qs.as_ptr().add(qb + l));
                    let lo_u8 = vand_u8(q_raw, vdup_n_u8(0xf));
                    let hi_u8 = vshr_n_u8(q_raw, 4);

                    let lo_u16 = vmovl_u8(lo_u8);
                    let lo_f32_0 = vcvtq_f32_u32(vmovl_u16(vget_low_u16(lo_u16)));
                    let lo_f32_1 = vcvtq_f32_u32(vmovl_u16(vget_high_u16(lo_u16)));

                    sum_v0 =
                        vfmaq_f32(sum_v0, vld1q_f32(xp.add(l)), vfmaq_f32(b1v, s1v, lo_f32_0));
                    sum_v1 = vfmaq_f32(
                        sum_v1,
                        vld1q_f32(xp.add(l + 4)),
                        vfmaq_f32(b1v, s1v, lo_f32_1),
                    );

                    let hi_u16 = vmovl_u8(hi_u8);
                    let hi_f32_0 = vcvtq_f32_u32(vmovl_u16(vget_low_u16(hi_u16)));
                    let hi_f32_1 = vcvtq_f32_u32(vmovl_u16(vget_high_u16(hi_u16)));

                    sum_v2 = vfmaq_f32(
                        sum_v2,
                        vld1q_f32(xp.add(32 + l)),
                        vfmaq_f32(b2v, s2v, hi_f32_0),
                    );
                    sum_v3 = vfmaq_f32(
                        sum_v3,
                        vld1q_f32(xp.add(32 + l + 4)),
                        vfmaq_f32(b2v, s2v, hi_f32_1),
                    );
                }
            }
        }
        vaddvq_f32(vaddq_f32(
            vaddq_f32(sum_v0, sum_v1),
            vaddq_f32(sum_v2, sum_v3),
        ))
    }
}

// wasm32 SIMD branch. Mirrors the aarch64 NEON layout one-for-one:
// - `v128` accumulator (== 4× f32 lanes), replaces `vdupq_n_f32(0)`.
// - `f32x4_splat` for s1/s2/b1/b2 broadcasts.
// - For each 16-byte qs chunk (32 nibbles) we want four groups of 4
//   dequantised f32s for the lo nibbles and four groups of 4 for the
//   hi nibbles. NEON does this via `vmovl_u8` widen + double-widen.
//   wasm32 simd128 supports the same chain via:
//     `i16x8_extend_low_u8x16` / `i16x8_extend_high_u8x16` (u8x16 → i16x8)
//     `i32x4_extend_low_i16x8` / `i32x4_extend_high_i16x8` (i16x8 → i32x4)
//     `f32x4_convert_i32x4`                                  (i32x4 → f32x4)
//   Sign-extend is safe here: nibble values live in [0,15], so
//   sign-extension == zero-extension.
//   This is wave-23 split-c Fix #1: the previous half-scalar pattern
//   (8-byte loads + 16 scalar nibble extractions per inner iteration)
//   is replaced by a single 16-byte vector load + vector mask/shift +
//   vector widen chain. ~16 → ~8 µops per inner iteration.
// - `f32x4_add(f32x4_mul(x, w), acc)` replaces `vfmaq_f32` (no FMA in
//   the +simd128 proposal; the relaxed-SIMD `f32x4_relaxed_madd` would
//   be slightly tighter but isn't universally enabled in CF V8).
// - Horizontal reduction at the end: extract 4 lanes + scalar add.
//
// Q4_K block layout (144 bytes, 256 elements) is identical on every
// arch — same layout the NEON path consumes.
#[cfg(target_arch = "wasm32")]
#[inline(always)]
fn mat_vec_q4k_row(x: &[f32], row_ptr: *const u8, blocks_per_row: usize) -> f32 {
    use std::arch::wasm32::*;
    unsafe {
        let mut sum_v = f32x4_splat(0.0);
        let mask_lo = u8x16_splat(0x0F);
        for b in 0..blocks_per_row {
            let block_ptr = row_ptr.add(b * 144);
            let x_offset = b * 256;
            let d_val = f16_to_f32(u16::from_le_bytes([*block_ptr, *block_ptr.add(1)]));
            let dmin = f16_to_f32(u16::from_le_bytes([*block_ptr.add(2), *block_ptr.add(3)]));
            let scales = std::slice::from_raw_parts(block_ptr.add(4), 12);
            let qs = std::slice::from_raw_parts(block_ptr.add(16), 128);

            for j in (0..256).step_by(64) {
                let (sc1, m1) = get_scale_min_k4(j / 32, scales);
                let (sc2, m2) = get_scale_min_k4(j / 32 + 1, scales);
                let s1v = f32x4_splat(d_val * sc1);
                let b1v = f32x4_splat(-dmin * m1);
                let s2v = f32x4_splat(d_val * sc2);
                let b2v = f32x4_splat(-dmin * m2);

                let qb = (j / 64) * 32;
                let xp = x.as_ptr().add(x_offset + j);

                // Process 16 packed bytes (32 nibbles) per inner iteration:
                // one full v128 load drives 4× f32x4 lo + 4× f32x4 hi
                // dequantised lanes via the SIMD widen chain.
                for l in (0..32).step_by(16) {
                    let qsp = qs.as_ptr().add(qb + l);
                    let bytes_v = v128_load(qsp as *const v128);

                    // Vector mask + shift to split nibbles in 16-lane regs.
                    let lo_u8 = v128_and(bytes_v, mask_lo);
                    let hi_u8 = u8x16_shr(bytes_v, 4);

                    // Lo nibbles: u8x16 → 2× i16x8 → 4× i32x4 → 4× f32x4.
                    // Lane order is preserved: lo_lo_lo holds nibbles 0..3,
                    // lo_lo_hi holds 4..7, lo_hi_lo holds 8..11, lo_hi_hi
                    // holds 12..15 — matching xp.add(l..l+16) order.
                    let lo_i16_lo = i16x8_extend_low_u8x16(lo_u8);
                    let lo_i16_hi = i16x8_extend_high_u8x16(lo_u8);
                    let lo_f32_0 = f32x4_convert_i32x4(i32x4_extend_low_i16x8(lo_i16_lo));
                    let lo_f32_1 = f32x4_convert_i32x4(i32x4_extend_high_i16x8(lo_i16_lo));
                    let lo_f32_2 = f32x4_convert_i32x4(i32x4_extend_low_i16x8(lo_i16_hi));
                    let lo_f32_3 = f32x4_convert_i32x4(i32x4_extend_high_i16x8(lo_i16_hi));

                    // sum += x_lo * (s1 * lo_nibble + b1)   (FMA-equivalent)
                    let xv0 = v128_load(xp.add(l) as *const v128);
                    let xv1 = v128_load(xp.add(l + 4) as *const v128);
                    let xv2 = v128_load(xp.add(l + 8) as *const v128);
                    let xv3 = v128_load(xp.add(l + 12) as *const v128);
                    let w0 = f32x4_add(f32x4_mul(s1v, lo_f32_0), b1v);
                    let w1 = f32x4_add(f32x4_mul(s1v, lo_f32_1), b1v);
                    let w2 = f32x4_add(f32x4_mul(s1v, lo_f32_2), b1v);
                    let w3 = f32x4_add(f32x4_mul(s1v, lo_f32_3), b1v);
                    sum_v = f32x4_add(sum_v, f32x4_mul(xv0, w0));
                    sum_v = f32x4_add(sum_v, f32x4_mul(xv1, w1));
                    sum_v = f32x4_add(sum_v, f32x4_mul(xv2, w2));
                    sum_v = f32x4_add(sum_v, f32x4_mul(xv3, w3));

                    // Hi nibbles: same widen chain on hi_u8.
                    let hi_i16_lo = i16x8_extend_low_u8x16(hi_u8);
                    let hi_i16_hi = i16x8_extend_high_u8x16(hi_u8);
                    let hi_f32_0 = f32x4_convert_i32x4(i32x4_extend_low_i16x8(hi_i16_lo));
                    let hi_f32_1 = f32x4_convert_i32x4(i32x4_extend_high_i16x8(hi_i16_lo));
                    let hi_f32_2 = f32x4_convert_i32x4(i32x4_extend_low_i16x8(hi_i16_hi));
                    let hi_f32_3 = f32x4_convert_i32x4(i32x4_extend_high_i16x8(hi_i16_hi));

                    // sum += x_hi * (s2 * hi_nibble + b2)
                    let xv4 = v128_load(xp.add(32 + l) as *const v128);
                    let xv5 = v128_load(xp.add(32 + l + 4) as *const v128);
                    let xv6 = v128_load(xp.add(32 + l + 8) as *const v128);
                    let xv7 = v128_load(xp.add(32 + l + 12) as *const v128);
                    let w4 = f32x4_add(f32x4_mul(s2v, hi_f32_0), b2v);
                    let w5 = f32x4_add(f32x4_mul(s2v, hi_f32_1), b2v);
                    let w6 = f32x4_add(f32x4_mul(s2v, hi_f32_2), b2v);
                    let w7 = f32x4_add(f32x4_mul(s2v, hi_f32_3), b2v);
                    sum_v = f32x4_add(sum_v, f32x4_mul(xv4, w4));
                    sum_v = f32x4_add(sum_v, f32x4_mul(xv5, w5));
                    sum_v = f32x4_add(sum_v, f32x4_mul(xv6, w6));
                    sum_v = f32x4_add(sum_v, f32x4_mul(xv7, w7));
                }
            }
        }
        // Horizontal reduce 4 lanes → scalar.
        let mut res = [0.0f32; 4];
        v128_store(res.as_mut_ptr() as *mut v128, sum_v);
        res[0] + res[1] + res[2] + res[3]
    }
}

#[cfg(not(any(target_arch = "aarch64", target_arch = "wasm32", target_arch = "x86_64")))]
#[inline(always)]
fn mat_vec_q4k_row(x: &[f32], row_ptr: *const u8, blocks_per_row: usize) -> f32 {
    mat_vec_q4k_row_scalar(x, row_ptr, blocks_per_row)
}

/// Portable scalar Q4_K row dot — reference + non-AVX2 x86 fallback.
#[cfg(not(any(target_arch = "aarch64", target_arch = "wasm32")))]
#[inline(always)]
fn mat_vec_q4k_row_scalar(x: &[f32], row_ptr: *const u8, blocks_per_row: usize) -> f32 {
    let mut row_sum = 0.0f32;
    for b in 0..blocks_per_row {
        let block_ptr = unsafe { row_ptr.add(b * 144) };
        let x_offset = b * 256;
        let d_val = unsafe { f16_to_f32(u16::from_le_bytes([*block_ptr, *block_ptr.add(1)])) };
        let dmin =
            unsafe { f16_to_f32(u16::from_le_bytes([*block_ptr.add(2), *block_ptr.add(3)])) };
        let scales = unsafe { std::slice::from_raw_parts(block_ptr.add(4), 12) };
        let qs = unsafe { std::slice::from_raw_parts(block_ptr.add(16), 128) };

        for j in (0..256).step_by(64) {
            let (sc1, m1) = get_scale_min_k4(j / 32, scales);
            let (sc2, m2) = get_scale_min_k4(j / 32 + 1, scales);
            let s1 = d_val * sc1;
            let b1 = -dmin * m1;
            let s2 = d_val * sc2;
            let b2 = -dmin * m2;
            let qb = (j / 64) * 32;

            for l in 0..32 {
                let qv = unsafe { *qs.get_unchecked(qb + l) };
                row_sum += x[x_offset + j + l] * (s1 * (qv & 0xf) as f32 + b1);
                row_sum += x[x_offset + j + 32 + l] * (s2 * (qv >> 4) as f32 + b2);
            }
        }
    }
    row_sum
}

/// x86-64 Q4_K row dot: AVX2 when available (the hotpath fix — Q4_K was the only
/// quant missing an x86 SIMD kernel; single-token decode runs this on CPU), else
/// scalar. 8-wide FMA mirroring the NEON kernel at `mat_vec_q4k_row` (aarch64).
#[cfg(target_arch = "x86_64")]
#[inline]
fn mat_vec_q4k_row(x: &[f32], row_ptr: *const u8, blocks_per_row: usize) -> f32 {
    if is_x86_feature_detected!("avx2") && is_x86_feature_detected!("fma") {
        unsafe { mat_vec_q4k_row_avx2(x, row_ptr, blocks_per_row) }
    } else {
        mat_vec_q4k_row_scalar(x, row_ptr, blocks_per_row)
    }
}

#[cfg(target_arch = "x86_64")]
#[target_feature(enable = "avx2,fma")]
unsafe fn mat_vec_q4k_row_avx2(x: &[f32], row_ptr: *const u8, blocks_per_row: usize) -> f32 {
    use std::arch::x86_64::*;
    let mut sum = _mm256_setzero_ps();
    let mask = _mm_set1_epi8(0x0f);
    for b in 0..blocks_per_row {
        let block_ptr = row_ptr.add(b * 144);
        let x_offset = b * 256;
        let d_val = f16_to_f32(u16::from_le_bytes([*block_ptr, *block_ptr.add(1)]));
        let dmin = f16_to_f32(u16::from_le_bytes([*block_ptr.add(2), *block_ptr.add(3)]));
        let scales = std::slice::from_raw_parts(block_ptr.add(4), 12);
        let qs = std::slice::from_raw_parts(block_ptr.add(16), 128);
        for j in (0..256).step_by(64) {
            let (sc1, m1) = get_scale_min_k4(j / 32, scales);
            let (sc2, m2) = get_scale_min_k4(j / 32 + 1, scales);
            let s1 = _mm256_set1_ps(d_val * sc1);
            let b1 = _mm256_set1_ps(-dmin * m1);
            let s2 = _mm256_set1_ps(d_val * sc2);
            let b2 = _mm256_set1_ps(-dmin * m2);
            let qb = (j / 64) * 32;
            let xp = x.as_ptr().add(x_offset + j);
            for l in (0..32).step_by(8) {
                // 8 packed bytes → lo/hi nibbles (byte-wise) → 8×i32 → 8×f32
                let raw = _mm_loadl_epi64(qs.as_ptr().add(qb + l) as *const __m128i);
                let lo = _mm_and_si128(raw, mask);
                let hi = _mm_and_si128(_mm_srli_epi16(raw, 4), mask);
                let lo_f = _mm256_cvtepi32_ps(_mm256_cvtepu8_epi32(lo));
                let hi_f = _mm256_cvtepi32_ps(_mm256_cvtepu8_epi32(hi));
                let w_lo = _mm256_fmadd_ps(s1, lo_f, b1); // d·sc·q − dmin·m
                let w_hi = _mm256_fmadd_ps(s2, hi_f, b2);
                sum = _mm256_fmadd_ps(_mm256_loadu_ps(xp.add(l)), w_lo, sum);
                sum = _mm256_fmadd_ps(_mm256_loadu_ps(xp.add(32 + l)), w_hi, sum);
            }
        }
    }
    // horizontal sum of the 8 lanes
    let lo128 = _mm256_castps256_ps128(sum);
    let hi128 = _mm256_extractf128_ps(sum, 1);
    let mut s = _mm_add_ps(lo128, hi128);
    s = _mm_hadd_ps(s, s);
    s = _mm_hadd_ps(s, s);
    _mm_cvtss_f32(s)
}

pub fn mat_vec_q4k_batch(out: &mut [&mut [f32]], xs: &[&[f32]], w: &[u8], _n: usize, d: usize) {
    let n_rows = out[0].len();
    // GPU fast path (prefill: many tokens share one weight). Pack the slice-of-
    // slices layout into the flat rows_shared buffers only after the cheap
    // `gpu_wants` gate says the GPU will actually take the op.
    #[cfg(all(feature = "cuda", not(target_arch = "wasm32")))]
    {
        let tokens = xs.len();
        if crate::cuda_matmul::gpu_wants(tokens) {
            let flat_x: Vec<f32> = xs.iter().flat_map(|s| s.iter().copied()).collect();
            let mut flat_out = vec![0.0f32; tokens * n_rows];
            if crate::cuda_matmul::try_mat_vec_q4k_rows_shared(
                &mut flat_out, &flat_x, w, n_rows, d, tokens,
            ) {
                for (t, dst) in out.iter_mut().enumerate() {
                    dst[..n_rows].copy_from_slice(&flat_out[t * n_rows..(t + 1) * n_rows]);
                }
                return;
            }
        }
    }
    let bpr = d / 256;
    let expected_len = n_rows * bpr * 144;
    if w.len() < expected_len {
        panic!(
            "[mat_vec_q4k_batch] WEIGHT BUFFER TOO SMALL: need {} bytes ({} rows x {} bpr x 144), have {}",
            expected_len, n_rows, bpr, w.len()
        );
    }
    let w_addr = w.as_ptr() as usize;
    let n_batch = xs.len();

    let out_ptrs: Vec<usize> = out.iter_mut().map(|s| s.as_mut_ptr() as usize).collect();

    (0..n_rows).into_par_iter().for_each(|i| {
        let rp = (w_addr + i * bpr * 144) as *const u8;
        // Sized for the wider native BATCH_CAPACITY (64) used by the
        // gemma4 pipeline. Wasm's BATCH_CAPACITY is 16; Qwen's native
        // path sends 8. Stack-allocated, so 64×4 = 256 bytes overhead
        // per worker iter — negligible. Sized to model.rs BATCH_CAPACITY
        // (128); if that constant rises again, raise this too or the
        // mat_vec call below will panic with `range end out of range`.
        // (2026-07-10: was 64 while BATCH_CAPACITY=128 — latent panic hit
        // by lm_head_all_positions pushing full-128 position batches.)
        let mut row_results = [0.0f32; 128];
        mat_vec_q4k_row_batch(xs, rp, bpr, &mut row_results[..n_batch]);
        for r in 0..n_batch {
            unsafe {
                *(out_ptrs[r] as *mut f32).add(i) = row_results[r];
            }
        }
    });
}

pub fn mat_vec_q4k_multi(out: &mut [&mut [f32]], x: &[f32], w_ptrs: &[*const u8], d: usize) {
    let bpr = d / 256;
    let n_rows = out.len();

    // For now, simple implementation that can be optimized later
    for r in 0..n_rows {
        for i in 0..out[r].len() {
            let rp = unsafe { w_ptrs[r].add(i * bpr * 144) };
            out[r][i] = mat_vec_q4k_row(x, rp, bpr);
        }
    }
}

pub fn mat_vec_q4k(out: &mut [f32], x: &[f32], w: &[u8], n: usize, d: usize) {
    // GPU fast path (cuBLAS on an L4) when built with `--features cuda` and a
    // CUDA device is present. tokens=1 (LLM decode) engages only under
    // FLUX_GPU_MIN_TOKENS=1 — set per-deploy on services whose dequantized f32
    // weights fit the VRAM budget. CPU kernel below remains source of truth.
    #[cfg(all(feature = "cuda", not(target_arch = "wasm32")))]
    {
        // MESH_GPU_CPU_RACE=1 (additive, DEFAULT OFF): GPU‖CPU row split. See the
        // module note above mat_vec_q8_0. Q4_K superblock = 144 bytes / 256 elems.
        if gpu_cpu_race_enabled() && crate::cuda_matmul::q4k_race_ready(n, d, w.len()) {
            if let Some(k) = gpu_cpu_race_split(n) {
                let bpr = d / 256;
                let bytes_per_row = bpr * 144;
                let (out_gpu, out_cpu) = out[..n].split_at_mut(k);
                let (w_gpu, w_cpu) = w.split_at(k * bytes_per_row);
                // GPU half (rows [0..k)) to the standing worker — no spawn. SAFETY:
                // slices live for the block, joined before read, disjoint ranges.
                let pending = unsafe {
                    gpu_race_lane::dispatch(gpu_race_lane::Kind::Q4K, out_gpu, x, w_gpu, k, d)
                };
                out_cpu.par_iter_mut().enumerate().for_each(|(i, o)| {
                    let rp = unsafe { w_cpu.as_ptr().add(i * bytes_per_row) };
                    *o = mat_vec_q4k_row(x, rp, bpr);
                });
                if !pending.join() {
                    out_gpu.par_iter_mut().enumerate().for_each(|(i, o)| {
                        let rp = unsafe { w_gpu.as_ptr().add(i * bytes_per_row) };
                        *o = mat_vec_q4k_row(x, rp, bpr);
                    });
                }
                return;
            }
        }
        // MESH_GPU_Q4K=1 (additive, DEFAULT OFF): custom in-kernel Q4_K dequant-
        // GEMV for single-token decode (reads RAW Q4_K ~4.0 GB vs the f16 working
        // set). Tried FIRST; on false (flag off / GPU absent / cubin unavailable /
        // wrong shape / any error) falls through to the existing cuBLAS/CPU path
        // UNCHANGED. CPU stays the source of truth.
        if crate::cuda_matmul::try_mat_vec_q4k_kernel(&mut out[..n], x, w, n, d) {
            return;
        }
        // Slice out to exactly n: the caller's buffer may be sized for the
        // batch capacity (> n), but the GPU dtoh asserts src.len()==dst.len().
        // The CPU path below writes out[..n] for the same reason.
        if crate::cuda_matmul::try_mat_vec_q4k(&mut out[..n], x, w, n, d) {
            return;
        }
    }
    let bpr = d / 256;
    let expected_len = n * bpr * 144;
    if w.len() < expected_len {
        panic!(
            "mat_vec_q4k: weight buffer too small! got {}, expected {}",
            w.len(),
            expected_len
        );
    }
    let w_base = w.as_ptr();

    if n <= RAYON_THRESHOLD {
        for i in 0..n {
            let rp = unsafe { w_base.add(i * bpr * 144) };
            out[i] = mat_vec_q4k_row(x, rp, bpr);
        }
    } else {
        let w_addr = w_base as usize;
        out[..n]
            .par_chunks_mut(Q4K_PAR_CHUNK_ROWS)
            .enumerate()
            .for_each(|(ci, chunk)| {
                for (i, val) in chunk.iter_mut().enumerate() {
                    let gi = ci * Q4K_PAR_CHUNK_ROWS + i;
                    let rp = unsafe { (w_addr as *const u8).add(gi * bpr * 144) };
                    *val = mat_vec_q4k_row(x, rp, bpr);
                }
            });
    }
}

#[inline(always)]
fn mat_vec_q4k_row_masked(
    x: &[f32],
    row_ptr: *const u8,
    blocks_per_row: usize,
    block_mask: &[u8],
) -> f32 {
    let mut row_sum = 0.0f32;
    for block in 0..blocks_per_row {
        if !active_mask_block(block_mask, block) {
            continue;
        }
        let x_start = block * 256;
        let x_end = x_start + 256;
        if x_end <= x.len() {
            let block_ptr = unsafe { row_ptr.add(block * 144) };
            row_sum += mat_vec_q4k_row(&x[x_start..x_end], block_ptr, 1);
        }
    }
    row_sum
}

pub fn mat_vec_q4k_masked(
    out: &mut [f32],
    x: &[f32],
    w: &[u8],
    n: usize,
    d: usize,
    block_mask: &[u8],
) {
    let bpr = d / 256;
    if !block_mask_has_skips(block_mask, bpr) {
        mat_vec_q4k(out, x, w, n, d);
        return;
    }

    let expected_len = n * bpr * 144;
    if w.len() < expected_len {
        panic!(
            "mat_vec_q4k_masked: weight buffer too small! got {}, expected {}",
            w.len(),
            expected_len
        );
    }
    let w_base = w.as_ptr();

    if n <= RAYON_THRESHOLD {
        for i in 0..n {
            let rp = unsafe { w_base.add(i * bpr * 144) };
            out[i] = mat_vec_q4k_row_masked(x, rp, bpr, block_mask);
        }
    } else {
        let w_addr = w_base as usize;
        out[..n]
            .par_chunks_mut(Q4K_PAR_CHUNK_ROWS)
            .enumerate()
            .for_each(|(ci, chunk)| {
                for (i, val) in chunk.iter_mut().enumerate() {
                    let gi = ci * Q4K_PAR_CHUNK_ROWS + i;
                    let rp = unsafe { (w_addr as *const u8).add(gi * bpr * 144) };
                    *val = mat_vec_q4k_row_masked(x, rp, bpr, block_mask);
                }
            });
    }
}

#[cfg(target_arch = "aarch64")]
#[inline(always)]
unsafe fn q5_high_bits8(qh: u16, masks: uint16x8_t) -> uint16x8_t {
    let bits = vandq_u16(vdupq_n_u16(qh), masks);
    let present = vcgtq_u16(bits, vdupq_n_u16(0));
    vandq_u16(present, vdupq_n_u16(16))
}

#[cfg(target_arch = "aarch64")]
#[inline(always)]
unsafe fn q5_accumulate8(
    sum_v: &mut float32x4_t,
    x_ptr: *const f32,
    q: uint8x8_t,
    high_bits: uint16x8_t,
    scale: float32x4_t,
) {
    let q_u16 = vaddq_u16(vmovl_u8(q), high_bits);
    let q_i16 = vsubq_s16(vreinterpretq_s16_u16(q_u16), vdupq_n_s16(16));
    let q_lo = vcvtq_f32_s32(vmovl_s16(vget_low_s16(q_i16)));
    let q_hi = vcvtq_f32_s32(vmovl_s16(vget_high_s16(q_i16)));
    *sum_v = vfmaq_f32(*sum_v, vld1q_f32(x_ptr), vmulq_f32(scale, q_lo));
    *sum_v = vfmaq_f32(*sum_v, vld1q_f32(x_ptr.add(4)), vmulq_f32(scale, q_hi));
}

#[cfg(target_arch = "aarch64")]
#[inline(always)]
fn mat_vec_q5_0_row(x: &[f32], row_ptr: *const u8, blocks_per_row: usize, d: usize) -> f32 {
    unsafe {
        let masks_lo = vld1q_u16(Q5_HIGH_BIT_MASKS_LO.as_ptr());
        let masks_hi = vld1q_u16(Q5_HIGH_BIT_MASKS_HI.as_ptr());
        // Four independent accumulators (one per q5_accumulate8 call site)
        // break the FMA dependency chain — throughput-bound, not latency-bound.
        let mut sum_v0 = vdupq_n_f32(0.0);
        let mut sum_v1 = vdupq_n_f32(0.0);
        let mut sum_v2 = vdupq_n_f32(0.0);
        let mut sum_v3 = vdupq_n_f32(0.0);
        let mut tail_sum = 0.0f32;

        for b in 0..blocks_per_row {
            let bp = row_ptr.add(b * 22);
            let d_val = f16_to_f32(u16::from_le_bytes([*bp, *bp.add(1)]));
            let qh = (*bp.add(2) as u32)
                | ((*bp.add(3) as u32) << 8)
                | ((*bp.add(4) as u32) << 16)
                | ((*bp.add(5) as u32) << 24);
            let qs = bp.add(6);
            let xo = b * 32;

            if xo + 32 <= d {
                let scale = vdupq_n_f32(d_val);
                let q_v = vld1q_u8(qs);
                let low_nibbles = vandq_u8(q_v, vdupq_n_u8(0x0f));
                let high_nibbles = vshrq_n_u8(q_v, 4);
                let qh_low = qh as u16;
                let qh_high = (qh >> 16) as u16;
                let xp = x.as_ptr().add(xo);

                q5_accumulate8(
                    &mut sum_v0,
                    xp,
                    vget_low_u8(low_nibbles),
                    q5_high_bits8(qh_low, masks_lo),
                    scale,
                );
                q5_accumulate8(
                    &mut sum_v1,
                    xp.add(8),
                    vget_high_u8(low_nibbles),
                    q5_high_bits8(qh_low, masks_hi),
                    scale,
                );
                q5_accumulate8(
                    &mut sum_v2,
                    xp.add(16),
                    vget_low_u8(high_nibbles),
                    q5_high_bits8(qh_high, masks_lo),
                    scale,
                );
                q5_accumulate8(
                    &mut sum_v3,
                    xp.add(24),
                    vget_high_u8(high_nibbles),
                    q5_high_bits8(qh_high, masks_hi),
                    scale,
                );
            } else {
                for j in 0..16 {
                    let idx0 = xo + j;
                    let idx1 = xo + j + 16;
                    let xh0 = (((qh >> j) << 4) & 0x10) as i32;
                    let xh1 = (((qh >> (j + 16)) << 4) & 0x10) as i32;
                    let q = *qs.add(j);
                    if idx0 < d {
                        let w0 = (((q & 0x0f) as i32 | xh0) - 16) as f32;
                        tail_sum += *x.get_unchecked(idx0) * d_val * w0;
                    }
                    if idx1 < d {
                        let w1 = (((q >> 4) as i32 | xh1) - 16) as f32;
                        tail_sum += *x.get_unchecked(idx1) * d_val * w1;
                    }
                }
            }
        }

        vaddvq_f32(vaddq_f32(
            vaddq_f32(sum_v0, sum_v1),
            vaddq_f32(sum_v2, sum_v3),
        )) + tail_sum
    }
}

// x86_64 decode hot path: runtime-detected AVX2+FMA Q5_0 row dot. Q5_0 FFN
// (gate/up/down via mat_vec_q5_0_pair / mat_vec_q5_0 -> this row fn) is the
// dominant ~59ms/token on the mesh and was scalar on x86. Mirrors the aarch64
// NEON decode: low nibbles -> indices 0..15, high nibbles -> 16..31, 5th bit
// from `qh` per index; block scale factored out (cosine ~0.9999 vs the dequant
// reference; gated on serving `divergent_tokens=0`). Runtime-detected so
// non-AVX2 x86 still runs the exact scalar fallback (no SIGILL).
#[cfg(target_arch = "x86_64")]
#[inline(always)]
fn mat_vec_q5_0_row(x: &[f32], row_ptr: *const u8, blocks_per_row: usize, d: usize) -> f32 {
    if is_x86_feature_detected!("avx2") && is_x86_feature_detected!("fma") {
        unsafe { mat_vec_q5_0_row_avx2(x, row_ptr, blocks_per_row, d) }
    } else {
        mat_vec_q5_0_row_scalar(x, row_ptr, blocks_per_row, d)
    }
}

#[cfg(target_arch = "x86_64")]
#[target_feature(enable = "avx2,fma")]
#[inline]
unsafe fn q5_chunk_acc(
    acc: std::arch::x86_64::__m256,
    xp: *const f32,
    nib_bytes8: std::arch::x86_64::__m128i,
    qh_shifted: u32,
    mask_lsb8: std::arch::x86_64::__m256i,
    v16: std::arch::x86_64::__m256i,
) -> std::arch::x86_64::__m256 {
    use std::arch::x86_64::*;
    // 8 nibbles (each already masked to 0..15) widen to i32x8.
    let nib = _mm256_cvtepi8_epi32(nib_bytes8);
    // 5th bit: lane i set iff bit i of qh_shifted is set -> contributes 16.
    let qbits = _mm256_set1_epi32(qh_shifted as i32);
    let isset = _mm256_cmpeq_epi32(_mm256_and_si256(qbits, mask_lsb8), mask_lsb8);
    let high = _mm256_and_si256(isset, v16);
    // q = (nibble | (bit<<4)) - 16  ==  nibble + 16*bit - 16  (nibble < 16)
    let q = _mm256_sub_epi32(_mm256_add_epi32(nib, high), v16);
    let qf = _mm256_cvtepi32_ps(q);
    _mm256_fmadd_ps(_mm256_loadu_ps(xp), qf, acc)
}

#[cfg(target_arch = "x86_64")]
#[target_feature(enable = "avx2,fma")]
unsafe fn mat_vec_q5_0_row_avx2(
    x: &[f32],
    row_ptr: *const u8,
    blocks_per_row: usize,
    d: usize,
) -> f32 {
    use std::arch::x86_64::*;
    let nib_mask = _mm_set1_epi8(0x0f);
    let v16 = _mm256_set1_epi32(16);
    // LSB-first bit-test masks: lane i = 1<<i (lane 0 == bit 0).
    let mask_lsb8 = _mm256_set_epi32(
        1 << 7,
        1 << 6,
        1 << 5,
        1 << 4,
        1 << 3,
        1 << 2,
        1 << 1,
        1 << 0,
    );
    // Vector running total: fold each block in with one FMA against the
    // broadcast scale — one horizontal reduce per ROW instead of per block.
    let mut acc_total = _mm256_setzero_ps();
    let mut tail = 0.0f32;
    let xptr = x.as_ptr();
    for b in 0..blocks_per_row {
        let bp = row_ptr.add(b * 22);
        let d_val = f16_to_f32(u16::from_le_bytes([*bp, *bp.add(1)]));
        let qh = (*bp.add(2) as u32)
            | ((*bp.add(3) as u32) << 8)
            | ((*bp.add(4) as u32) << 16)
            | ((*bp.add(5) as u32) << 24);
        let qs = bp.add(6);
        let xo = b * 32;
        if xo + 32 <= d {
            let xp = xptr.add(xo);
            let q16 = _mm_loadu_si128(qs as *const __m128i);
            let low16 = _mm_and_si128(q16, nib_mask); // nibbles for idx 0..15
            let high16 = _mm_and_si128(_mm_srli_epi16(q16, 4), nib_mask); // idx 16..31
            // Two independent accumulator chains keep the FMA pipes fed.
            let mut acc_a = _mm256_setzero_ps();
            let mut acc_b = _mm256_setzero_ps();
            // idx 0..7: low nibbles bytes 0..7, qh bits 0..7, x+0
            acc_a = q5_chunk_acc(acc_a, xp, low16, qh, mask_lsb8, v16);
            // idx 8..15: low nibbles bytes 8..15, qh bits 8..15, x+8
            acc_b =
                q5_chunk_acc(acc_b, xp.add(8), _mm_srli_si128(low16, 8), qh >> 8, mask_lsb8, v16);
            // idx 16..23: high nibbles bytes 0..7, qh bits 16..23, x+16
            acc_a = q5_chunk_acc(acc_a, xp.add(16), high16, qh >> 16, mask_lsb8, v16);
            // idx 24..31: high nibbles bytes 8..15, qh bits 24..31, x+24
            acc_b = q5_chunk_acc(
                acc_b,
                xp.add(24),
                _mm_srli_si128(high16, 8),
                qh >> 24,
                mask_lsb8,
                v16,
            );
            acc_total = _mm256_fmadd_ps(
                _mm256_set1_ps(d_val),
                _mm256_add_ps(acc_a, acc_b),
                acc_total,
            );
        } else {
            for j in 0..16 {
                let idx0 = xo + j;
                let idx1 = xo + j + 16;
                let xh0 = (((qh >> j) << 4) & 0x10) as i32;
                let xh1 = (((qh >> (j + 16)) << 4) & 0x10) as i32;
                let q = *qs.add(j);
                if idx0 < d {
                    let w0 = (((q & 0x0f) as i32 | xh0) - 16) as f32;
                    tail += *x.get_unchecked(idx0) * d_val * w0;
                }
                if idx1 < d {
                    let w1 = (((q >> 4) as i32 | xh1) - 16) as f32;
                    tail += *x.get_unchecked(idx1) * d_val * w1;
                }
            }
        }
    }
    // horizontal sum of the 8 lanes, once per row
    let lo = _mm256_castps256_ps128(acc_total);
    let hi = _mm256_extractf128_ps(acc_total, 1);
    let qv = _mm_add_ps(lo, hi);
    let shuf = _mm_movehdup_ps(qv);
    let sums = _mm_add_ps(qv, shuf);
    let shuf2 = _mm_movehl_ps(shuf, sums);
    let s = _mm_add_ss(sums, shuf2);
    _mm_cvtss_f32(s) + tail
}

#[cfg(not(target_arch = "aarch64"))]
#[inline(always)]
fn mat_vec_q5_0_row_scalar(x: &[f32], row_ptr: *const u8, blocks_per_row: usize, d: usize) -> f32 {
    let mut sum = 0.0f32;
    unsafe {
        for b in 0..blocks_per_row {
            let bp = row_ptr.add(b * 22);
            let d_val = f16_to_f32(u16::from_le_bytes([*bp, *bp.add(1)]));
            let qh = (*bp.add(2) as u32)
                | ((*bp.add(3) as u32) << 8)
                | ((*bp.add(4) as u32) << 16)
                | ((*bp.add(5) as u32) << 24);
            let qs = std::slice::from_raw_parts(bp.add(6), 16);
            let xo = b * 32;
            for j in 0..16 {
                let idx0 = xo + j;
                let idx1 = xo + j + 16;
                let xh0 = (((qh >> j) << 4) & 0x10) as i32;
                let xh1 = (((qh >> (j + 16)) << 4) & 0x10) as i32;
                let q = qs[j];
                if idx0 < d {
                    let w0 = (((q & 0x0f) as i32 | xh0) - 16) as f32;
                    sum += x[idx0] * d_val * w0;
                }
                if idx1 < d {
                    let w1 = (((q >> 4) as i32 | xh1) - 16) as f32;
                    sum += x[idx1] * d_val * w1;
                }
            }
        }
    }
    sum
}

// Non-x86, non-aarch64 (e.g. wasm32): scalar Q5_0 row.
#[cfg(all(not(target_arch = "aarch64"), not(target_arch = "x86_64")))]
#[inline(always)]
fn mat_vec_q5_0_row(x: &[f32], row_ptr: *const u8, blocks_per_row: usize, d: usize) -> f32 {
    mat_vec_q5_0_row_scalar(x, row_ptr, blocks_per_row, d)
}

#[inline(always)]
fn mat_vec_q5_0_row_masked(
    x: &[f32],
    row_ptr: *const u8,
    blocks_per_row: usize,
    d: usize,
    block_mask: &[u8],
) -> f32 {
    let mut row_sum = 0.0f32;
    for block in 0..blocks_per_row {
        if !active_mask_block(block_mask, block) {
            continue;
        }
        let block_start = block * 32;
        let block_len = d.saturating_sub(block_start).min(32);
        if block_len == 0 {
            continue;
        }
        let block_ptr = unsafe { row_ptr.add(block * 22) };
        row_sum += mat_vec_q5_0_row(
            &x[block_start..block_start + block_len],
            block_ptr,
            1,
            block_len,
        );
    }
    row_sum
}

pub fn mat_vec_q5_0(out: &mut [f32], x: &[f32], w: &[u8], n: usize, d: usize) {
    let blocks_per_row = d.div_ceil(32);
    let expected_len = n * blocks_per_row * 22;
    if w.len() < expected_len {
        panic!(
            "[mat_vec_q5_0] WEIGHT BUFFER TOO SMALL: need {} bytes ({} rows x {} bpr x 22), have {}",
            expected_len, n, blocks_per_row, w.len()
        );
    }
    out[..n].par_iter_mut().enumerate().for_each(|(i, o)| {
        let row_ptr = unsafe { w.as_ptr().add(i * blocks_per_row * 22) };
        *o = mat_vec_q5_0_row(x, row_ptr, blocks_per_row, d);
    });
}

pub fn mat_vec_q5_0_masked(
    out: &mut [f32],
    x: &[f32],
    w: &[u8],
    n: usize,
    d: usize,
    block_mask: &[u8],
) {
    let blocks_per_row = d.div_ceil(32);
    if !block_mask_has_skips(block_mask, blocks_per_row) {
        mat_vec_q5_0(out, x, w, n, d);
        return;
    }

    out[..n].par_iter_mut().enumerate().for_each(|(i, o)| {
        let row_ptr = unsafe { w.as_ptr().add(i * blocks_per_row * 22) };
        *o = mat_vec_q5_0_row_masked(x, row_ptr, blocks_per_row, d, block_mask);
    });
}

pub fn mat_vec_q5_0_pair(
    out_a: &mut [f32],
    out_b: &mut [f32],
    x: &[f32],
    w_a: &[u8],
    w_b: &[u8],
    n: usize,
    d: usize,
) {
    let blocks_per_row = d.div_ceil(32);
    out_a[..n]
        .par_iter_mut()
        .zip(out_b[..n].par_iter_mut())
        .enumerate()
        .for_each(|(i, (a, b))| {
            let row_offset = i * blocks_per_row * 22;
            let row_ptr_a = unsafe { w_a.as_ptr().add(row_offset) };
            let row_ptr_b = unsafe { w_b.as_ptr().add(row_offset) };
            *a = mat_vec_q5_0_row(x, row_ptr_a, blocks_per_row, d);
            *b = mat_vec_q5_0_row(x, row_ptr_b, blocks_per_row, d);
        });
}

pub fn mat_vec_q5_0_pair_masked(
    out_a: &mut [f32],
    out_b: &mut [f32],
    x: &[f32],
    w_a: &[u8],
    w_b: &[u8],
    n: usize,
    d: usize,
    block_mask: &[u8],
) {
    let blocks_per_row = d.div_ceil(32);
    if !block_mask_has_skips(block_mask, blocks_per_row) {
        mat_vec_q5_0_pair(out_a, out_b, x, w_a, w_b, n, d);
        return;
    }

    out_a[..n]
        .par_iter_mut()
        .zip(out_b[..n].par_iter_mut())
        .enumerate()
        .for_each(|(i, (a, b))| {
            let row_offset = i * blocks_per_row * 22;
            let row_ptr_a = unsafe { w_a.as_ptr().add(row_offset) };
            let row_ptr_b = unsafe { w_b.as_ptr().add(row_offset) };
            *a = mat_vec_q5_0_row_masked(x, row_ptr_a, blocks_per_row, d, block_mask);
            *b = mat_vec_q5_0_row_masked(x, row_ptr_b, blocks_per_row, d, block_mask);
        });
}

pub fn mat_vec_q5_0_pair_output_masked(
    out_a: &mut [f32],
    out_b: &mut [f32],
    x: &[f32],
    w_a: &[u8],
    w_b: &[u8],
    n: usize,
    d: usize,
    output_block_len: usize,
    output_block_mask: &[u8],
) {
    if output_block_len == 0
        || !output_block_mask
            .iter()
            .take(n.div_ceil(output_block_len))
            .any(|&mask| mask == 0)
    {
        mat_vec_q5_0_pair(out_a, out_b, x, w_a, w_b, n, d);
        return;
    }

    let blocks_per_row = d.div_ceil(32);
    out_a[..n]
        .par_chunks_mut(output_block_len)
        .zip(out_b[..n].par_chunks_mut(output_block_len))
        .enumerate()
        .for_each(|(output_block, (chunk_a, chunk_b))| {
            if !active_mask_block(output_block_mask, output_block) {
                chunk_a.fill(0.0);
                chunk_b.fill(0.0);
                return;
            }

            let row_base = output_block * output_block_len;
            for (row_in_block, (a, b)) in chunk_a.iter_mut().zip(chunk_b.iter_mut()).enumerate() {
                let row = row_base + row_in_block;
                let row_offset = row * blocks_per_row * 22;
                let row_ptr_a = unsafe { w_a.as_ptr().add(row_offset) };
                let row_ptr_b = unsafe { w_b.as_ptr().add(row_offset) };
                *a = mat_vec_q5_0_row(x, row_ptr_a, blocks_per_row, d);
                *b = mat_vec_q5_0_row(x, row_ptr_b, blocks_per_row, d);
            }
        });
}

/// Lane count at which the batch kernels switch from the fused per-lane row
/// kernel to dequantize-once + per-lane f32 dot. Below this, re-decoding the
/// quantized row per lane is cheaper than materializing the f32 row.
const BATCH_DEQUANT_ONCE_MIN: usize = 4;

pub fn mat_vec_q5_0_batch(out: &mut [&mut [f32]], xs: &[&[f32]], w: &[u8], n: usize, d: usize) {
    let n_batch = xs.len();
    if n_batch >= BATCH_DEQUANT_ONCE_MIN {
        // Dequantize each weight row ONCE and reuse across lanes — the
        // per-token loop below re-decodes every 5-bit row n_batch times
        // (and pays n_batch rayon dispatches).
        let out_ptrs: Vec<usize> = out.iter_mut().map(|s| s.as_mut_ptr() as usize).collect();
        (0..n).into_par_iter().for_each_init(
            || vec![0.0f32; d],
            |row_buf, i| {
                dequantize_q5_0_row(row_buf, w, i, d);
                for r in 0..n_batch {
                    let row_out = unsafe { (out_ptrs[r] as *mut f32).add(i) };
                    unsafe {
                        *row_out = dot_product(row_buf, xs[r]);
                    }
                }
            },
        );
        return;
    }
    for (out_slice, x) in out.iter_mut().zip(xs.iter()) {
        mat_vec_q5_0(out_slice, x, w, n, d);
    }
}

#[cfg(target_arch = "aarch64")]
#[inline(always)]
fn mat_vec_q8_0_row(x: &[f32], row_ptr: *const u8, blocks_per_row: usize, d: usize) -> f32 {
    unsafe {
        // Four independent accumulators break the FMA dependency chain: the
        // full 32-element block (8 FMAs) retires in two rounds of 4 parallel
        // FMAs instead of 8 serial ones.
        let mut sum_v0 = vdupq_n_f32(0.0);
        let mut sum_v1 = vdupq_n_f32(0.0);
        let mut sum_v2 = vdupq_n_f32(0.0);
        let mut sum_v3 = vdupq_n_f32(0.0);
        let mut tail_sum = 0.0f32;
        for b in 0..blocks_per_row {
            let bp = row_ptr.add(b * 34);
            let d_val = f16_to_f32(u16::from_le_bytes([*bp, *bp.add(1)]));
            let scale = vdupq_n_f32(d_val);
            let qs = bp.add(2) as *const i8;
            let xo = b * 32;
            let xp = x.as_ptr().add(xo);

            if xo + 32 <= d {
                for j in (0..32).step_by(16) {
                    let qa_i16 = vmovl_s8(vld1_s8(qs.add(j)));
                    let qb_i16 = vmovl_s8(vld1_s8(qs.add(j + 8)));

                    let qa_lo = vcvtq_f32_s32(vmovl_s16(vget_low_s16(qa_i16)));
                    let qa_hi = vcvtq_f32_s32(vmovl_s16(vget_high_s16(qa_i16)));
                    let qb_lo = vcvtq_f32_s32(vmovl_s16(vget_low_s16(qb_i16)));
                    let qb_hi = vcvtq_f32_s32(vmovl_s16(vget_high_s16(qb_i16)));

                    sum_v0 = vfmaq_f32(sum_v0, vld1q_f32(xp.add(j)), vmulq_f32(scale, qa_lo));
                    sum_v1 = vfmaq_f32(sum_v1, vld1q_f32(xp.add(j + 4)), vmulq_f32(scale, qa_hi));
                    sum_v2 = vfmaq_f32(sum_v2, vld1q_f32(xp.add(j + 8)), vmulq_f32(scale, qb_lo));
                    sum_v3 =
                        vfmaq_f32(sum_v3, vld1q_f32(xp.add(j + 12)), vmulq_f32(scale, qb_hi));
                }
            } else {
                for j in 0..32 {
                    let idx = xo + j;
                    if idx < d {
                        tail_sum += *x.get_unchecked(idx) * d_val * *qs.add(j) as f32;
                    }
                }
            }
        }
        vaddvq_f32(vaddq_f32(
            vaddq_f32(sum_v0, sum_v1),
            vaddq_f32(sum_v2, sum_v3),
        )) + tail_sum
    }
}

// x86_64 decode hot path: runtime-detected AVX2+FMA Q8_0 row dot. Mirrors the
// aarch64 NEON path above so Cloud Run (x86) decode matvec is vectorized instead
// of scalar. Numerically: factors the block scale `d_val` out of the 32-element
// integer dot (matches the NEON reassociation; cosine ~0.9999 vs the dequant
// reference, `divergent_tokens=0` in serving). Feature-gated by runtime
// detection so non-AVX2 x86 still runs the exact scalar fallback (no SIGILL).
#[cfg(target_arch = "x86_64")]
#[inline(always)]
fn mat_vec_q8_0_row(x: &[f32], row_ptr: *const u8, blocks_per_row: usize, d: usize) -> f32 {
    if is_x86_feature_detected!("avx2") && is_x86_feature_detected!("fma") {
        unsafe { mat_vec_q8_0_row_avx2(x, row_ptr, blocks_per_row, d) }
    } else {
        mat_vec_q8_0_row_scalar(x, row_ptr, blocks_per_row, d)
    }
}

#[cfg(target_arch = "x86_64")]
#[target_feature(enable = "avx2,fma")]
unsafe fn mat_vec_q8_0_row_avx2(
    x: &[f32],
    row_ptr: *const u8,
    blocks_per_row: usize,
    d: usize,
) -> f32 {
    use std::arch::x86_64::*;
    // Vector running total: the block sum is folded in with one FMA against
    // the broadcast scale instead of a 5-op horizontal reduce per 32 elements.
    // One horizontal sum per ROW, not per block.
    let mut acc_total = _mm256_setzero_ps();
    let mut tail = 0.0f32;
    let xptr = x.as_ptr();
    for b in 0..blocks_per_row {
        let bp = row_ptr.add(b * 34);
        let d_val = f16_to_f32(u16::from_le_bytes([*bp, *bp.add(1)]));
        let qs = bp.add(2) as *const i8;
        let xo = b * 32;
        if xo + 32 <= d {
            let xp = xptr.add(xo);
            // 32 i8 quants -> four 8-wide i32->f32 converts, FMA against x.
            // Two independent chains (a, b) keep the FMA pipes fed.
            let q0 = _mm256_cvtepi32_ps(_mm256_cvtepi8_epi32(_mm_loadl_epi64(qs as *const __m128i)));
            let q1 = _mm256_cvtepi32_ps(_mm256_cvtepi8_epi32(_mm_loadl_epi64(
                qs.add(8) as *const __m128i,
            )));
            let q2 = _mm256_cvtepi32_ps(_mm256_cvtepi8_epi32(_mm_loadl_epi64(
                qs.add(16) as *const __m128i,
            )));
            let q3 = _mm256_cvtepi32_ps(_mm256_cvtepi8_epi32(_mm_loadl_epi64(
                qs.add(24) as *const __m128i,
            )));
            let mut a = _mm256_mul_ps(_mm256_loadu_ps(xp), q0);
            let mut bacc = _mm256_mul_ps(_mm256_loadu_ps(xp.add(8)), q1);
            a = _mm256_fmadd_ps(_mm256_loadu_ps(xp.add(16)), q2, a);
            bacc = _mm256_fmadd_ps(_mm256_loadu_ps(xp.add(24)), q3, bacc);
            acc_total = _mm256_fmadd_ps(_mm256_set1_ps(d_val), _mm256_add_ps(a, bacc), acc_total);
        } else {
            for j in 0..32 {
                let idx = xo + j;
                if idx < d {
                    tail += *x.get_unchecked(idx) * d_val * *qs.add(j) as f32;
                }
            }
        }
    }
    // horizontal sum of the 8 lanes, once per row
    let lo = _mm256_castps256_ps128(acc_total);
    let hi = _mm256_extractf128_ps(acc_total, 1);
    let qv = _mm_add_ps(lo, hi);
    let shuf = _mm_movehdup_ps(qv);
    let sums = _mm_add_ps(qv, shuf);
    let shuf2 = _mm_movehl_ps(shuf, sums);
    let s = _mm_add_ss(sums, shuf2);
    _mm_cvtss_f32(s) + tail
}

#[cfg(not(target_arch = "aarch64"))]
#[inline(always)]
fn mat_vec_q8_0_row_scalar(x: &[f32], row_ptr: *const u8, blocks_per_row: usize, d: usize) -> f32 {
    let mut sum = 0.0f32;
    unsafe {
        for b in 0..blocks_per_row {
            let bp = row_ptr.add(b * 34);
            let d_val = f16_to_f32(u16::from_le_bytes([*bp, *bp.add(1)]));
            let qs = std::slice::from_raw_parts(bp.add(2) as *const i8, 32);
            let xo = b * 32;
            for j in 0..32 {
                let idx = xo + j;
                if idx < d {
                    sum += x[idx] * d_val * qs[j] as f32;
                }
            }
        }
    }
    sum
}

// Non-x86, non-aarch64 (e.g. wasm32): use the scalar row directly.
#[cfg(all(not(target_arch = "aarch64"), not(target_arch = "x86_64")))]
#[inline(always)]
fn mat_vec_q8_0_row(x: &[f32], row_ptr: *const u8, blocks_per_row: usize, d: usize) -> f32 {
    mat_vec_q8_0_row_scalar(x, row_ptr, blocks_per_row, d)
}

// ── MESH_GPU_CPU_RACE=1 (additive, DEFAULT OFF): heterogeneous GPU‖CPU split ──
//
// Single-token decode matvec is bandwidth-bound (each weight matrix is read once).
// The GPU reads its weight rows from HBM and the CPU reads ITS weight rows from
// system DRAM — DIFFERENT memory buses. Running both concurrently over DISJOINT
// row-ranges makes the bandwidths ADD (no quality loss: each row is computed by
// exactly one kernel, and both kernels match the f64 reference, so the
// concatenation is numerically exact).
//
// Concurrency is at the OS-thread level: the GPU half runs on a `std::thread::
// scope` thread (it calls the EXISTING `try_*_kernel`, which blocks on its own
// cudaSync entirely INSIDE the process-global GPU mutex — no CudaSlice / raw
// device pointer ever crosses the thread boundary, so the closure is Send), while
// the MAIN thread runs the existing CPU `par_iter_mut` row loop (saturating
// rayon). They overlap because HBM and DRAM don't contend; then we join.
//
// If the GPU half returns `false` (flag off mid-flight / GPU absent / any error),
// the scoped thread computes its own range with the CPU kernel, so `out` is
// always complete and exact — never partially written.
#[cfg(all(feature = "cuda", not(target_arch = "wasm32")))]
fn gpu_cpu_race_enabled() -> bool {
    use std::sync::OnceLock;
    static V: OnceLock<bool> = OnceLock::new();
    *V.get_or_init(|| {
        std::env::var("MESH_GPU_CPU_RACE")
            .map(|v| v == "1")
            .unwrap_or(false)
    })
}

/// GPU's share of the rows, from `MESH_GPU_CPU_RACE_GPU_FRAC` (default 0.65).
/// The GPU gets rows `[0..k)` where `k = round(n * frac)`, clamped to `[1, n-1]`
/// so BOTH halves are non-empty (a 0 or n split would just be the existing
/// single-device path). Returns `None` when the split would be degenerate.
#[cfg(all(feature = "cuda", not(target_arch = "wasm32")))]
fn gpu_cpu_race_split(n: usize) -> Option<usize> {
    use std::sync::OnceLock;
    static FRAC: OnceLock<f64> = OnceLock::new();
    let frac = *FRAC.get_or_init(|| {
        std::env::var("MESH_GPU_CPU_RACE_GPU_FRAC")
            .ok()
            .and_then(|v| v.parse::<f64>().ok())
            .filter(|f| f.is_finite() && *f > 0.0 && *f < 1.0)
            .unwrap_or(0.65)
    });
    if n < 2 {
        return None;
    }
    let k = (n as f64 * frac).round() as usize;
    let k = k.clamp(1, n - 1);
    Some(k)
}

// ── Persistent GPU-lane worker — SPIN-WAIT handoff (no channel / no park) ──────
//
// HISTORY / MEASURED PROBLEM. The race already uses ONE persistent worker thread
// (lazily spawned ONCE via `OnceLock`) rather than a per-matvec spawn, and that
// removed the ~0.66 ms spawn cost. But the profile still showed ~0.7 ms/matvec
// (224 matvecs × 0.7 ≈ 150 ms/token → ~5 tps vs ~13 for GPU-kernel-alone). The
// cause was NOT spawn and NOT re-upload (fetch ~30 µs; the GPU half logs e.g.
// `Q8-KERNEL gemv [9318x4096] 0.30ms` correctly). It was the per-matvec
// cross-thread PARK/WAKEUP latency: a `channel.send` wakes the parked worker and
// the reply `recv` parks the main thread — each park/unpark is ~0.5 ms on the
// virtualized Cloud Run vCPU. The overlapped compute is only ~33 ms; parking
// dominated.
//
// THE FIX. Keep the SINGLE persistent worker, the SYNC kernel entries, and the
// disjoint row-split — but replace the crossbeam channel + OS park/unpark with a
// SPIN-WAIT control block (busy-poll on a cache-line atomic). Per-matvec handoff
// drops from ~0.5 ms (OS park) to ~µs (cache-line poll), so the two lanes
// overlap at ~max(GPU, CPU) — the makespan target. Std-only: no crossbeam on
// this path.
//
// ATOMIC PROTOCOL. One shared `Control` (Arc), with an `AtomicU8 state` cycling
//   IDLE(0) → SUBMITTED(1) → DONE(2) → IDLE(0) → …
// Exactly one job is in flight at a time (matvecs are sequential), so there is a
// single producer (main) and single consumer (worker) and no ABA hazard.
//   • Main publishes the job fields into the `UnsafeCell<Job>` (plain writes),
//     then `state.store(SUBMITTED, Release)`.
//   • Worker spins `while state.load(Acquire) != SUBMITTED { spin_loop() }`, then
//     reads the job (the Acquire pairs with main's Release → the field writes are
//     visible), runs the kernel, stores the result bool, `state.store(DONE,
//     Release)`.
//   • Main runs the CPU half meanwhile, then spins
//     `while state.load(Acquire) != DONE { spin_loop() }` (Acquire pairs with the
//     worker's Release → the worker's `out` writes and the result are visible),
//     reads the result, then `state.store(IDLE, Release)` to re-arm.
//
// SPIN POINTS. (1) worker idle loop waiting for SUBMITTED (continuous between
// jobs — burns one core; see trade-off below); (2) main's join loop waiting for
// DONE (brief — the GPU half is ~0.3 ms and the CPU half usually takes
// comparable, so DONE is typically already set by the time main finishes its
// half). Both use `std::hint::spin_loop()`.
//
// 1-CORE-SPIN TRADE-OFF. The worker busy-polls continuously while idle, pinning
// one logical core at 100%. This is the deliberate cost of the µs handoff: on the
// 8-vCPU Cloud Run node one core is given to handoff latency; the other 7 still
// saturate the rayon CPU half. The flag is DEFAULT OFF, so nothing spins unless
// MESH_GPU_CPU_RACE=1 is set AND the first race matvec lazily starts the worker.
// (A future refinement could park after a spin budget; deliberately omitted to
// keep the handoff a pure cache-line poll.)
#[cfg(all(feature = "cuda", not(target_arch = "wasm32")))]
mod gpu_race_lane {
    use std::cell::UnsafeCell;
    use std::sync::atomic::{AtomicBool, AtomicU8, Ordering};
    use std::sync::{Arc, OnceLock};

    // State machine values for `Control::state` (see module note).
    const IDLE: u8 = 0;
    const SUBMITTED: u8 = 1;
    const DONE: u8 = 2;

    /// Which custom in-kernel dequant-GEMV entry the GPU half should call. Mirrors
    /// the three quant formats the race path drives (Q8_0 / Q4_K / Q6_K).
    #[derive(Clone, Copy)]
    pub enum Kind {
        Q8_0,
        Q4K,
        Q6K,
    }

    /// The GPU-half job fields. Carries RAW pointers because the `out`/`x`/`w`
    /// slices are stack-borrowed by the caller and are NOT `'static`; the main
    /// thread spins to DONE (a full happens-before join) before it reads `out` or
    /// lets the borrows expire, so the worker only ever touches them while they
    /// are live. The GPU half writes ONLY `out[0..n_gpu)` and reads ONLY
    /// `w[0 .. n_gpu*bytes_per_row]` — DISJOINT from the CPU half's `out[k..]` /
    /// weight suffix — so there is no aliasing across the lanes.
    ///
    /// `Job` lives inside `Control.job: UnsafeCell<Job>`; the `state` transitions
    /// (Release/Acquire) are what publish/observe these plain fields across the
    /// thread boundary — never touched outside the SUBMITTED↔DONE window.
    struct Job {
        kind: Kind,
        out_ptr: *mut f32,
        x_ptr: *const f32,
        x_len: usize,
        w_ptr: *const u8,
        w_len: usize,
        n_gpu: usize,
        d: usize,
    }

    /// Shared spin-wait control block. `state` is the single synchronization
    /// point: all of `job`'s plain fields and `result` are published/observed via
    /// Release/Acquire on `state`, so they are NOT themselves atomic. Exactly one
    /// job is in flight (sequential matvecs), so there is one writer of `job`
    /// (main, before SUBMITTED) and one writer of `result`/`out` (worker, before
    /// DONE) — no concurrent access to the cells while a transition is pending.
    struct Control {
        state: AtomicU8,
        result: AtomicBool,
        job: UnsafeCell<Job>,
    }

    // SAFETY: `Control` is shared across the main and worker threads via `Arc`.
    // The only data accessed concurrently is `state` (an atomic) and `result`
    // (an atomic). The non-atomic `job` cell is written by exactly one thread at
    // a time inside the state machine: main writes it only while `state == IDLE`
    // (before storing SUBMITTED), the worker reads it only after observing
    // SUBMITTED, and main does not write it again until after observing DONE and
    // re-arming to IDLE. The Release/Acquire pairing on `state` establishes the
    // happens-before edges that make those non-atomic accesses data-race-free.
    // The raw pointers in `job` reference the caller's live, disjoint slices; the
    // caller spins to DONE before reading or dropping them, so the worker's
    // access is strictly inside their lifetime.
    unsafe impl Send for Control {}
    unsafe impl Sync for Control {}

    static LANE: OnceLock<Arc<Control>> = OnceLock::new();

    /// The standing worker: spin until a job is SUBMITTED, run the matching SYNC
    /// kernel entry (which locks the GPU mutex itself), publish its bool result,
    /// and store DONE. On a kernel miss (`false`) the caller computes the GPU
    /// range on the CPU, so the row set is never left unwritten. This loops
    /// forever, busy-polling between jobs (burns one core — see module note).
    fn worker(ctrl: Arc<Control>) {
        loop {
            // Spin (no park) until main publishes a job. The Acquire load pairs
            // with main's `store(SUBMITTED, Release)`, so the `job` field writes
            // that preceded it are visible after we observe SUBMITTED.
            while ctrl.state.load(Ordering::Acquire) != SUBMITTED {
                std::hint::spin_loop();
            }
            // Read the published job. SAFETY: we observed SUBMITTED (Acquire), so
            // the writes happen-before this read; main will not touch `job` again
            // until it observes DONE, so we have exclusive read access here.
            let job = unsafe { &*ctrl.job.get() };
            // Reconstruct the caller's disjoint slices from the raw parts. SAFETY:
            // see the `unsafe impl Send/Sync for Control` note — these are live +
            // disjoint and the caller spins to DONE before touching them.
            let out = unsafe { std::slice::from_raw_parts_mut(job.out_ptr, job.n_gpu) };
            let x = unsafe { std::slice::from_raw_parts(job.x_ptr, job.x_len) };
            let w = unsafe { std::slice::from_raw_parts(job.w_ptr, job.w_len) };
            let ok = match job.kind {
                Kind::Q8_0 => {
                    crate::cuda_matmul::try_mat_vec_q8_0_kernel(out, x, w, job.n_gpu, job.d)
                }
                Kind::Q4K => {
                    crate::cuda_matmul::try_mat_vec_q4k_kernel(out, x, w, job.n_gpu, job.d)
                }
                Kind::Q6K => {
                    crate::cuda_matmul::try_mat_vec_q6k_kernel(out, x, w, job.n_gpu, job.d)
                }
            };
            // Publish the result, then DONE. The `store(DONE, Release)` pairs with
            // main's Acquire spin: both `result` and the `out` writes above
            // happen-before main's read of them.
            ctrl.result.store(ok, Ordering::Relaxed);
            ctrl.state.store(DONE, Ordering::Release);
        }
    }

    /// Handle to an in-flight GPU-half job. The caller runs the CPU half, then
    /// calls `join()` to spin-wait until the GPU half finishes, getting back
    /// whether the kernel handled it (`true`) or the caller must compute the GPU
    /// range on the CPU (`false`).
    pub struct Pending {
        ctrl: Arc<Control>,
    }

    impl Pending {
        /// Spin-wait until the GPU half completes (state == DONE), then re-arm to
        /// IDLE. Returns the kernel's success bool. The brief busy-poll replaces
        /// the parking `recv` of the old channel path.
        #[must_use]
        pub fn join(self) -> bool {
            // Spin (no park) until the worker publishes DONE. The Acquire load
            // pairs with the worker's `store(DONE, Release)`, so the worker's
            // `out` writes and the `result` store are visible after we observe it.
            while self.ctrl.state.load(Ordering::Acquire) != DONE {
                std::hint::spin_loop();
            }
            let ok = self.ctrl.result.load(Ordering::Relaxed);
            // Re-arm for the next matvec. Release so a subsequent `dispatch` that
            // writes `job` before storing SUBMITTED is correctly ordered after
            // this transition out of DONE.
            self.ctrl.state.store(IDLE, Ordering::Release);
            ok
        }
    }

    /// Dispatch the GPU half `out[0..n_gpu) = W[0..n_gpu) · x` to the standing
    /// worker via the spin-wait control block — no thread spawn, no channel.
    /// Returns a `Pending` the caller `join`s after running the CPU half. The
    /// worker is spawned ONCE on first use.
    ///
    /// SAFETY: `out`/`x`/`w` MUST outlive the returned `Pending` (the caller MUST
    /// `join()` before they go out of scope or are read), `out[0..n_gpu)` and
    /// `w[0 .. n_gpu*bytes_per_row]` MUST be DISJOINT from any range the caller
    /// concurrently touches, and the caller MUST NOT read `out[0..n_gpu)` until
    /// after `join()`. The race call sites uphold all three. Sequential dispatch
    /// is also required (one job in flight): the call sites issue exactly one
    /// `dispatch` per matvec and `join()` before the next, so `state == IDLE`
    /// holds on entry.
    pub unsafe fn dispatch(
        kind: Kind,
        out: &mut [f32],
        x: &[f32],
        w: &[u8],
        n_gpu: usize,
        d: usize,
    ) -> Pending {
        let ctrl = LANE.get_or_init(|| {
            let ctrl = Arc::new(Control {
                state: AtomicU8::new(IDLE),
                result: AtomicBool::new(false),
                job: UnsafeCell::new(Job {
                    kind: Kind::Q8_0,
                    out_ptr: std::ptr::null_mut(),
                    x_ptr: std::ptr::null(),
                    x_len: 0,
                    w_ptr: std::ptr::null(),
                    w_len: 0,
                    n_gpu: 0,
                    d: 0,
                }),
            });
            let worker_ctrl = Arc::clone(&ctrl);
            std::thread::Builder::new()
                .name("gpu-race-lane".to_string())
                .spawn(move || worker(worker_ctrl))
                .expect("spawn gpu-race-lane worker");
            ctrl
        });
        // Publish the job fields. SAFETY: `state == IDLE` here (sequential
        // dispatch — see fn doc), so the worker is not touching `job`; these
        // plain writes are ordered-before the `store(SUBMITTED, Release)` below,
        // which publishes them to the worker.
        unsafe {
            *ctrl.job.get() = Job {
                kind,
                out_ptr: out.as_mut_ptr(),
                x_ptr: x.as_ptr(),
                x_len: x.len(),
                w_ptr: w.as_ptr(),
                w_len: w.len(),
                n_gpu,
                d,
            };
        }
        // Release: hands the job fields off to the worker's Acquire spin.
        ctrl.state.store(SUBMITTED, Ordering::Release);
        Pending {
            ctrl: Arc::clone(ctrl),
        }
    }
}

pub fn mat_vec_q8_0(out: &mut [f32], x: &[f32], w: &[u8], n: usize, d: usize) {
    // GPU fast path (cuBLAS on an L4) when built with `--features cuda` and a
    // CUDA device is present at runtime; otherwise this is a no-op that returns
    // false and we run the CPU kernel below. Numerically equivalent (last-bit).
    #[cfg(all(feature = "cuda", not(target_arch = "wasm32")))]
    {
        // MESH_GPU_CPU_RACE=1 (additive, DEFAULT OFF): split rows GPU‖CPU and run
        // both memory buses concurrently. Decode-only (n>=2, d%32==0); on false
        // (flag off / kernel unavailable / wrong shape) falls through unchanged.
        if gpu_cpu_race_enabled()
            && crate::cuda_matmul::q8k_race_ready(n, d, w.len())
        {
            if let Some(k) = gpu_cpu_race_split(n) {
                let blocks_per_row = d / 32;
                let bytes_per_row = blocks_per_row * 34;
                let (out_gpu, out_cpu) = out[..n].split_at_mut(k);
                // GPU rows [0..k): weight prefix w[0 .. k*bpr]; CPU rows [k..n):
                // weight suffix. Both are exact prefixes/suffixes of the row-major
                // buffer, so each kernel sees a contiguous, correctly-aligned
                // weight slice for its own rows.
                let (w_gpu, w_cpu) = w.split_at(k * bytes_per_row);
                // Dispatch the GPU half (rows [0..k)) to the STANDING worker — no
                // per-call thread spawn. SAFETY: `out_gpu`/`x`/`w_gpu` live for the
                // whole block and we `join()` before reading `out_gpu`; the GPU
                // half's `out_gpu`/`w_gpu` ranges are DISJOINT from the CPU half's
                // `out_cpu`/`w_cpu` (split_at boundary), so the lanes never alias.
                let pending = unsafe {
                    gpu_race_lane::dispatch(gpu_race_lane::Kind::Q8_0, out_gpu, x, w_gpu, k, d)
                };
                // CPU half on the main thread (rows [k..n)) — overlaps the GPU half.
                out_cpu.par_iter_mut().enumerate().for_each(|(i, o)| {
                    let rp = unsafe { w_cpu.as_ptr().add(i * bytes_per_row) };
                    *o = mat_vec_q8_0_row(x, rp, blocks_per_row, d);
                });
                // Join the GPU half; on a kernel miss compute its range on the CPU
                // so the row set is never left unwritten.
                if !pending.join() {
                    out_gpu.par_iter_mut().enumerate().for_each(|(i, o)| {
                        let rp = unsafe { w_gpu.as_ptr().add(i * bytes_per_row) };
                        *o = mat_vec_q8_0_row(x, rp, blocks_per_row, d);
                    });
                }
                return;
            }
        }
        // MESH_GPU_Q8K=1 (additive, default OFF): custom in-kernel Q8 dequant-GEMV
        // for decode (reads RAW Q8 ~7.7 GB, not the ~14.5 GB f16 set). Tried FIRST;
        // on false (flag off / unavailable / any error) falls through unchanged.
        // out may be batch-capacity-sized (> n); GPU dtoh needs an exact-n dst.
        if crate::cuda_matmul::try_mat_vec_q8_0_kernel(&mut out[..n], x, w, n, d) {
            return;
        }
        if crate::cuda_matmul::try_mat_vec_q8_0(&mut out[..n], x, w, n, d) {
            return;
        }
    }
    let blocks_per_row = d.div_ceil(32);
    let expected_len = n * blocks_per_row * 34;
    if w.len() < expected_len {
        panic!(
            "[mat_vec_q8_0] WEIGHT BUFFER TOO SMALL: need {} bytes ({} rows x {} bpr x 34), have {}",
            expected_len, n, blocks_per_row, w.len()
        );
    }
    out[..n].par_iter_mut().enumerate().for_each(|(i, o)| {
        let row_ptr = unsafe { w.as_ptr().add(i * blocks_per_row * 34) };
        *o = mat_vec_q8_0_row(x, row_ptr, blocks_per_row, d);
    });
}

/// Q5_K dequantization for one row. Mirrors the implementation in
/// llama.cpp/ggml-quants.c.
pub fn dequantize_q5k_row(out: &mut [f32], w: &[u8], row_idx: usize, d: usize) {
    const QUANT_BLOCK_ELEMS: usize = 256;
    const Q5K_BLOCK_BYTES: usize = 176;
    let bpr = d / QUANT_BLOCK_ELEMS;
    let row_off = row_idx * bpr * Q5K_BLOCK_BYTES;
    for b in 0..bpr {
        let bp_off = row_off + b * Q5K_BLOCK_BYTES;
        let bp = &w[bp_off..bp_off + Q5K_BLOCK_BYTES];
        let o = b * QUANT_BLOCK_ELEMS;
        let d_val = f16_to_f32(u16::from_le_bytes([bp[0], bp[1]]));
        let dmin = f16_to_f32(u16::from_le_bytes([bp[2], bp[3]]));
        let scales = &bp[4..16];
        let qh = &bp[16..48];
        let ql = &bp[48..176];

        let mut u1: u8 = 1;
        let mut u2: u8 = 2;
        let mut is: usize = 0;
        for group in 0..4 {
            let (sc1, m1) = get_scale_min_k4(is, scales);
            is += 1;
            let (sc2, m2) = get_scale_min_k4(is, scales);
            is += 1;
            let d1 = d_val * sc1;
            let mm1 = dmin * m1;
            let d2 = d_val * sc2;
            let mm2 = dmin * m2;
            let q_off = group * 32;
            let base = o + group * 64;
            for l in 0..32 {
                let q = ql[q_off + l];
                let h = qh[l];
                let lo = (q & 0xf) as u32 + if h & u1 != 0 { 16 } else { 0 };
                let hi = (q >> 4) as u32 + if h & u2 != 0 { 16 } else { 0 };
                out[base + l] = d1 * lo as f32 - mm1;
                out[base + 32 + l] = d2 * hi as f32 - mm2;
            }
            u1 <<= 2;
            u2 <<= 2;
        }
    }
}

/// Fused Q5_K row dot (aarch64 NEON): the Q4_K kernel structure plus the
/// 5th bit — `qh[l]` bit `2*group` (lo nibbles) / `2*group + 1` (hi
/// nibbles) adds 16 to the quant before scaling. Four independent
/// accumulators, same as the other row kernels. Block = 176 B / 256 elems:
/// d f16 @0, dmin f16 @2, scales[12] @4, qh[32] @16, ql[128] @48.
#[cfg(target_arch = "aarch64")]
#[inline(always)]
fn mat_vec_q5k_row(x: &[f32], row_ptr: *const u8, blocks_per_row: usize) -> f32 {
    use std::arch::aarch64::*;
    unsafe {
        let sixteen = vdup_n_u8(16);
        let mut sum_v0 = vdupq_n_f32(0.0);
        let mut sum_v1 = vdupq_n_f32(0.0);
        let mut sum_v2 = vdupq_n_f32(0.0);
        let mut sum_v3 = vdupq_n_f32(0.0);
        for b in 0..blocks_per_row {
            let block_ptr = row_ptr.add(b * 176);
            let x_offset = b * 256;
            let d_val = f16_to_f32(u16::from_le_bytes([*block_ptr, *block_ptr.add(1)]));
            let dmin = f16_to_f32(u16::from_le_bytes([*block_ptr.add(2), *block_ptr.add(3)]));
            let scales = std::slice::from_raw_parts(block_ptr.add(4), 12);
            let qh = block_ptr.add(16);
            let ql = block_ptr.add(48);

            for group in 0..4usize {
                let (sc1, m1) = get_scale_min_k4(group * 2, scales);
                let (sc2, m2) = get_scale_min_k4(group * 2 + 1, scales);
                let s1v = vdupq_n_f32(d_val * sc1);
                let b1v = vdupq_n_f32(-dmin * m1);
                let s2v = vdupq_n_f32(d_val * sc2);
                let b2v = vdupq_n_f32(-dmin * m2);
                let u1v = vdup_n_u8(1u8 << (2 * group));
                let u2v = vdup_n_u8(2u8 << (2 * group));

                let xp = x.as_ptr().add(x_offset + group * 64);

                for l in (0..32).step_by(8) {
                    let q_raw = vld1_u8(ql.add(group * 32 + l));
                    let qh_raw = vld1_u8(qh.add(l));
                    // lo/hi nibble + 16 where the matching qh bit is set.
                    let lo5 = vadd_u8(
                        vand_u8(q_raw, vdup_n_u8(0xf)),
                        vand_u8(vtst_u8(qh_raw, u1v), sixteen),
                    );
                    let hi5 = vadd_u8(
                        vshr_n_u8(q_raw, 4),
                        vand_u8(vtst_u8(qh_raw, u2v), sixteen),
                    );

                    let lo_u16 = vmovl_u8(lo5);
                    let lo_f32_0 = vcvtq_f32_u32(vmovl_u16(vget_low_u16(lo_u16)));
                    let lo_f32_1 = vcvtq_f32_u32(vmovl_u16(vget_high_u16(lo_u16)));
                    sum_v0 =
                        vfmaq_f32(sum_v0, vld1q_f32(xp.add(l)), vfmaq_f32(b1v, s1v, lo_f32_0));
                    sum_v1 = vfmaq_f32(
                        sum_v1,
                        vld1q_f32(xp.add(l + 4)),
                        vfmaq_f32(b1v, s1v, lo_f32_1),
                    );

                    let hi_u16 = vmovl_u8(hi5);
                    let hi_f32_0 = vcvtq_f32_u32(vmovl_u16(vget_low_u16(hi_u16)));
                    let hi_f32_1 = vcvtq_f32_u32(vmovl_u16(vget_high_u16(hi_u16)));
                    sum_v2 = vfmaq_f32(
                        sum_v2,
                        vld1q_f32(xp.add(32 + l)),
                        vfmaq_f32(b2v, s2v, hi_f32_0),
                    );
                    sum_v3 = vfmaq_f32(
                        sum_v3,
                        vld1q_f32(xp.add(32 + l + 4)),
                        vfmaq_f32(b2v, s2v, hi_f32_1),
                    );
                }
            }
        }
        vaddvq_f32(vaddq_f32(
            vaddq_f32(sum_v0, sum_v1),
            vaddq_f32(sum_v2, sum_v3),
        ))
    }
}

/// Q5_K matvec. aarch64 runs the fused NEON row kernel (rayon above
/// `RAYON_THRESHOLD` rows); other arches run a parallel dequant-row + f32
/// dot. Either way this replaces the previous SERIAL dequant+dot loop in
/// `mat_vec_dispatch_batch` — Q5_K was the only quant format with no
/// parallel, no fused matvec on any arch.
pub fn mat_vec_q5k(out: &mut [f32], x: &[f32], w: &[u8], n: usize, d: usize) {
    let bpr = d / 256;
    #[cfg(target_arch = "aarch64")]
    {
        let w_base = w.as_ptr();
        if n <= RAYON_THRESHOLD {
            for i in 0..n {
                let rp = unsafe { w_base.add(i * bpr * 176) };
                out[i] = mat_vec_q5k_row(x, rp, bpr);
            }
        } else {
            let w_addr = w_base as usize;
            out[..n]
                .par_chunks_mut(64)
                .enumerate()
                .for_each(|(ci, chunk)| {
                    let start_idx = ci * 64;
                    for (i, o) in chunk.iter_mut().enumerate() {
                        let rp = unsafe { (w_addr as *const u8).add((start_idx + i) * bpr * 176) };
                        *o = mat_vec_q5k_row(x, rp, bpr);
                    }
                });
        }
    }
    #[cfg(not(target_arch = "aarch64"))]
    {
        let _ = bpr;
        if n <= RAYON_THRESHOLD {
            let mut row_buf = vec![0.0f32; d];
            for i in 0..n {
                dequantize_q5k_row(&mut row_buf, w, i, d);
                out[i] = dot_product(&row_buf, x);
            }
        } else {
            out[..n]
                .par_chunks_mut(64)
                .enumerate()
                .for_each_init(
                    || vec![0.0f32; d],
                    |row_buf, (ci, chunk)| {
                        let start_idx = ci * 64;
                        for (i, o) in chunk.iter_mut().enumerate() {
                            dequantize_q5k_row(row_buf, w, start_idx + i, d);
                            *o = dot_product(row_buf, x);
                        }
                    },
                );
        }
    }
}

pub fn mat_vec_q5k_batch(out: &mut [&mut [f32]], xs: &[&[f32]], w: &[u8], _n: usize, d: usize) {
    let n_rows = out[0].len();
    let bpr = d / 256;
    let expected_len = n_rows * bpr * 176;
    if w.len() < expected_len {
        panic!(
            "[mat_vec_q5k_batch] WEIGHT BUFFER TOO SMALL: need {} bytes ({} rows x {} bpr x 176), have {}",
            expected_len, n_rows, bpr, w.len()
        );
    }
    let n_batch = xs.len();
    let out_ptrs: Vec<usize> = out.iter_mut().map(|s| s.as_mut_ptr() as usize).collect();

    // Parallelize over output rows. For each row, dequantize then dot.
    // `for_each_init` amortizes the dequant scratch across each rayon
    // task-split instead of re-allocating it per row.
    (0..n_rows).into_par_iter().for_each_init(
        || vec![0.0f32; d],
        |row_buf, i| {
            dequantize_q5k_row(row_buf, w, i, d);
            for r in 0..n_batch {
                let row_out = unsafe { (out_ptrs[r] as *mut f32).add(i) };
                unsafe {
                    *row_out = dot_product(row_buf, xs[r]);
                }
            }
        },
    );
}

pub fn mat_vec_q8_0_batch(out: &mut [&mut [f32]], xs: &[&[f32]], w: &[u8], n: usize, d: usize) {
    // GPU fast path: pack into one rows_shared GEMM instead of `tokens`
    // independent GEMVs (one weight residency lookup, one cuBLAS launch).
    #[cfg(all(feature = "cuda", not(target_arch = "wasm32")))]
    {
        let tokens = xs.len();
        if crate::cuda_matmul::gpu_wants(tokens) {
            let flat_x: Vec<f32> = xs.iter().flat_map(|s| s.iter().copied()).collect();
            let mut flat_out = vec![0.0f32; tokens * n];
            if crate::cuda_matmul::try_mat_vec_q8_0_rows_shared(
                &mut flat_out, &flat_x, w, n, d, tokens,
            ) {
                for (t, dst) in out.iter_mut().enumerate() {
                    dst[..n].copy_from_slice(&flat_out[t * n..(t + 1) * n]);
                }
                return;
            }
        }
    }
    let n_batch = xs.len();
    if n_batch >= BATCH_DEQUANT_ONCE_MIN {
        // Dequantize each weight row ONCE and reuse across lanes — the
        // per-token loop below re-decodes every Q8 row n_batch times (and
        // pays n_batch rayon dispatches).
        let out_ptrs: Vec<usize> = out.iter_mut().map(|s| s.as_mut_ptr() as usize).collect();
        (0..n).into_par_iter().for_each_init(
            || vec![0.0f32; d],
            |row_buf, i| {
                dequantize_q8_0_row(row_buf, w, i, d);
                for r in 0..n_batch {
                    let row_out = unsafe { (out_ptrs[r] as *mut f32).add(i) };
                    unsafe {
                        *row_out = dot_product(row_buf, xs[r]);
                    }
                }
            },
        );
        return;
    }
    for (out_slice, x) in out.iter_mut().zip(xs.iter()) {
        mat_vec_q8_0(out_slice, x, w, n, d);
    }
}

/// Row-shared batched Q8_0 matmul: out[t*n + r] = sum_c w[r,c]*xs[t*d + c].
/// `xs` is a flat [tokens*d] buffer, `out` is a flat [tokens*n] buffer. Each Q8
/// weight row is dequantized exactly ONCE and reused across all `tokens`
/// columns. Parallelized over the `n` output rows. This is the hot path for
/// FLUX DiT block projections where many tokens share one weight.
pub fn mat_vec_q8_0_rows_shared(out: &mut [f32], xs: &[f32], w: &[u8], n: usize, d: usize, tokens: usize) {
    // GPU fast path: this is THE FLUX/LTX DiT hot path. On an L4 the resident
    // dequantized weights live in VRAM (~300 GB/s) so the per-step re-reads no
    // longer stream from the ~4.5 GB/s mmap. Falls back to the CPU kernel when
    // the `cuda` feature is off, no device is present, or the op errors.
    #[cfg(all(feature = "cuda", not(target_arch = "wasm32")))]
    {
        if crate::cuda_matmul::try_mat_vec_q8_0_rows_shared(out, xs, w, n, d, tokens) {
            return;
        }
    }
    let blocks_per_row = d.div_ceil(32);
    let expected_len = n * blocks_per_row * 34;
    assert!(
        w.len() >= expected_len,
        "[mat_vec_q8_0_rows_shared] weight buffer too small: need {expected_len}, have {}",
        w.len()
    );
    assert_eq!(xs.len(), tokens * d, "xs length mismatch");
    assert_eq!(out.len(), tokens * n, "out length mismatch");
    let out_ptr = out.as_mut_ptr() as usize;
    // Parallelize over output rows (each `r` writes a disjoint `t*n + r` column
    // of `out`). The Q8 weight row is dequantized ONCE into a scratch buffer and
    // reused across all `tokens` columns via the NEON `dot_product`. This kernel
    // is already SIMD-vectorized + thread-parallel; the practical floor for the
    // full FLUX DiT is mmap page-fault IO (12.6 GB weights on a 16 GB box), not
    // this arithmetic — see flux-matmul-bench (cold sweep ~4.5 GB/s).
    // `for_each_init` amortizes the dequant scratch across each rayon
    // task-split instead of re-allocating it per row.
    (0..n).into_par_iter().for_each_init(
        || vec![0.0f32; d],
        |row, r| {
            dequantize_q8_0_row(row, w, r, d);
            for t in 0..tokens {
                let val = dot_product(row, &xs[t * d..t * d + d]);
                unsafe {
                    *((out_ptr as *mut f32).add(t * n + r)) = val;
                }
            }
        },
    );
}

#[cfg(target_arch = "aarch64")]
#[inline(always)]
#[allow(clippy::not_unsafe_ptr_arg_deref)]
pub fn mat_vec_q6k_row(x: &[f32], row_ptr: *const u8, blocks_per_row: usize) -> f32 {
    unsafe {
        // Four independent accumulators (one per q6_accumulate8 call site)
        // break the FMA dependency chain — throughput-bound, not latency-bound.
        let mut sum_v0 = vdupq_n_f32(0.0);
        let mut sum_v1 = vdupq_n_f32(0.0);
        let mut sum_v2 = vdupq_n_f32(0.0);
        let mut sum_v3 = vdupq_n_f32(0.0);
        for b in 0..blocks_per_row {
            let bp = row_ptr.add(b * 210);
            let d_val = f16_to_f32(u16::from_le_bytes([*bp.add(208), *bp.add(209)]));
            let xo = b * 256;
            for group in 0..2 {
                let ns = group * 128;
                let ql = bp.add(group * 64);
                let qh = bp.add(128 + group * 32);
                let sc = bp.add(192 + group * 8) as *const i8;
                let xb = x.as_ptr().add(xo + ns);
                for l in (0..32).step_by(8) {
                    let qhv = vld1_u8(qh.add(l));
                    let ql1 = vld1_u8(ql.add(l));
                    let ql2 = vld1_u8(ql.add(l + 32));
                    let low_mask = vdup_n_u8(0x0f);
                    let high_mask = vdup_n_u8(0x03);

                    let q1 = vorr_u8(
                        vand_u8(ql1, low_mask),
                        vshl_n_u8(vand_u8(qhv, high_mask), 4),
                    );
                    let q2 = vorr_u8(
                        vand_u8(ql2, low_mask),
                        vshl_n_u8(vand_u8(vshr_n_u8(qhv, 2), high_mask), 4),
                    );
                    let q3 = vorr_u8(
                        vshr_n_u8(ql1, 4),
                        vshl_n_u8(vand_u8(vshr_n_u8(qhv, 4), high_mask), 4),
                    );
                    let q4 = vorr_u8(
                        vshr_n_u8(ql2, 4),
                        vshl_n_u8(vand_u8(vshr_n_u8(qhv, 6), high_mask), 4),
                    );

                    let is = l >> 4;
                    q6_accumulate8(
                        &mut sum_v0,
                        xb.add(l),
                        q1,
                        vdupq_n_f32(d_val * *sc.add(is) as f32),
                    );
                    q6_accumulate8(
                        &mut sum_v1,
                        xb.add(l + 32),
                        q2,
                        vdupq_n_f32(d_val * *sc.add(is + 2) as f32),
                    );
                    q6_accumulate8(
                        &mut sum_v2,
                        xb.add(l + 64),
                        q3,
                        vdupq_n_f32(d_val * *sc.add(is + 4) as f32),
                    );
                    q6_accumulate8(
                        &mut sum_v3,
                        xb.add(l + 96),
                        q4,
                        vdupq_n_f32(d_val * *sc.add(is + 6) as f32),
                    );
                }
            }
        }
        vaddvq_f32(vaddq_f32(
            vaddq_f32(sum_v0, sum_v1),
            vaddq_f32(sum_v2, sum_v3),
        ))
    }
}

#[cfg(target_arch = "aarch64")]
#[inline(always)]
unsafe fn q6_accumulate8(
    sum_v: &mut float32x4_t,
    x_ptr: *const f32,
    q: uint8x8_t,
    scale: float32x4_t,
) {
    let q_i16 = vsubq_s16(vreinterpretq_s16_u16(vmovl_u8(q)), vdupq_n_s16(32));
    let q_lo = vcvtq_f32_s32(vmovl_s16(vget_low_s16(q_i16)));
    let q_hi = vcvtq_f32_s32(vmovl_s16(vget_high_s16(q_i16)));
    *sum_v = vfmaq_f32(*sum_v, vld1q_f32(x_ptr), vmulq_f32(scale, q_lo));
    *sum_v = vfmaq_f32(*sum_v, vld1q_f32(x_ptr.add(4)), vmulq_f32(scale, q_hi));
}

// wasm32 SIMD branch. Mirrors the aarch64 NEON layout one-for-one:
//
// Per block (210 B, 256 elements):
//   ql (128 B) = low 4-bit nibbles
//   qh (64  B) = high 2-bit pairs
//   sc (16  i8) = signed sub-scales
//   d  (f16)    = super-scale at offset 208
//
// Per group (group ∈ {0,1}):
//   ql_g = ql + group*64 (slice of 64 bytes → 32 paired bytes)
//   qh_g = qh + group*32
//   sc_g = sc + group*8
//   xb   = x + xo + group*128
//
// Each `l` in 0..32 yields four 6-bit values:
//   q1 = (ql_g[l]    & 0x0f) | ((qh_g[l] >> 0 & 3) << 4) - 32 → xb[l]
//   q2 = (ql_g[l+32] & 0x0f) | ((qh_g[l] >> 2 & 3) << 4) - 32 → xb[l+32]
//   q3 = (ql_g[l]    >> 4 ) | ((qh_g[l] >> 4 & 3) << 4) - 32 → xb[l+64]
//   q4 = (ql_g[l+32] >> 4 ) | ((qh_g[l] >> 6 & 3) << 4) - 32 → xb[l+96]
// Sub-scale index: is = l >> 4, picking sc_g[is], sc_g[is+2], sc_g[is+4], sc_g[is+6].
//
// SIMD strategy (mirrors the wave-22 Q4_K wasm32 SIMD path):
//   - `f32x4` accumulator (4 lanes), zero-initialised, summed at end.
//   - Inner unroll: process 8 `l`-steps per pass (l in 0..32 step 8). Within
//     each pass we materialise 8 dequantised f32 values for each of the 4
//     positions (l..l+8 covers 8 entries at xb[l], 8 at xb[l+32], etc.) into
//     stack arrays, then `v128_load` 4× lanes per slot (twice — first half +
//     second half), `f32x4_mul` against the residual, `f32x4_add` into the
//     accumulator.
//   - Sub-scale `is = l >> 4` is constant across each 16-wide chunk, so we
//     hoist the per-position scalar `d_val * sc_g[is + offset]` out of the
//     8-wide loop and re-broadcast inside.
//
// 2026-04-27 BUG NOTES: the prior failed SIMD attempt used an `f32x4_splat`
// for the scale and then `f32x4_extract_lane(sum_v, 0) * 4.0` style horizontal
// reduce — which double-counted the splatted scale. This rewrite avoids that
// by:
//   1. Computing `q_i32 - 32` per element and converting to f32 individually
//      (no splatted shared scale across lanes other than the per-(l>>4) scale,
//      which is genuinely shared).
//   2. Using a clean `[res[0]+res[1]+res[2]+res[3]]` horizontal reduce at the
//      very end, identical to the Q4_K wasm32 path.
// Smoke-tested via the new `mat_vec_q6k_wasm_simd_matches_scalar` test below.
#[cfg(target_arch = "wasm32")]
#[inline(always)]
pub fn mat_vec_q6k_row(x: &[f32], row_ptr: *const u8, blocks_per_row: usize) -> f32 {
    // BUG-FIX 2026-04-27: same 4× SIMD splat-and-sum-all-lanes bug as the
    // aarch64 path. Replaced with scalar accumulation. See aarch64 variant
    // for the full diagnosis.
    unsafe {
        use std::arch::wasm32::*;

        let mut sum_v = f32x4_splat(0.0);
        for b in 0..blocks_per_row {
            let bp = row_ptr.add(b * 210);
            let xo = b * 256;
            let d_val = f16_to_f32(u16::from_le_bytes([*bp.add(208), *bp.add(209)]));
            for group in 0..2 {
                let ns = group * 128;
                let ql = bp.add(group * 64);
                let qh = bp.add(128 + group * 32);
                let sc = bp.add(192 + group * 8) as *const i8;
                let xb = x.as_ptr().add(xo + ns);
                // Process 8 l-steps per pass (matches NEON `step_by(8)`).
                // Each pass touches xb[l..l+8], xb[l+32..l+40], etc.
                for l in (0..32).step_by(8) {
                    let is = l >> 4; // constant for this 8-wide chunk
                    let s0 = d_val * (*sc.add(is) as f32);
                    let s1 = d_val * (*sc.add(is + 2) as f32);
                    let s2 = d_val * (*sc.add(is + 4) as f32);
                    let s3 = d_val * (*sc.add(is + 6) as f32);

                    // Materialise 8 dequantised f32 values per slot, mirroring
                    // the NEON `vmovl_u8` widen pattern but via stack arrays.
                    let mut q1f = [0.0f32; 8];
                    let mut q2f = [0.0f32; 8];
                    let mut q3f = [0.0f32; 8];
                    let mut q4f = [0.0f32; 8];
                    for k in 0..8 {
                        let qhv = *qh.add(l + k) as i32;
                        let ql1 = *ql.add(l + k) as i32;
                        let ql2 = *ql.add(l + k + 32) as i32;
                        q1f[k] = (((ql1 & 0xF) | ((qhv & 3) << 4)) - 32) as f32;
                        q2f[k] = (((ql2 & 0xF) | (((qhv >> 2) & 3) << 4)) - 32) as f32;
                        q3f[k] = (((ql1 >> 4) | (((qhv >> 4) & 3) << 4)) - 32) as f32;
                        q4f[k] = (((ql2 >> 4) | (((qhv >> 6) & 3) << 4)) - 32) as f32;
                    }

                    let s0v = f32x4_splat(s0);
                    let s1v = f32x4_splat(s1);
                    let s2v = f32x4_splat(s2);
                    let s3v = f32x4_splat(s3);

                    // Slot 1: xb[l..l+8] * (s0 * q1)
                    let q1_lo = v128_load(q1f.as_ptr() as *const v128);
                    let q1_hi = v128_load(q1f.as_ptr().add(4) as *const v128);
                    let xv0 = v128_load(xb.add(l) as *const v128);
                    let xv1 = v128_load(xb.add(l + 4) as *const v128);
                    sum_v = f32x4_add(sum_v, f32x4_mul(xv0, f32x4_mul(s0v, q1_lo)));
                    sum_v = f32x4_add(sum_v, f32x4_mul(xv1, f32x4_mul(s0v, q1_hi)));

                    // Slot 2: xb[l+32..l+40] * (s1 * q2)
                    let q2_lo = v128_load(q2f.as_ptr() as *const v128);
                    let q2_hi = v128_load(q2f.as_ptr().add(4) as *const v128);
                    let xv2 = v128_load(xb.add(l + 32) as *const v128);
                    let xv3 = v128_load(xb.add(l + 36) as *const v128);
                    sum_v = f32x4_add(sum_v, f32x4_mul(xv2, f32x4_mul(s1v, q2_lo)));
                    sum_v = f32x4_add(sum_v, f32x4_mul(xv3, f32x4_mul(s1v, q2_hi)));

                    // Slot 3: xb[l+64..l+72] * (s2 * q3)
                    let q3_lo = v128_load(q3f.as_ptr() as *const v128);
                    let q3_hi = v128_load(q3f.as_ptr().add(4) as *const v128);
                    let xv4 = v128_load(xb.add(l + 64) as *const v128);
                    let xv5 = v128_load(xb.add(l + 68) as *const v128);
                    sum_v = f32x4_add(sum_v, f32x4_mul(xv4, f32x4_mul(s2v, q3_lo)));
                    sum_v = f32x4_add(sum_v, f32x4_mul(xv5, f32x4_mul(s2v, q3_hi)));

                    // Slot 4: xb[l+96..l+104] * (s3 * q4)
                    let q4_lo = v128_load(q4f.as_ptr() as *const v128);
                    let q4_hi = v128_load(q4f.as_ptr().add(4) as *const v128);
                    let xv6 = v128_load(xb.add(l + 96) as *const v128);
                    let xv7 = v128_load(xb.add(l + 100) as *const v128);
                    sum_v = f32x4_add(sum_v, f32x4_mul(xv6, f32x4_mul(s3v, q4_lo)));
                    sum_v = f32x4_add(sum_v, f32x4_mul(xv7, f32x4_mul(s3v, q4_hi)));
                }
            }
        }
        // Horizontal reduce 4 lanes → scalar.
        let mut res = [0.0f32; 4];
        v128_store(res.as_mut_ptr() as *mut v128, sum_v);
        res[0] + res[1] + res[2] + res[3]
    }
}

/// Scalar Q6_K row matvec — portable reference + the x86 non-AVX2 fallback. The
/// numeric source of truth for `q6k_row_matches_kernel`.
#[cfg(not(any(target_arch = "aarch64", target_arch = "wasm32")))]
#[inline]
fn q6k_row_scalar(x: &[f32], row_ptr: *const u8, blocks_per_row: usize) -> f32 {
    let mut row_sum = 0.0f32;
    let x_ptr = x.as_ptr();
    unsafe {
        for b in 0..blocks_per_row {
            let bp = row_ptr.add(b * 210);
            let xo = b * 256;
            let d_val = f16_to_f32(u16::from_le_bytes([*bp.add(208), *bp.add(209)]));

            for group in 0..2 {
                let ns = group * 128;
                let ql = bp.add(group * 64);
                let qh = bp.add(128 + group * 32);
                let sc = bp.add(192 + group * 8) as *const i8;
                let xb = x_ptr.add(xo + ns);

                let mut ds = [0.0f32; 8];
                for i in 0..8 {
                    ds[i] = d_val * (*sc.add(i) as f32);
                }

                for l in 0..32 {
                    let qhv = *qh.add(l) as i32;
                    let ql1 = *ql.add(l) as i32;
                    let ql2 = *ql.add(l + 32) as i32;

                    let q1 = ((ql1 & 0xF) | ((qhv & 3) << 4)) - 32;
                    let q2 = ((ql2 & 0xF) | (((qhv >> 2) & 3) << 4)) - 32;
                    let q3 = ((ql1 >> 4) | (((qhv >> 4) & 3) << 4)) - 32;
                    let q4 = ((ql2 >> 4) | (((qhv >> 6) & 3) << 4)) - 32;

                    let is = l >> 4;
                    row_sum += *xb.add(l) * ds[is] * q1 as f32;
                    row_sum += *xb.add(l + 32) * ds[is + 2] * q2 as f32;
                    row_sum += *xb.add(l + 64) * ds[is + 4] * q3 as f32;
                    row_sum += *xb.add(l + 96) * ds[is + 6] * q4 as f32;
                }
            }
        }
    }
    row_sum
}

/// x86_64 Q6_K row matvec. The lm_head/embed are Q6_K in Q4_K_M (hit every token),
/// so this was the second scalar gap on the native serving path. AVX2 hot path,
/// runtime-dispatched; non-AVX2 x86 uses the scalar reference.
#[cfg(target_arch = "x86_64")]
#[inline(always)]
#[allow(dead_code)]
pub fn mat_vec_q6k_row(x: &[f32], row_ptr: *const u8, blocks_per_row: usize) -> f32 {
    if std::is_x86_feature_detected!("avx2") && std::is_x86_feature_detected!("fma") {
        unsafe { q6k_row_avx2(x, row_ptr, blocks_per_row) }
    } else {
        q6k_row_scalar(x, row_ptr, blocks_per_row)
    }
}

/// Generic (non-aarch64/wasm/x86) Q6_K row matvec → scalar reference.
#[cfg(not(any(target_arch = "aarch64", target_arch = "wasm32", target_arch = "x86_64")))]
#[inline(always)]
#[allow(dead_code)]
pub fn mat_vec_q6k_row(x: &[f32], row_ptr: *const u8, blocks_per_row: usize) -> f32 {
    q6k_row_scalar(x, row_ptr, blocks_per_row)
}

/// AVX2+FMA Q6_K row matvec (x86_64) — 8-wide FMA over `dequant · x`, mirroring the
/// scalar reference exactly. The 6-bit reconstruction (`ql` nibble | `qh` 2-bit pair,
/// −32 bias) stays scalar into a stack array then `loadu`'d (cheap vs the FLOP-heavy
/// accumulate); `is = l>>4` is constant per 8-wide chunk so the four sub-scales are
/// broadcast. Same math as `q6k_row_scalar`; sound-but-reassociated, certified by
/// `q6k_row_matches_kernel` on a real AVX2 host.
#[cfg(target_arch = "x86_64")]
#[target_feature(enable = "avx2,fma")]
unsafe fn q6k_row_avx2(x: &[f32], row_ptr: *const u8, blocks_per_row: usize) -> f32 {
    use std::arch::x86_64::*;
    let x_ptr = x.as_ptr();
    let mut acc = _mm256_setzero_ps();
    for b in 0..blocks_per_row {
        let bp = row_ptr.add(b * 210);
        let xo = b * 256;
        let d_val = f16_to_f32(u16::from_le_bytes([*bp.add(208), *bp.add(209)]));
        for group in 0..2 {
            let ns = group * 128;
            let ql = bp.add(group * 64);
            let qh = bp.add(128 + group * 32);
            let sc = bp.add(192 + group * 8) as *const i8;
            let xb = x_ptr.add(xo + ns);
            let mut ds = [0.0f32; 8];
            for i in 0..8 {
                ds[i] = d_val * (*sc.add(i) as f32);
            }
            let mut l = 0usize;
            while l < 32 {
                let is = l >> 4;
                let s0 = _mm256_set1_ps(ds[is]);
                let s1 = _mm256_set1_ps(ds[is + 2]);
                let s2 = _mm256_set1_ps(ds[is + 4]);
                let s3 = _mm256_set1_ps(ds[is + 6]);
                let mut q1a = [0.0f32; 8];
                let mut q2a = [0.0f32; 8];
                let mut q3a = [0.0f32; 8];
                let mut q4a = [0.0f32; 8];
                for k in 0..8 {
                    let qhv = *qh.add(l + k) as i32;
                    let ql1 = *ql.add(l + k) as i32;
                    let ql2 = *ql.add(l + k + 32) as i32;
                    q1a[k] = (((ql1 & 0xF) | ((qhv & 3) << 4)) - 32) as f32;
                    q2a[k] = (((ql2 & 0xF) | (((qhv >> 2) & 3) << 4)) - 32) as f32;
                    q3a[k] = (((ql1 >> 4) | (((qhv >> 4) & 3) << 4)) - 32) as f32;
                    q4a[k] = (((ql2 >> 4) | (((qhv >> 6) & 3) << 4)) - 32) as f32;
                }
                let w1 = _mm256_mul_ps(s0, _mm256_loadu_ps(q1a.as_ptr()));
                let w2 = _mm256_mul_ps(s1, _mm256_loadu_ps(q2a.as_ptr()));
                let w3 = _mm256_mul_ps(s2, _mm256_loadu_ps(q3a.as_ptr()));
                let w4 = _mm256_mul_ps(s3, _mm256_loadu_ps(q4a.as_ptr()));
                acc = _mm256_fmadd_ps(_mm256_loadu_ps(xb.add(l)), w1, acc);
                acc = _mm256_fmadd_ps(_mm256_loadu_ps(xb.add(l + 32)), w2, acc);
                acc = _mm256_fmadd_ps(_mm256_loadu_ps(xb.add(l + 64)), w3, acc);
                acc = _mm256_fmadd_ps(_mm256_loadu_ps(xb.add(l + 96)), w4, acc);
                l += 8;
            }
        }
    }
    let mut t = [0.0f32; 8];
    _mm256_storeu_ps(t.as_mut_ptr(), acc);
    t[0] + t[1] + t[2] + t[3] + t[4] + t[5] + t[6] + t[7]
}

pub fn mat_vec_q6k(out: &mut [f32], x: &[f32], w: &[u8], n: usize, d: usize) {
    // GPU fast path — see mat_vec_q4k for the gating contract.
    #[cfg(all(feature = "cuda", not(target_arch = "wasm32")))]
    {
        // MESH_GPU_CPU_RACE=1 (additive, DEFAULT OFF): GPU‖CPU row split. See the
        // module note above mat_vec_q8_0. Q6_K superblock = 210 bytes / 256 elems.
        if gpu_cpu_race_enabled() && crate::cuda_matmul::q6k_race_ready(n, d, w.len()) {
            if let Some(k) = gpu_cpu_race_split(n) {
                let bpr = d / 256;
                let bytes_per_row = bpr * 210;
                let (out_gpu, out_cpu) = out[..n].split_at_mut(k);
                let (w_gpu, w_cpu) = w.split_at(k * bytes_per_row);
                // GPU half (rows [0..k)) to the standing worker — no spawn. SAFETY:
                // slices live for the block, joined before read, disjoint ranges.
                let pending = unsafe {
                    gpu_race_lane::dispatch(gpu_race_lane::Kind::Q6K, out_gpu, x, w_gpu, k, d)
                };
                out_cpu.par_iter_mut().enumerate().for_each(|(i, o)| {
                    let rp = unsafe { w_cpu.as_ptr().add(i * bytes_per_row) };
                    *o = mat_vec_q6k_row(x, rp, bpr);
                });
                if !pending.join() {
                    out_gpu.par_iter_mut().enumerate().for_each(|(i, o)| {
                        let rp = unsafe { w_gpu.as_ptr().add(i * bytes_per_row) };
                        *o = mat_vec_q6k_row(x, rp, bpr);
                    });
                }
                return;
            }
        }
        // MESH_GPU_Q4K=1 (additive, DEFAULT OFF): the SAME flag enables the Q6_K
        // kernel (Q4_K_M's ffn_down/attn_v tensors are Q6_K). Tried FIRST; on
        // false falls through to the existing cuBLAS/CPU path UNCHANGED.
        if crate::cuda_matmul::try_mat_vec_q6k_kernel(&mut out[..n], x, w, n, d) {
            return;
        }
        // out may be batch-capacity-sized (> n); GPU dtoh needs an exact-n dst.
        if crate::cuda_matmul::try_mat_vec_q6k(&mut out[..n], x, w, n, d) {
            return;
        }
    }
    let bpr = d / 256;
    let w_base = w.as_ptr();

    if n <= RAYON_THRESHOLD {
        for i in 0..n {
            let rp = unsafe { w_base.add(i * bpr * 210) };
            out[i] = mat_vec_q6k_row(x, rp, bpr);
        }
    } else {
        let w_addr = w_base as usize;
        out[..n]
            .par_chunks_mut(64)
            .enumerate()
            .for_each(|(ci, chunk)| {
                let start_idx = ci * 64;
                for i in (0..chunk.len()).step_by(2) {
                    if i + 1 < chunk.len() {
                        let gi = start_idx + i;
                        let rp0 = unsafe { (w_addr as *const u8).add(gi * bpr * 210) };
                        let rp1 = unsafe { (w_addr as *const u8).add((gi + 1) * bpr * 210) };
                        chunk[i] = mat_vec_q6k_row(x, rp0, bpr);
                        chunk[i + 1] = mat_vec_q6k_row(x, rp1, bpr);
                    } else {
                        let gi = start_idx + i;
                        let rp = unsafe { (w_addr as *const u8).add(gi * bpr * 210) };
                        chunk[i] = mat_vec_q6k_row(x, rp, bpr);
                    }
                }
            });
    }
}

#[inline(always)]
fn mat_vec_q6k_row_masked(
    x: &[f32],
    row_ptr: *const u8,
    blocks_per_row: usize,
    block_mask: &[u8],
) -> f32 {
    let mut row_sum = 0.0f32;
    for block in 0..blocks_per_row {
        if !active_mask_block(block_mask, block) {
            continue;
        }
        let x_start = block * 256;
        let x_end = x_start + 256;
        if x_end <= x.len() {
            let block_ptr = unsafe { row_ptr.add(block * 210) };
            row_sum += mat_vec_q6k_row(&x[x_start..x_end], block_ptr, 1);
        }
    }
    row_sum
}

pub fn mat_vec_q6k_masked(
    out: &mut [f32],
    x: &[f32],
    w: &[u8],
    n: usize,
    d: usize,
    block_mask: &[u8],
) {
    let bpr = d / 256;
    if !block_mask_has_skips(block_mask, bpr) {
        mat_vec_q6k(out, x, w, n, d);
        return;
    }

    let w_base = w.as_ptr();
    if n <= RAYON_THRESHOLD {
        for i in 0..n {
            let rp = unsafe { w_base.add(i * bpr * 210) };
            out[i] = mat_vec_q6k_row_masked(x, rp, bpr, block_mask);
        }
    } else {
        let w_addr = w_base as usize;
        out[..n]
            .par_chunks_mut(64)
            .enumerate()
            .for_each(|(ci, chunk)| {
                let start_idx = ci * 64;
                for (i, val) in chunk.iter_mut().enumerate() {
                    let gi = start_idx + i;
                    let rp = unsafe { (w_addr as *const u8).add(gi * bpr * 210) };
                    *val = mat_vec_q6k_row_masked(x, rp, bpr, block_mask);
                }
            });
    }
}

pub fn mat_vec_q6k_batch(out: &mut [&mut [f32]], xs: &[&[f32]], w: &[u8], _n: usize, d: usize) {
    let n_rows = out[0].len();
    // GPU fast path — see mat_vec_q4k_batch for the pack-after-gate pattern.
    #[cfg(all(feature = "cuda", not(target_arch = "wasm32")))]
    {
        let tokens = xs.len();
        if crate::cuda_matmul::gpu_wants(tokens) {
            let flat_x: Vec<f32> = xs.iter().flat_map(|s| s.iter().copied()).collect();
            let mut flat_out = vec![0.0f32; tokens * n_rows];
            if crate::cuda_matmul::try_mat_vec_q6k_rows_shared(
                &mut flat_out, &flat_x, w, n_rows, d, tokens,
            ) {
                for (t, dst) in out.iter_mut().enumerate() {
                    dst[..n_rows].copy_from_slice(&flat_out[t * n_rows..(t + 1) * n_rows]);
                }
                return;
            }
        }
    }
    let bpr = d / 256;
    let expected_len = n_rows * bpr * 210;
    if w.len() < expected_len {
        panic!(
            "[mat_vec_q6k_batch] WEIGHT BUFFER TOO SMALL: need {} bytes ({} rows x {} bpr x 210), have {}",
            expected_len, n_rows, bpr, w.len()
        );
    }
    let w_addr = w.as_ptr() as usize;
    let n_batch = xs.len();
    let out_ptrs: Vec<usize> = out.iter_mut().map(|s| s.as_mut_ptr() as usize).collect();

    if n_batch >= BATCH_DEQUANT_ONCE_MIN {
        // Dequantize each weight row ONCE and reuse it across all lanes via
        // the SIMD f32 dot — the fused row kernel would re-decode the 6-bit
        // weights n_batch times per row. `for_each_init` amortizes the
        // scratch across rayon task-splits.
        (0..n_rows).into_par_iter().for_each_init(
            || vec![0.0f32; d],
            |row_buf, i| {
                dequantize_q6k_row(row_buf, w, i, d);
                for r in 0..n_batch {
                    let row_out = unsafe { (out_ptrs[r] as *mut f32).add(i) };
                    unsafe {
                        *row_out = dot_product(row_buf, xs[r]);
                    }
                }
            },
        );
        return;
    }
    (0..n_rows).into_par_iter().for_each(|i| {
        let rp = (w_addr + i * bpr * 210) as *const u8;
        for r in 0..n_batch {
            let row_out = unsafe { (out_ptrs[r] as *mut f32).add(i) };
            unsafe {
                *row_out = mat_vec_q6k_row(xs[r], rp, bpr);
            }
        }
    });
}

pub fn mat_vec_f32_batch(out: &mut [&mut [f32]], xs: &[&[f32]], w: &[f32], _n: usize, d: usize) {
    let n_batch = xs.len();
    let n_rows = out[0].len();

    // Bounds check to prevent SIGSEGV in the parallel loop below.
    // mat_vec_f32_batch is usually called by cached_mat_vec or forward passes
    // with computed dimensions; if they mismatch the physical w.len(),
    // we want a clean panic, not a native crash.
    if n_rows * d > w.len() {
        panic!(
            "[mat_vec_f32_batch] WEIGHT BUFFER TOO SMALL: need {} floats ({}x{}), have {}",
            n_rows * d,
            n_rows,
            d,
            w.len()
        );
    }

    let w_addr = w.as_ptr() as usize;
    let out_ptrs: Vec<usize> = out.iter_mut().map(|s| s.as_mut_ptr() as usize).collect();

    (0..n_rows).into_par_iter().for_each(|i| {
        let row = unsafe { std::slice::from_raw_parts((w_addr as *const f32).add(i * d), d) };
        for r in 0..n_batch {
            let row_out = unsafe { (out_ptrs[r] as *mut f32).add(i) };
            unsafe {
                *row_out = dot_product(row, xs[r]);
            }
        }
    });
}

// ── F32 mat-vec ──────────────────────────────────────────────────────

pub fn mat_vec_f32(out: &mut [f32], x: &[f32], w: &[f32], n: usize, d: usize) {
    // GPU fast path (lm-head / norm-adjacent f32 tensors). The try fn requires
    // w.len() == n*d exactly, so over-long weight slices fall through to CPU.
    #[cfg(all(feature = "cuda", not(target_arch = "wasm32")))]
    {
        if w.len() == n * d && n <= out.len()
            && crate::cuda_matmul::try_matmul_f32_rows_shared(&mut out[..n], x, w, n, d, 1)
        {
            return;
        }
    }
    // Bounds check to prevent SIGSEGV.
    if n * d > w.len() {
        panic!(
            "[mat_vec_f32] WEIGHT BUFFER TOO SMALL: need {} floats ({}x{}), have {}",
            n * d,
            n,
            d,
            w.len()
        );
    }
    if n <= RAYON_THRESHOLD {
        for i in 0..n {
            out[i] = dot_product(&w[i * d..(i + 1) * d], &x[..d]);
        }
    } else {
        let w_addr = w.as_ptr() as usize;
        out[..n]
            .par_chunks_mut(64)
            .enumerate()
            .for_each(|(ci, chunk)| {
                for (i, val) in chunk.iter_mut().enumerate() {
                    let gi = ci * 64 + i;
                    let row = unsafe {
                        std::slice::from_raw_parts((w_addr as *const f32).add(gi * d), d)
                    };
                    *val = dot_product(row, &x[..d]);
                }
            });
    }
}

/// Attention-score f32 row matvec for decode-time K-cache rows.
///
/// Unlike `mat_vec_f32`, this intentionally skips the CUDA f32 matmul probe:
/// attention scores are short-row CPU work in decode profiles, and the generic
/// GPU dispatch check is paid once per layer/head on the hot path.
pub fn attention_scores_f32(out: &mut [f32], x: &[f32], w: &[f32], n: usize, d: usize) {
    if n * d > w.len() {
        panic!(
            "[attention_scores_f32] WEIGHT BUFFER TOO SMALL: need {} floats ({}x{}), have {}",
            n * d,
            n,
            d,
            w.len()
        );
    }
    if n <= RAYON_THRESHOLD {
        for i in 0..n {
            out[i] = dot_product(&w[i * d..(i + 1) * d], &x[..d]);
        }
    } else {
        let w_addr = w.as_ptr() as usize;
        out[..n]
            .par_chunks_mut(64)
            .enumerate()
            .for_each(|(ci, chunk)| {
                for (i, val) in chunk.iter_mut().enumerate() {
                    let gi = ci * 64 + i;
                    let row = unsafe {
                        std::slice::from_raw_parts((w_addr as *const f32).add(gi * d), d)
                    };
                    *val = dot_product(row, &x[..d]);
                }
            });
    }
}

// ── Helpers ──────────────────────────────────────────────────────────

pub fn rms_norm(out: &mut [f32], x: &[f32], w: &[f32], eps: f32) {
    let n = x.len();
    let (mut sum_sq, mut i) = {
        #[cfg(target_arch = "aarch64")]
        unsafe {
            use std::arch::aarch64::*;
            // 4 independent accumulators break the vfmaq latency dependency chain
            // (a single accumulator serializes on ~3-cycle FMA latency) → ~3×.
            let xp = x.as_ptr();
            let (mut a0, mut a1, mut a2, mut a3) = (
                vdupq_n_f32(0.0),
                vdupq_n_f32(0.0),
                vdupq_n_f32(0.0),
                vdupq_n_f32(0.0),
            );
            let mut j = 0;
            while j + 16 <= n {
                let v0 = vld1q_f32(xp.add(j));
                let v1 = vld1q_f32(xp.add(j + 4));
                let v2 = vld1q_f32(xp.add(j + 8));
                let v3 = vld1q_f32(xp.add(j + 12));
                a0 = vfmaq_f32(a0, v0, v0);
                a1 = vfmaq_f32(a1, v1, v1);
                a2 = vfmaq_f32(a2, v2, v2);
                a3 = vfmaq_f32(a3, v3, v3);
                j += 16;
            }
            while j + 4 <= n {
                let v = vld1q_f32(xp.add(j));
                a0 = vfmaq_f32(a0, v, v);
                j += 4;
            }
            let acc = vaddq_f32(vaddq_f32(a0, a1), vaddq_f32(a2, a3));
            (vaddvq_f32(acc), j)
        }
        #[cfg(target_arch = "wasm32")]
        unsafe {
            use std::arch::wasm32::*;
            let mut acc = f32x4_splat(0.0);
            let xp = x.as_ptr();
            let nq = n / 4;
            for j in 0..nq {
                let v = v128_load(xp.add(j * 4) as *const v128);
                acc = f32x4_add(acc, f32x4_mul(v, v));
            }
            let mut res = [0.0f32; 4];
            v128_store(res.as_mut_ptr() as *mut v128, acc);
            (res[0] + res[1] + res[2] + res[3], nq * 4)
        }
        // x86_64: AVX2+FMA sum-of-squares, 4 independent accumulators —
        // same latency-chain break as the aarch64 arm above. Was scalar.
        #[cfg(target_arch = "x86_64")]
        {
            if is_x86_feature_detected!("avx2") && is_x86_feature_detected!("fma") {
                unsafe { sum_squares_avx2_partial(x) }
            } else {
                (0.0f32, 0)
            }
        }
        #[cfg(not(any(
            target_arch = "aarch64",
            target_arch = "wasm32",
            target_arch = "x86_64"
        )))]
        {
            (0.0f32, 0)
        }
    };
    while i < n {
        sum_sq += x[i] * x[i];
        i += 1;
    }

    let inv = 1.0 / (sum_sq / n as f32 + eps).sqrt();
    #[cfg(target_arch = "aarch64")]
    unsafe {
        let iv = vdupq_n_f32(inv);
        let mut i = 0;
        while i + 4 <= n {
            let xv = vld1q_f32(x.as_ptr().add(i));
            let wv = vld1q_f32(w.as_ptr().add(i));
            vst1q_f32(out.as_mut_ptr().add(i), vmulq_f32(vmulq_f32(xv, iv), wv));
            i += 4;
        }
        while i < n {
            out[i] = x[i] * inv * w[i];
            i += 1;
        }
    }
    #[cfg(target_arch = "x86_64")]
    {
        if is_x86_feature_detected!("avx2") && is_x86_feature_detected!("fma") {
            unsafe { rms_norm_scale_avx2(out, x, w, inv) };
            return;
        }
    }
    #[cfg(not(target_arch = "aarch64"))]
    for i in 0..n {
        out[i] = x[i] * inv * w[i];
    }
}

/// AVX2 sum-of-squares over the 32-aligned prefix; returns
/// `(partial_sum, elements_consumed)` so the caller's scalar tail loop
/// finishes the remainder — mirrors the aarch64 arm of [`rms_norm`].
#[cfg(target_arch = "x86_64")]
#[target_feature(enable = "avx2,fma")]
unsafe fn sum_squares_avx2_partial(x: &[f32]) -> (f32, usize) {
    use std::arch::x86_64::*;
    let n = x.len();
    let xp = x.as_ptr();
    let mut a0 = _mm256_setzero_ps();
    let mut a1 = _mm256_setzero_ps();
    let mut a2 = _mm256_setzero_ps();
    let mut a3 = _mm256_setzero_ps();
    let mut j = 0;
    while j + 32 <= n {
        let v0 = _mm256_loadu_ps(xp.add(j));
        let v1 = _mm256_loadu_ps(xp.add(j + 8));
        let v2 = _mm256_loadu_ps(xp.add(j + 16));
        let v3 = _mm256_loadu_ps(xp.add(j + 24));
        a0 = _mm256_fmadd_ps(v0, v0, a0);
        a1 = _mm256_fmadd_ps(v1, v1, a1);
        a2 = _mm256_fmadd_ps(v2, v2, a2);
        a3 = _mm256_fmadd_ps(v3, v3, a3);
        j += 32;
    }
    while j + 8 <= n {
        let v = _mm256_loadu_ps(xp.add(j));
        a0 = _mm256_fmadd_ps(v, v, a0);
        j += 8;
    }
    let acc = _mm256_add_ps(_mm256_add_ps(a0, a1), _mm256_add_ps(a2, a3));
    let lo = _mm256_castps256_ps128(acc);
    let hi = _mm256_extractf128_ps(acc, 1);
    let q = _mm_add_ps(lo, hi);
    let shuf = _mm_movehdup_ps(q);
    let sums = _mm_add_ps(q, shuf);
    let shuf2 = _mm_movehl_ps(shuf, sums);
    (_mm_cvtss_f32(_mm_add_ss(sums, shuf2)), j)
}

/// AVX2 normalize pass of [`rms_norm`]: `out = x * inv * w`.
#[cfg(target_arch = "x86_64")]
#[target_feature(enable = "avx2,fma")]
unsafe fn rms_norm_scale_avx2(out: &mut [f32], x: &[f32], w: &[f32], inv: f32) {
    use std::arch::x86_64::*;
    let n = x.len();
    let iv = _mm256_set1_ps(inv);
    let mut i = 0;
    while i + 8 <= n {
        let xv = _mm256_loadu_ps(x.as_ptr().add(i));
        let wv = _mm256_loadu_ps(w.as_ptr().add(i));
        _mm256_storeu_ps(
            out.as_mut_ptr().add(i),
            _mm256_mul_ps(_mm256_mul_ps(xv, iv), wv),
        );
        i += 8;
    }
    while i < n {
        out[i] = x[i] * inv * w[i];
        i += 1;
    }
}

/// Gemma 3 RMSNorm: weight is a delta from identity →
/// `out = x * inv * (1 + w)`.
///
/// IMPORTANT: Gemma 4 uses the LLAMA formula (`out = x * inv * w`) on
/// the GGUF tensors, NOT `(1 + w)`. Aether's production v197-napi run
/// (`apps/edge-workers/src/lib/distributed-inference/gcp-layer-node.ts:3090-3097`)
/// documents this:
///
///   "Gemma 3 uses `(1 + weight)` gamma convention; Gemma 4 uses raw
///   weight as the gamma (similar to Llama). Weights in GCS for 31B
///   (attn_norm ~4.6, q_norm ~1.02) are already scaled. Applying (1+w)
///   compounds to extreme amplification and garbage tokens."
///
/// Use `gemma_rms_norm_shifted` for gemma3 and `rms_norm` (the LLaMA
/// formula) for gemma4 — or call `gemma_rms_norm` with an `arch` flag.
/// HF transformers `Gemma3RMSNorm` does the `(1+w)` shift; for gemma4
/// the equivalent is `Gemma4RMSNorm` with raw weight.
/// Sum of squares, 4 independent accumulators (breaks the FMA latency chain).
/// Shared by the RMSNorm family — ~3× over a single accumulator on aarch64.
#[inline]
pub fn sum_squares(x: &[f32]) -> f32 {
    let n = x.len();
    #[cfg(target_arch = "aarch64")]
    unsafe {
        use std::arch::aarch64::*;
        let xp = x.as_ptr();
        let (mut a0, mut a1, mut a2, mut a3) = (
            vdupq_n_f32(0.0),
            vdupq_n_f32(0.0),
            vdupq_n_f32(0.0),
            vdupq_n_f32(0.0),
        );
        let mut j = 0;
        while j + 16 <= n {
            let v0 = vld1q_f32(xp.add(j));
            let v1 = vld1q_f32(xp.add(j + 4));
            let v2 = vld1q_f32(xp.add(j + 8));
            let v3 = vld1q_f32(xp.add(j + 12));
            a0 = vfmaq_f32(a0, v0, v0);
            a1 = vfmaq_f32(a1, v1, v1);
            a2 = vfmaq_f32(a2, v2, v2);
            a3 = vfmaq_f32(a3, v3, v3);
            j += 16;
        }
        while j + 4 <= n {
            let v = vld1q_f32(xp.add(j));
            a0 = vfmaq_f32(a0, v, v);
            j += 4;
        }
        let mut s = vaddvq_f32(vaddq_f32(vaddq_f32(a0, a1), vaddq_f32(a2, a3)));
        while j < n {
            s += x[j] * x[j];
            j += 1;
        }
        s
    }
    #[cfg(not(target_arch = "aarch64"))]
    {
        let mut s = 0.0f32;
        for &v in x {
            s += v * v;
        }
        s
    }
}

pub fn gemma_rms_norm_shifted(out: &mut [f32], x: &[f32], w: &[f32], eps: f32) {
    let n = x.len();
    let inv = 1.0 / (sum_squares(x) / n as f32 + eps).sqrt();
    #[cfg(target_arch = "aarch64")]
    unsafe {
        use std::arch::aarch64::*;
        let iv = vdupq_n_f32(inv);
        let one = vdupq_n_f32(1.0);
        let mut i = 0;
        while i + 4 <= n {
            let xv = vld1q_f32(x.as_ptr().add(i));
            let wv = vld1q_f32(w.as_ptr().add(i));
            vst1q_f32(
                out.as_mut_ptr().add(i),
                vmulq_f32(vmulq_f32(xv, iv), vaddq_f32(one, wv)),
            );
            i += 4;
        }
        while i < n {
            out[i] = x[i] * inv * (1.0 + w[i]);
            i += 1;
        }
    }
    #[cfg(not(target_arch = "aarch64"))]
    for i in 0..n {
        out[i] = x[i] * inv * (1.0 + w[i]);
    }
}

/// Arch-aware Gemma RMSNorm dispatcher. Gemma 3 → `(1 + w)`,
/// Gemma 4 → raw `w` (same as Llama). The arch is captured at
/// pipeline-construction time; this function takes a precomputed
/// `shift_by_one` flag so the hot path doesn't re-string-compare.
pub fn gemma_rms_norm(out: &mut [f32], x: &[f32], w: &[f32], eps: f32, shift_by_one: bool) {
    if shift_by_one {
        gemma_rms_norm_shifted(out, x, w, eps);
    } else {
        rms_norm(out, x, w, eps); // identical to Llama RMSNorm (now 4-acc SIMD)
    }
}

/// LayerNorm: y = (x - mean) / sqrt(var + eps) * w + b.
/// Whisper uses LayerNorm (not RMSNorm); needed for Pneuma encoder/decoder.
pub fn layer_norm(out: &mut [f32], x: &[f32], w: &[f32], b: &[f32], eps: f32) {
    let n = x.len();
    let (mean, mut i) = {
        #[cfg(target_arch = "aarch64")]
        unsafe {
            use std::arch::aarch64::*;
            let xp = x.as_ptr();
            let (mut a0, mut a1, mut a2, mut a3) = (
                vdupq_n_f32(0.0),
                vdupq_n_f32(0.0),
                vdupq_n_f32(0.0),
                vdupq_n_f32(0.0),
            );
            let mut j = 0;
            while j + 16 <= n {
                a0 = vaddq_f32(a0, vld1q_f32(xp.add(j)));
                a1 = vaddq_f32(a1, vld1q_f32(xp.add(j + 4)));
                a2 = vaddq_f32(a2, vld1q_f32(xp.add(j + 8)));
                a3 = vaddq_f32(a3, vld1q_f32(xp.add(j + 12)));
                j += 16;
            }
            while j + 4 <= n {
                a0 = vaddq_f32(a0, vld1q_f32(xp.add(j)));
                j += 4;
            }
            (
                vaddvq_f32(vaddq_f32(vaddq_f32(a0, a1), vaddq_f32(a2, a3))) / n as f32,
                j,
            )
        }
        #[cfg(target_arch = "wasm32")]
        unsafe {
            use std::arch::wasm32::*;
            let mut acc = f32x4_splat(0.0);
            let xp = x.as_ptr();
            let nq = n / 4;
            for j in 0..nq {
                acc = f32x4_add(acc, v128_load(xp.add(j * 4) as *const v128));
            }
            let mut res = [0.0f32; 4];
            v128_store(res.as_mut_ptr() as *mut v128, acc);
            ((res[0] + res[1] + res[2] + res[3]) / n as f32, nq * 4)
        }
        #[cfg(not(any(target_arch = "aarch64", target_arch = "wasm32")))]
        {
            (0.0f32, 0)
        }
    };
    let mut mean = mean;
    while i < n {
        mean += x[i] / n as f32;
        i += 1;
    }

    let (var, mut i) = {
        #[cfg(target_arch = "aarch64")]
        unsafe {
            use std::arch::aarch64::*;
            let mv = vdupq_n_f32(mean);
            let xp = x.as_ptr();
            let (mut a0, mut a1, mut a2, mut a3) = (
                vdupq_n_f32(0.0),
                vdupq_n_f32(0.0),
                vdupq_n_f32(0.0),
                vdupq_n_f32(0.0),
            );
            let mut j = 0;
            while j + 16 <= n {
                let d0 = vsubq_f32(vld1q_f32(xp.add(j)), mv);
                let d1 = vsubq_f32(vld1q_f32(xp.add(j + 4)), mv);
                let d2 = vsubq_f32(vld1q_f32(xp.add(j + 8)), mv);
                let d3 = vsubq_f32(vld1q_f32(xp.add(j + 12)), mv);
                a0 = vfmaq_f32(a0, d0, d0);
                a1 = vfmaq_f32(a1, d1, d1);
                a2 = vfmaq_f32(a2, d2, d2);
                a3 = vfmaq_f32(a3, d3, d3);
                j += 16;
            }
            while j + 4 <= n {
                let d = vsubq_f32(vld1q_f32(xp.add(j)), mv);
                a0 = vfmaq_f32(a0, d, d);
                j += 4;
            }
            (
                vaddvq_f32(vaddq_f32(vaddq_f32(a0, a1), vaddq_f32(a2, a3))) / n as f32,
                j,
            )
        }
        #[cfg(target_arch = "wasm32")]
        unsafe {
            use std::arch::wasm32::*;
            let mv = f32x4_splat(mean);
            let mut acc = f32x4_splat(0.0);
            let xp = x.as_ptr();
            let nq = n / 4;
            for j in 0..nq {
                let d = f32x4_sub(v128_load(xp.add(j * 4) as *const v128), mv);
                acc = f32x4_add(acc, f32x4_mul(d, d));
            }
            let mut res = [0.0f32; 4];
            v128_store(res.as_mut_ptr() as *mut v128, acc);
            ((res[0] + res[1] + res[2] + res[3]) / n as f32, nq * 4)
        }
        #[cfg(not(any(target_arch = "aarch64", target_arch = "wasm32")))]
        {
            (0.0f32, 0)
        }
    };
    let mut var = var;
    while i < n {
        let d = x[i] - mean;
        var += d * d / n as f32;
        i += 1;
    }

    let inv = 1.0 / (var + eps).sqrt();
    #[cfg(target_arch = "aarch64")]
    unsafe {
        use std::arch::aarch64::*;
        let mv = vdupq_n_f32(mean);
        let iv = vdupq_n_f32(inv);
        let mut j = 0;
        while j + 4 <= n {
            let xv = vld1q_f32(x.as_ptr().add(j));
            let wv = vld1q_f32(w.as_ptr().add(j));
            let bv = vld1q_f32(b.as_ptr().add(j));
            let normed = vmulq_f32(vsubq_f32(xv, mv), iv);
            vst1q_f32(out.as_mut_ptr().add(j), vfmaq_f32(bv, normed, wv));
            j += 4;
        }
        i = j;
    }
    #[cfg(target_arch = "wasm32")]
    unsafe {
        use std::arch::wasm32::*;
        let mv = f32x4_splat(mean);
        let iv = f32x4_splat(inv);
        let mut j = 0;
        while j + 4 <= n {
            let xv = v128_load(x.as_ptr().add(j) as *const v128);
            let wv = v128_load(w.as_ptr().add(j) as *const v128);
            let bv = v128_load(b.as_ptr().add(j) as *const v128);
            let normed = f32x4_mul(f32x4_sub(xv, mv), iv);
            v128_store(
                out.as_mut_ptr().add(j) as *mut v128,
                f32x4_add(bv, f32x4_mul(normed, wv)),
            );
            j += 4;
        }
        i = j;
    }
    // x86/non-SIMD: no SIMD branch reset `i`, and the variance loop left it at `n`.
    // Without this reset the scalar write loop below never runs and `out` stays zero
    // (the LLMs use rms_norm, so this layer_norm path was never exercised on x86).
    #[cfg(not(any(target_arch = "aarch64", target_arch = "wasm32")))]
    {
        i = 0;
    }
    while i < n {
        out[i] = (x[i] - mean) * inv * w[i] + b[i];
        i += 1;
    }
}

/// GELU activation (tanh approximation, matches HF Whisper).
///   y = x * 0.5 * (1 + tanh(sqrt(2/pi) * (x + 0.044715 * x^3)))
pub fn gelu_inplace(x: &mut [f32]) {
    const C: f32 = 0.797_884_6_f32; // sqrt(2/pi)
    const K: f32 = 0.044715_f32;
    for v in x.iter_mut() {
        let xv = *v;
        let inner = C * (xv + K * xv * xv * xv);
        *v = 0.5 * xv * (1.0 + inner.tanh());
    }
}

// ── wasm32 SIMD softmax ─────────────────────────────────────────────
// Three passes: max, exp+sum (scalar — wasm has no SIMD exp host
// import), normalize. Vectorize the max-find and the normalize; leave
// the exp pass scalar because each `f32::exp` call traps to the V8
// math host. Split-a Fix C: this trims ~3-5 ms per token off the
// attention block at pos=1024 on gemma4-31b (32 heads × ≤1024 keys).
#[cfg(target_arch = "wasm32")]
pub fn softmax(x: &mut [f32]) {
    use std::arch::wasm32::*;
    let n = x.len();
    if n == 0 {
        return;
    }
    // Pass 1: vectorized max-find with 4-lane reduction tail.
    let max_val;
    unsafe {
        let mut max_v = f32x4_splat(x[0]);
        let chunks = n / 4;
        let mut i = 0;
        while i + 4 <= n {
            let xv = v128_load(x.as_ptr().add(i) as *const v128);
            max_v = f32x4_pmax(max_v, xv);
            i += 4;
        }
        let mut m = f32x4_extract_lane::<0>(max_v)
            .max(f32x4_extract_lane::<1>(max_v))
            .max(f32x4_extract_lane::<2>(max_v))
            .max(f32x4_extract_lane::<3>(max_v));
        let base = chunks * 4;
        for k in base..n {
            let v = *x.get_unchecked(k);
            if v > m {
                m = v;
            }
        }
        max_val = m;
    }
    // Pass 2: scalar exp + sum (no wasm SIMD exp).
    let mut sum = 0.0f32;
    for v in x.iter_mut() {
        let e = (*v - max_val).exp();
        *v = e;
        sum += e;
    }
    // Pass 3: vectorized normalize.
    let inv = 1.0 / sum;
    unsafe {
        let inv_v = f32x4_splat(inv);
        let mut i = 0;
        while i + 4 <= n {
            let xv = v128_load(x.as_ptr().add(i) as *const v128);
            v128_store(x.as_mut_ptr().add(i) as *mut v128, f32x4_mul(xv, inv_v));
            i += 4;
        }
        while i < n {
            *x.get_unchecked_mut(i) *= inv;
            i += 1;
        }
    }
}

#[cfg(not(target_arch = "wasm32"))]
pub fn softmax(x: &mut [f32]) {
    if x.is_empty() {
        return;
    }
    // aarch64: vectorize all three passes; the exp pass reuses `neon_exp4`.
    #[cfg(target_arch = "aarch64")]
    unsafe {
        use std::arch::aarch64::*;
        let n = x.len();
        // Pass 1: max
        let mut maxv = vdupq_n_f32(x[0]);
        let mut i = 0;
        while i + 4 <= n {
            maxv = vmaxq_f32(maxv, vld1q_f32(x.as_ptr().add(i)));
            i += 4;
        }
        let mut m = vmaxvq_f32(maxv);
        while i < n {
            m = m.max(*x.get_unchecked(i));
            i += 1;
        }
        // Pass 2: exp(x - m) + sum
        let mv = vdupq_n_f32(m);
        let mut sumv = vdupq_n_f32(0.0);
        i = 0;
        while i + 4 <= n {
            let e = neon_exp4(vsubq_f32(vld1q_f32(x.as_ptr().add(i)), mv));
            vst1q_f32(x.as_mut_ptr().add(i), e);
            sumv = vaddq_f32(sumv, e);
            i += 4;
        }
        let mut sum = vaddvq_f32(sumv);
        while i < n {
            let e = (*x.get_unchecked(i) - m).exp();
            *x.get_unchecked_mut(i) = e;
            sum += e;
            i += 1;
        }
        // Pass 3: normalize
        let invv = vdupq_n_f32(1.0 / sum);
        let inv = 1.0 / sum;
        i = 0;
        while i + 4 <= n {
            vst1q_f32(x.as_mut_ptr().add(i), vmulq_f32(vld1q_f32(x.as_ptr().add(i)), invv));
            i += 4;
        }
        while i < n {
            *x.get_unchecked_mut(i) *= inv;
            i += 1;
        }
    }
    // x86_64: AVX2+FMA all three passes (max / exp+sum / normalize), the exp
    // pass via `avx2_exp8` — the same polynomial as `neon_exp4`. Runs per
    // head per layer per token on Cloud Run decode; was fully scalar.
    #[cfg(target_arch = "x86_64")]
    {
        if is_x86_feature_detected!("avx2") && is_x86_feature_detected!("fma") {
            unsafe { softmax_avx2(x) };
            return;
        }
    }
    #[cfg(not(target_arch = "aarch64"))]
    {
        let mut max_val = x[0];
        for &v in x.iter() {
            if v > max_val {
                max_val = v;
            }
        }
        let mut sum = 0.0f32;
        for v in x.iter_mut() {
            let e = (*v - max_val).exp();
            *v = e;
            sum += e;
        }
        let inv = 1.0 / sum;
        for v in x.iter_mut() {
            *v *= inv;
        }
    }
}

/// AVX2 exp on 8 lanes — the exact `neon_exp4` Cephes polynomial (clamp,
/// round-to-floor base-2 split, degree-6 poly, exponent-bits rebuild), so
/// the certified rel-L2 (~2e-9 vs scalar `exp`) carries over lane-for-lane.
#[cfg(target_arch = "x86_64")]
#[target_feature(enable = "avx2,fma")]
unsafe fn avx2_exp8(x: std::arch::x86_64::__m256) -> std::arch::x86_64::__m256 {
    use std::arch::x86_64::*;
    let x = _mm256_min_ps(
        _mm256_max_ps(x, _mm256_set1_ps(-88.376_26)),
        _mm256_set1_ps(88.376_26),
    );
    let log2ef = _mm256_set1_ps(std::f32::consts::LOG2_E);
    let fx = _mm256_floor_ps(_mm256_fmadd_ps(x, log2ef, _mm256_set1_ps(0.5)));
    let mut xr = _mm256_fnmadd_ps(fx, _mm256_set1_ps(0.693_359_4), x);
    xr = _mm256_fnmadd_ps(fx, _mm256_set1_ps(-2.121_944_4e-4), xr);
    let mut y = _mm256_set1_ps(1.987_569_1e-4);
    y = _mm256_fmadd_ps(y, xr, _mm256_set1_ps(1.398_199_9e-3));
    y = _mm256_fmadd_ps(y, xr, _mm256_set1_ps(8.333_452e-3));
    y = _mm256_fmadd_ps(y, xr, _mm256_set1_ps(4.166_579_6e-2));
    y = _mm256_fmadd_ps(y, xr, _mm256_set1_ps(1.666_666_5e-1));
    y = _mm256_fmadd_ps(y, xr, _mm256_set1_ps(0.5));
    y = _mm256_fmadd_ps(y, _mm256_mul_ps(xr, xr), xr);
    y = _mm256_add_ps(y, _mm256_set1_ps(1.0));
    let pow2 = _mm256_castsi256_ps(_mm256_slli_epi32(
        _mm256_add_epi32(_mm256_cvtps_epi32(fx), _mm256_set1_epi32(127)),
        23,
    ));
    _mm256_mul_ps(y, pow2)
}

#[cfg(target_arch = "x86_64")]
#[target_feature(enable = "avx2,fma")]
unsafe fn softmax_avx2(x: &mut [f32]) {
    use std::arch::x86_64::*;
    let n = x.len();
    // Pass 1: max
    let mut maxv = _mm256_set1_ps(x[0]);
    let mut i = 0;
    while i + 8 <= n {
        maxv = _mm256_max_ps(maxv, _mm256_loadu_ps(x.as_ptr().add(i)));
        i += 8;
    }
    let mut mbuf = [0.0f32; 8];
    _mm256_storeu_ps(mbuf.as_mut_ptr(), maxv);
    let mut m = mbuf[0];
    for &v in &mbuf[1..] {
        m = m.max(v);
    }
    while i < n {
        m = m.max(*x.get_unchecked(i));
        i += 1;
    }
    // Pass 2: exp(x - m) + sum
    let mv = _mm256_set1_ps(m);
    let mut sumv = _mm256_setzero_ps();
    i = 0;
    while i + 8 <= n {
        let e = avx2_exp8(_mm256_sub_ps(_mm256_loadu_ps(x.as_ptr().add(i)), mv));
        _mm256_storeu_ps(x.as_mut_ptr().add(i), e);
        sumv = _mm256_add_ps(sumv, e);
        i += 8;
    }
    let lo = _mm256_castps256_ps128(sumv);
    let hi = _mm256_extractf128_ps(sumv, 1);
    let q = _mm_add_ps(lo, hi);
    let shuf = _mm_movehdup_ps(q);
    let sums = _mm_add_ps(q, shuf);
    let shuf2 = _mm_movehl_ps(shuf, sums);
    let mut sum = _mm_cvtss_f32(_mm_add_ss(sums, shuf2));
    while i < n {
        let e = (*x.get_unchecked(i) - m).exp();
        *x.get_unchecked_mut(i) = e;
        sum += e;
        i += 1;
    }
    // Pass 3: normalize
    let inv = 1.0 / sum;
    let invv = _mm256_set1_ps(inv);
    i = 0;
    while i + 8 <= n {
        _mm256_storeu_ps(
            x.as_mut_ptr().add(i),
            _mm256_mul_ps(_mm256_loadu_ps(x.as_ptr().add(i)), invv),
        );
        i += 8;
    }
    while i < n {
        *x.get_unchecked_mut(i) *= inv;
        i += 1;
    }
}

/// LLaMA / Mistral style RoPE: pairs are adjacent (q[2i], q[2i+1]).
pub fn rope(
    q: &mut [f32],
    k: &mut [f32],
    pos: usize,
    num_heads: usize,
    num_kv_heads: usize,
    head_dim: usize,
    theta: f32,
) {
    for i in 0..head_dim / 2 {
        let freq = 1.0 / theta.powf((i * 2) as f32 / head_dim as f32);
        let val = pos as f32 * freq;
        let (fci, fcr) = val.sin_cos();
        for h in 0..num_heads {
            let idx = h * head_dim + i * 2;
            let (q0, q1) = (q[idx], q[idx + 1]);
            q[idx] = q0 * fcr - q1 * fci;
            q[idx + 1] = q0 * fci + q1 * fcr;
        }
        for h in 0..num_kv_heads {
            let idx = h * head_dim + i * 2;
            let (k0, k1) = (k[idx], k[idx + 1]);
            k[idx] = k0 * fcr - k1 * fci;
            k[idx + 1] = k0 * fci + k1 * fcr;
        }
    }
}

/// GPT-NeoX / Qwen2 style RoPE (HuggingFace `rotate_half`): pairs are
/// `(q[i], q[i + head_dim/2])` for `i in 0..head_dim/2`. New values:
/// `q'[i]            = q[i] * cos - q[i + d/2] * sin`
/// `q'[i + d/2]      = q[i] * sin + q[i + d/2] * cos`
///
/// llama.cpp tags this as `GGML_ROPE_TYPE_NEOX` and Qwen2 uses it. Mixing
/// it up with the LLaMA-style interleaved rotation scrambles positional
/// information so that attention can't distinguish context, producing
/// input-invariant output even when the rest of the kernel is correct.
///
/// Architectural status (split-a Fix A, 2026-05-04): wasm32 SIMD branch
/// is **deferred** as next-bule. The rotate inner loop touches
/// `q[base+i]` and `q[base+i+half]` per head — a strided 2-element
/// gather pattern. Wasm simd128 has no gather opcode, so the natural
/// vectorization (4 heads at once) requires 4 scalar loads + 4 scalar
/// stores per quad and gives a ~1.3× lift at best, not the 4× the
/// dot-product path delivers. The investigation predicts ~5–10 ms
/// per-token saving combined with softmax — the larger win is the
/// `cos/sin` precompute table, not SIMD on the rotate itself. Ship
/// the precompute table refactor before adding SIMD here.
pub fn rope_neox(
    q: &mut [f32],
    k: &mut [f32],
    pos: usize,
    num_heads: usize,
    num_kv_heads: usize,
    head_dim: usize,
    theta: f32,
) {
    rope_neox_f(q, k, pos as f32, num_heads, num_kv_heads, head_dim, theta);
}

/// Float-position NeoX RoPE — same math as [`rope_neox`] but takes a
/// fractional effective position. Needed for Gemma3/Gemma4 global-layer
/// linear position scaling (`position / ropeScalingFactor`) on the
/// non-cached fallback path (positions beyond the precomputed table).
#[allow(clippy::too_many_arguments)]
pub fn rope_neox_f(
    q: &mut [f32],
    k: &mut [f32],
    pos: f32,
    num_heads: usize,
    num_kv_heads: usize,
    head_dim: usize,
    theta: f32,
) {
    let half = head_dim / 2;
    for i in 0..half {
        let freq = 1.0 / theta.powf((i * 2) as f32 / head_dim as f32);
        let val = pos * freq;
        let (fci, fcr) = val.sin_cos();
        for h in 0..num_heads {
            let base = h * head_dim;
            let (q0, q1) = (q[base + i], q[base + i + half]);
            q[base + i] = q0 * fcr - q1 * fci;
            q[base + i + half] = q0 * fci + q1 * fcr;
        }
        for h in 0..num_kv_heads {
            let base = h * head_dim;
            let (k0, k1) = (k[base + i], k[base + i + half]);
            k[base + i] = k0 * fcr - k1 * fci;
            k[base + i + half] = k0 * fci + k1 * fcr;
        }
    }
}

/// Topological RoTE (Rotary Time Embeddings)
/// Instead of a linear position, the rotation is driven by the thermodynamic 'heat'
/// of the acoustic point. This encodes phase relative to the point's age in the manifold.
pub fn topological_rote(vec: &mut [f32], heat: f32, num_heads: usize, head_dim: usize, theta: f32) {
    for i in 0..head_dim / 2 {
        let freq = 1.0 / theta.powf((i * 2) as f32 / head_dim as f32);
        // The 'position' is now the thermodynamic potential (1.0 - heat)
        let val = (1.0 - heat) * 1000.0 * freq;
        let (fci, fcr) = val.sin_cos();
        for h in 0..num_heads {
            let idx = h * head_dim + i * 2;
            let (q0, q1) = (vec[idx], vec[idx + 1]);
            vec[idx] = q0 * fcr - q1 * fci;
            vec[idx + 1] = q0 * fci + q1 * fcr;
        }
    }
}

/// Fused SwiGLU: gate = silu(gate) * up, in-place on gate buffer
/// 4-wide NEON exp (Cephes single-precision); rel error ~1e-7. Used to vectorize
/// the SwiGLU/SiLU sigmoid on the FFN hot path.
#[cfg(target_arch = "aarch64")]
#[inline]
unsafe fn neon_exp4(x: std::arch::aarch64::float32x4_t) -> std::arch::aarch64::float32x4_t {
    use std::arch::aarch64::*;
    let x = vminq_f32(vmaxq_f32(x, vdupq_n_f32(-88.376_26)), vdupq_n_f32(88.376_26));
    let log2ef = vdupq_n_f32(std::f32::consts::LOG2_E);
    let mut fx = vrndmq_f32(vmlaq_f32(vdupq_n_f32(0.5), x, log2ef));
    let mut xr = vmlsq_f32(x, fx, vdupq_n_f32(0.693_359_4));
    xr = vmlsq_f32(xr, fx, vdupq_n_f32(-2.121_944_4e-4));
    let mut y = vdupq_n_f32(1.987_569_1e-4);
    y = vmlaq_f32(vdupq_n_f32(1.398_199_9e-3), y, xr);
    y = vmlaq_f32(vdupq_n_f32(8.333_452e-3), y, xr);
    y = vmlaq_f32(vdupq_n_f32(4.166_579_6e-2), y, xr);
    y = vmlaq_f32(vdupq_n_f32(1.666_666_5e-1), y, xr);
    y = vmlaq_f32(vdupq_n_f32(0.5), y, xr);
    y = vmlaq_f32(xr, y, vmulq_f32(xr, xr));
    y = vaddq_f32(y, vdupq_n_f32(1.0));
    let pow2 = vreinterpretq_f32_s32(vshlq_n_s32(
        vaddq_s32(vcvtq_s32_f32(fx), vdupq_n_s32(127)),
        23,
    ));
    let _ = &mut fx;
    vmulq_f32(y, pow2)
}

/// SiLU gate: `gate[i] = silu(gate[i]) * up[i]`, in-place. NEON-vectorized on
/// aarch64 (≈1.9× over scalar `exp`, rel-L2 ~2e-9), scalar elsewhere.
pub fn swiglu_inplace(gate: &mut [f32], up: &[f32]) {
    #[cfg(target_arch = "aarch64")]
    unsafe {
        use std::arch::aarch64::*;
        let n = gate.len();
        let one = vdupq_n_f32(1.0);
        let mut i = 0;
        while i + 4 <= n {
            let x = vld1q_f32(gate.as_ptr().add(i));
            let u = vld1q_f32(up.as_ptr().add(i));
            let silu = vdivq_f32(x, vaddq_f32(one, neon_exp4(vnegq_f32(x))));
            vst1q_f32(gate.as_mut_ptr().add(i), vmulq_f32(silu, u));
            i += 4;
        }
        while i < n {
            let x = gate[i];
            gate[i] = (x / (1.0 + (-x).exp())) * up[i];
            i += 1;
        }
    }
    // x86_64: AVX2+FMA via `avx2_exp8` — runs once per FFN per layer per
    // token on Cloud Run decode; was scalar exp.
    #[cfg(target_arch = "x86_64")]
    {
        if is_x86_feature_detected!("avx2") && is_x86_feature_detected!("fma") {
            unsafe { swiglu_avx2(gate, up) };
            return;
        }
    }
    #[cfg(not(target_arch = "aarch64"))]
    for i in 0..gate.len() {
        let x = gate[i];
        gate[i] = (x / (1.0 + (-x).exp())) * up[i];
    }
}

#[cfg(target_arch = "x86_64")]
#[target_feature(enable = "avx2,fma")]
unsafe fn swiglu_avx2(gate: &mut [f32], up: &[f32]) {
    use std::arch::x86_64::*;
    let n = gate.len();
    let one = _mm256_set1_ps(1.0);
    let mut i = 0;
    while i + 8 <= n {
        let x = _mm256_loadu_ps(gate.as_ptr().add(i));
        let u = _mm256_loadu_ps(up.as_ptr().add(i));
        let neg = _mm256_sub_ps(_mm256_setzero_ps(), x);
        let silu = _mm256_div_ps(x, _mm256_add_ps(one, avx2_exp8(neg)));
        _mm256_storeu_ps(gate.as_mut_ptr().add(i), _mm256_mul_ps(silu, u));
        i += 8;
    }
    while i < n {
        let x = gate[i];
        gate[i] = (x / (1.0 + (-x).exp())) * up[i];
        i += 1;
    }
}

// Legacy compat
pub fn swiglu(out: &mut [f32], gate: &[f32], up: &[f32]) {
    out.copy_from_slice(&gate[..out.len()]);
    swiglu_inplace(out, up);
}

/// Fused GeGLU (gelu-glu): gate = gelu(gate) * up, in-place. Used by
/// Gemma3 / Gemma4 MLP — they activate the gate projection with GeLU
/// (the Gaussian Error Linear Unit) rather than SwiGLU's silu. The
/// HF / llama.cpp implementations use the GeLU "tanh approximation"
/// (`0.5 * x * (1 + tanh(sqrt(2/π) * (x + 0.044715 * x^3)))`) — match
/// it byte-for-byte to keep parity with the TS Aether reference.
pub fn gelu_glu_inplace(gate: &mut [f32], up: &[f32]) {
    const C: f32 = 0.797_884_6; // sqrt(2/π)
    // aarch64: vectorize via tanh(y) = 1 − 2/(exp(2y)+1), reusing `neon_exp4`.
    #[cfg(target_arch = "aarch64")]
    unsafe {
        use std::arch::aarch64::*;
        let cv = vdupq_n_f32(C);
        let a = vdupq_n_f32(0.044715);
        let half = vdupq_n_f32(0.5);
        let one = vdupq_n_f32(1.0);
        let two = vdupq_n_f32(2.0);
        let n = gate.len();
        let mut i = 0;
        while i + 4 <= n {
            let x = vld1q_f32(gate.as_ptr().add(i));
            let u = vld1q_f32(up.as_ptr().add(i));
            let x3 = vmulq_f32(vmulq_f32(x, x), x);
            let inner = vmulq_f32(cv, vaddq_f32(x, vmulq_f32(a, x3)));
            let e = neon_exp4(vmulq_f32(two, inner));
            let t = vsubq_f32(one, vdivq_f32(two, vaddq_f32(e, one))); // tanh(inner)
            let gelu = vmulq_f32(half, vmulq_f32(x, vaddq_f32(one, t)));
            vst1q_f32(gate.as_mut_ptr().add(i), vmulq_f32(gelu, u));
            i += 4;
        }
        while i < n {
            let x = gate[i];
            let inner = C * (x + 0.044715 * x * x * x);
            gate[i] = (0.5 * x * (1.0 + inner.tanh())) * up[i];
            i += 1;
        }
    }
    #[cfg(not(target_arch = "aarch64"))]
    for i in 0..gate.len() {
        let x = gate[i];
        let inner = C * (x + 0.044715 * x * x * x);
        let gelu = 0.5 * x * (1.0 + inner.tanh());
        gate[i] = gelu * up[i];
    }
}

/// Tanh-based logit softcap. Each element is replaced by
/// `tanh(x / cap) * cap`, smoothly clamping magnitudes near `cap`.
/// Gemma4 applies this at the end of `lm_head` with cap=30.0; without
/// it, logits explode uncapped and argmax picks garbage tokens.
pub fn tanh_softcap(x: &mut [f32], cap: f32) {
    let inv_cap = 1.0 / cap;
    for v in x.iter_mut() {
        *v = (*v * inv_cap).tanh() * cap;
    }
}

/// In-place scalar multiply. Used by Gemma4's per-layer
/// `layer_output_scale` (a single F32 scalar that dampens each layer's
/// contribution to the residual stream — values land in roughly
/// [0.036, 0.992], stabilizing 60-layer Gemma4 against drift).
pub fn scalar_mul(x: &mut [f32], s: f32) {
    for v in x.iter_mut() {
        *v *= s;
    }
}

/// Per-head RMSNorm. Treats `qkv` as a flat buffer of `num_heads`
/// consecutive `head_dim`-sized vectors and applies an independent
/// RMSNorm to each, scaled by the shared `head_dim`-shaped weight `w`.
/// Gemma3 / Gemma4 normalize Q and K per-head before RoPE — different
/// from the per-token attn_norm at the start of the layer (which
/// normalizes the residual stream).
pub fn rms_norm_per_head(qkv: &mut [f32], w: &[f32], num_heads: usize, head_dim: usize, eps: f32) {
    debug_assert_eq!(
        w.len(),
        head_dim,
        "rms_norm_per_head: weight len {} != head_dim {}",
        w.len(),
        head_dim
    );
    debug_assert_eq!(
        qkv.len(),
        num_heads * head_dim,
        "rms_norm_per_head: qkv len {} != num_heads*head_dim {}",
        qkv.len(),
        num_heads * head_dim
    );
    // q_norm / k_norm weight convention: Gemma 3 stores deltas from
    // identity → `(1 + w)`; Gemma 4 stores already-shifted weights →
    // `w`. Default to raw weight; callers needing the gemma3 formula
    // should use `rms_norm_per_head_shifted`.
    for h in 0..num_heads {
        let head = &mut qkv[h * head_dim..(h + 1) * head_dim];
        let mut sum_sq = 0.0f32;
        for &v in head.iter() {
            sum_sq += v * v;
        }
        let inv = 1.0 / (sum_sq / head_dim as f32 + eps).sqrt();
        for i in 0..head_dim {
            head[i] = head[i] * inv * w[i];
        }
    }
}

/// Gemma 3 variant: `out = x * inv * (1 + w)` per head.
pub fn rms_norm_per_head_shifted(
    qkv: &mut [f32],
    w: &[f32],
    num_heads: usize,
    head_dim: usize,
    eps: f32,
) {
    debug_assert_eq!(w.len(), head_dim);
    debug_assert_eq!(qkv.len(), num_heads * head_dim);
    for h in 0..num_heads {
        let head = &mut qkv[h * head_dim..(h + 1) * head_dim];
        let mut sum_sq = 0.0f32;
        for &v in head.iter() {
            sum_sq += v * v;
        }
        let inv = 1.0 / (sum_sq / head_dim as f32 + eps).sqrt();
        for i in 0..head_dim {
            head[i] = head[i] * inv * (1.0 + w[i]);
        }
    }
}

/// Precompute the NeoX RoPE cos/sin table for every (position, dim_pair)
/// across the full sequence horizon. Returns a flat `Vec<f32>` of length
/// `max_seq_len * head_dim` laid out as
/// `[cos_0_0, sin_0_0, cos_0_1, sin_0_1, …, cos_0_(half-1), sin_0_(half-1),
///   cos_1_0, sin_1_0, …]`
/// — i.e. interleaved cos/sin pairs, one pair per dim-pair, all pairs
/// for position 0 first, then position 1, etc. Stride per position is
/// `head_dim` floats (= `2 * (head_dim/2)`).
///
/// This is the cos/sin precompute table called out in the wave-22
/// split-a investigation (Fix C): the rope rotate inner loop is
/// dominated by `theta.powf(...)` + `val.sin_cos()` — order ~10–20 ns
/// per dim-pair on wasm, multiplied by `(head_dim/2) × seq_len` per
/// layer per token. Wasm simd128 has no gather opcode so the rotate
/// itself doesn't vectorize cleanly, but the trig is pure waste:
/// every position's value depends only on `(pos, i, head_dim, theta)`,
/// all compile-time constants once the model is loaded. Compute the
/// table ONCE at pipeline boot and the per-token cost collapses to
/// two memory loads + four FMAs per element.
///
/// Memory cost: `max_seq_len * head_dim * 4` bytes.
/// - Gemma4-31B sliding (max=128, head_dim=256) → 128 KiB per table
/// - Gemma4-31B global  (max=128, head_dim=512) → 256 KiB per table
/// - Gemma4-31B native  (max=2048, head_dim=512) → 4 MiB per table
/// - Phi-3-mini wasm    (max=128, head_dim=96)  → 48 KiB per table
/// - Phi-3-mini native  (max=2048, head_dim=96) → 768 KiB per table
///
/// Partial-RoPE callers (Gemma4 globals with `rope_partial_factor=0.25`)
/// reuse the same table — the first `n_rot/2` cos/sin pairs of each
/// position slice are exactly the values needed.
pub fn precompute_rope_table(max_seq_len: usize, head_dim: usize, theta: f32) -> Vec<f32> {
    precompute_rope_table_scaled(max_seq_len, head_dim, theta, 1.0)
}

/// Like [`precompute_rope_table`] but bakes a *linear position scaling*
/// into the table: the angle for table-row `pos` is computed at the
/// effective position `pos / pos_scale` instead of `pos`. This is the
/// Gemma3/Gemma4 GLOBAL-layer RoPE: HF / the Aether TS reference compute
/// `scaledPosition = position / ropeScalingFactor` (default 8.0) for
/// global-attention layers, then the same NeoX rotation. Sliding (local)
/// layers use `pos_scale = 1.0` (no scaling). See
/// `open-source/aether/src/gcp-layer-node.ts` `applyRoPE` (`scaledPosition
/// = position / ropeScalingFactor`) and its global-layer call site
/// (`layerScaling = isGemma3 && isGlobalLayer ? ropeScalingFactor : 1.0`).
///
/// Baking the scale into the table (rather than scaling the lookup index)
/// keeps the integer-indexed cached fast path exact at fractional
/// effective positions: the global table is only ever read by global
/// layers, so the scaled angles are correct for every row.
pub fn precompute_rope_table_scaled(
    max_seq_len: usize,
    head_dim: usize,
    theta: f32,
    pos_scale: f32,
) -> Vec<f32> {
    debug_assert_eq!(
        head_dim % 2,
        0,
        "precompute_rope_table: head_dim={} must be even",
        head_dim
    );
    debug_assert!(
        pos_scale > 0.0,
        "precompute_rope_table: pos_scale={} must be > 0",
        pos_scale
    );
    let half = head_dim / 2;
    let inv_scale = 1.0 / pos_scale;
    let mut table = vec![0.0f32; max_seq_len * head_dim];
    // Hoist freq[i] = 1 / theta^(2i/head_dim) — independent of pos.
    let mut freqs = vec![0.0f32; half];
    for i in 0..half {
        freqs[i] = 1.0 / theta.powf((i * 2) as f32 / head_dim as f32);
    }
    for pos in 0..max_seq_len {
        let scaled_pos = pos as f32 * inv_scale;
        let row = &mut table[pos * head_dim..(pos + 1) * head_dim];
        for i in 0..half {
            let val = scaled_pos * freqs[i];
            let (sin_v, cos_v) = val.sin_cos();
            row[i * 2] = cos_v;
            row[i * 2 + 1] = sin_v;
        }
    }
    table
}

/// Cached NeoX-style RoPE: same math as [`rope_neox`] but reads cos/sin
/// from a precomputed table instead of calling `theta.powf` + `sin_cos`
/// at every (position, dim-pair) on every forward. The table layout is
/// the one produced by [`precompute_rope_table`].
///
/// `table` MUST have been computed with the same `head_dim` and `theta`
/// as the call. The slice for this position is
/// `table[pos * head_dim .. (pos + 1) * head_dim]`.
///
/// Falls through to scalar (no SIMD on the rotate itself — see the
/// docblock on [`rope_neox`] for why; the win here is eliminating the
/// trig host-trampoline cost, not vectorizing the multiply-add).
pub fn rope_neox_cached(
    q: &mut [f32],
    k: &mut [f32],
    pos: usize,
    num_heads: usize,
    num_kv_heads: usize,
    head_dim: usize,
    table: &[f32],
) {
    let half = head_dim / 2;
    let row_off = pos * head_dim;
    debug_assert!(
        row_off + head_dim <= table.len(),
        "rope_neox_cached: pos={} out of table bounds (table len {} for head_dim {})",
        pos,
        table.len(),
        head_dim
    );
    for i in 0..half {
        let fcr = table[row_off + i * 2];
        let fci = table[row_off + i * 2 + 1];
        for h in 0..num_heads {
            let base = h * head_dim;
            let q0 = q[base + i];
            let q1 = q[base + i + half];
            q[base + i] = q0 * fcr - q1 * fci;
            q[base + i + half] = q0 * fci + q1 * fcr;
        }
        for h in 0..num_kv_heads {
            let base = h * head_dim;
            let k0 = k[base + i];
            let k1 = k[base + i + half];
            k[base + i] = k0 * fcr - k1 * fci;
            k[base + i + half] = k0 * fci + k1 * fcr;
        }
    }
}

/// Cached LLaMA / Mistral style RoPE: same math as [`rope`] (adjacent
/// interleaved pairs `(q[2i], q[2i+1])`) but reads cos/sin from a
/// [`precompute_rope_table`]-shaped table instead of paying
/// `theta.powf` + `sin_cos` per (position, dim-pair) on every forward —
/// head_dim/2 transcendental pairs per layer per token on the decode
/// hot path. Table angles come from the same
/// `pos as f32 * (1/theta^(2i/head_dim))` formula; results match the
/// uncached [`rope`] to within an ulp (`rope_cached_matches_rope`).
pub fn rope_cached(
    q: &mut [f32],
    k: &mut [f32],
    pos: usize,
    num_heads: usize,
    num_kv_heads: usize,
    head_dim: usize,
    table: &[f32],
) {
    let row_off = pos * head_dim;
    debug_assert!(
        row_off + head_dim <= table.len(),
        "rope_cached: pos={} out of table bounds (table len {} for head_dim {})",
        pos,
        table.len(),
        head_dim
    );
    for i in 0..head_dim / 2 {
        let fcr = table[row_off + i * 2];
        let fci = table[row_off + i * 2 + 1];
        for h in 0..num_heads {
            let idx = h * head_dim + i * 2;
            let (q0, q1) = (q[idx], q[idx + 1]);
            q[idx] = q0 * fcr - q1 * fci;
            q[idx + 1] = q0 * fci + q1 * fcr;
        }
        for h in 0..num_kv_heads {
            let idx = h * head_dim + i * 2;
            let (k0, k1) = (k[idx], k[idx + 1]);
            k[idx] = k0 * fcr - k1 * fci;
            k[idx + 1] = k0 * fci + k1 * fcr;
        }
    }
}

/// Cached partial NeoX RoPE: rotates only the first `n_rot` dims (still
/// using `head_dim/2` as the pair stride, per the NeoX convention) and
/// reads cos/sin from a [`precompute_rope_table`]-shaped table sized for
/// the full `head_dim`. The trailing `head_dim - n_rot` elements of each
/// head are left untouched.
pub fn rope_neox_partial_cached(
    q: &mut [f32],
    k: &mut [f32],
    pos: usize,
    num_heads: usize,
    num_kv_heads: usize,
    head_dim: usize,
    n_rot: usize,
    table: &[f32],
) {
    debug_assert!(
        n_rot <= head_dim,
        "rope_neox_partial_cached: n_rot {} > head_dim {}",
        n_rot,
        head_dim
    );
    debug_assert_eq!(
        n_rot % 2,
        0,
        "rope_neox_partial_cached: n_rot {} must be even",
        n_rot
    );
    let half_rot = n_rot / 2;
    let half_dim = head_dim / 2;
    let row_off = pos * head_dim;
    debug_assert!(
        row_off + head_dim <= table.len(),
        "rope_neox_partial_cached: pos={} out of table bounds (table len {} for head_dim {})",
        pos,
        table.len(),
        head_dim
    );
    for i in 0..half_rot {
        let fcr = table[row_off + i * 2];
        let fci = table[row_off + i * 2 + 1];
        for h in 0..num_heads {
            let base = h * head_dim;
            let q0 = q[base + i];
            let q1 = q[base + i + half_dim];
            q[base + i] = q0 * fcr - q1 * fci;
            q[base + i + half_dim] = q0 * fci + q1 * fcr;
        }
        for h in 0..num_kv_heads {
            let base = h * head_dim;
            let k0 = k[base + i];
            let k1 = k[base + i + half_dim];
            k[base + i] = k0 * fcr - k1 * fci;
            k[base + i + half_dim] = k0 * fci + k1 * fcr;
        }
    }
}

/// RoPE-NeoX with partial rotation. Rotates only the first `n_rot`
/// dimensions of each head's Q/K vector and copies the rest unchanged.
/// Gemma 4 proportional RoPE uses `head_dim` in the frequency denominator,
/// matching the HF / Aether TS reference. Rotated pairs are spaced by
/// `head_dim / 2` (NeoX convention) not `n_rot / 2`.
pub fn rope_neox_partial(
    q: &mut [f32],
    k: &mut [f32],
    pos: usize,
    num_heads: usize,
    num_kv_heads: usize,
    head_dim: usize,
    n_rot: usize,
    theta: f32,
) {
    rope_neox_partial_f(
        q,
        k,
        pos as f32,
        num_heads,
        num_kv_heads,
        head_dim,
        n_rot,
        theta,
    );
}

/// Float-position partial NeoX RoPE — see [`rope_neox_f`] / Gemma global
/// position scaling. Rotates only the first `n_rot` dims (NeoX pair
/// stride `head_dim/2`), copying the rest unchanged.
#[allow(clippy::too_many_arguments)]
pub fn rope_neox_partial_f(
    q: &mut [f32],
    k: &mut [f32],
    pos: f32,
    num_heads: usize,
    num_kv_heads: usize,
    head_dim: usize,
    n_rot: usize,
    theta: f32,
) {
    debug_assert!(
        n_rot <= head_dim,
        "rope_neox_partial: n_rot {} > head_dim {}",
        n_rot,
        head_dim
    );
    debug_assert_eq!(
        n_rot % 2,
        0,
        "rope_neox_partial: n_rot {} must be even",
        n_rot
    );
    let half_rot = n_rot / 2;
    let half_dim = head_dim / 2;
    for i in 0..half_rot {
        let freq = 1.0 / theta.powf((i * 2) as f32 / head_dim as f32);
        let val = pos * freq;
        let (fci, fcr) = val.sin_cos();
        for h in 0..num_heads {
            let base = h * head_dim;
            let (q0, q1) = (q[base + i], q[base + i + half_dim]);
            q[base + i] = q0 * fcr - q1 * fci;
            q[base + i + half_dim] = q0 * fci + q1 * fcr;
        }
        for h in 0..num_kv_heads {
            let base = h * head_dim;
            let (k0, k1) = (k[base + i], k[base + i + half_dim]);
            k[base + i] = k0 * fcr - k1 * fci;
            k[base + i + half_dim] = k0 * fci + k1 * fcr;
        }
    }
}

// ── Acoustic Topology ────────────────────────────────────────────────

/// Reconstructs the phase space of a 1D audio waveform using Takens' Delay Embedding.
/// Returns a cloud of points in the reconstructed manifold.
pub fn takens_embedding(audio: &[f32], delay: usize, dim: usize) -> Vec<Vec<f32>> {
    let n = audio.len();
    if n <= (dim - 1) * delay {
        return Vec::new();
    }

    let num_points = n - (dim - 1) * delay;
    let mut manifold = Vec::with_capacity(num_points);

    for i in 0..num_points {
        let mut point = Vec::with_capacity(dim);
        for d in 0..dim {
            point.push(audio[i + d * delay]);
        }
        manifold.push(point);
    }
    manifold
}

/// Simplified Persistence Barcode generator.
/// Tracks β1 holes (loops) in the acoustic manifold by measuring orbital recurrence.
pub fn generate_persistence_barcode(manifold: &[Vec<f32>]) -> (u32, f32, f32) {
    if manifold.is_empty() {
        return (0, 0.0, 0.0);
    }

    let mut beta1 = 0;
    let mut total_dilation = 0.0;
    let mut density = 0.0;

    let dim = manifold[0].len();
    let n = manifold.len();

    // We approximate β1 by counting points that return to a localized neighborhood
    // after a minimum "orbital" distance (detecting a loop in phase space).
    let recurrence_threshold = 0.05;
    let min_orbit_steps = 10;

    for i in 0..n.saturating_sub(min_orbit_steps) {
        let p1 = &manifold[i];

        // Measure local density
        let mut local_neighbors = 0;
        for j in (i + 1)..n {
            let p2 = &manifold[j];
            let mut dist_sq = 0.0;
            for k in 0..dim {
                let diff = p1[k] - p2[k];
                dist_sq += diff * diff;
            }

            if dist_sq < recurrence_threshold * recurrence_threshold {
                local_neighbors += 1;

                // If the recurrence happens after a delay, we've closed a loop (β1)
                if j - i >= min_orbit_steps {
                    beta1 += 1;
                    total_dilation += dist_sq.sqrt();
                }
            }
        }
        density += local_neighbors as f32 / n as f32;
    }

    (beta1, total_dilation, density / n as f32)
}

// ── Zigzag Persistence & Thermodynamic Decay ──────────────────────────

/// A point in the Comet Tail with an associated thermodynamic heat (age).
pub struct CometPoint {
    pub coordinate: Vec<f32>,
    pub heat: f32,
}

/// Executes one step of the Zigzag Persistence filtration.
/// Injects new audio points and cools existing ones, removing them if they reach the absolute zero.
pub fn zigzag_step(comet_tail: &mut Vec<CometPoint>, new_points: Vec<Vec<f32>>, cooling_rate: f32) {
    // 1. Thermodynamic Decay: Cool existing points
    for point in comet_tail.iter_mut() {
        point.heat -= cooling_rate;
    }

    // 2. Ergodic Flow: Remove cooled points (Absolute Zero)
    comet_tail.retain(|p| p.heat > 0.0);

    // 3. Injection: Add new points at maximum heat
    for p in new_points {
        comet_tail.push(CometPoint {
            coordinate: p,
            heat: 1.0,
        });
    }
}

/// Computes the barcode for a moving Comet Tail.
pub fn compute_comet_barcode(comet_tail: &[CometPoint]) -> (u32, f32, f32) {
    let manifold: Vec<Vec<f32>> = comet_tail.iter().map(|p| p.coordinate.clone()).collect();
    generate_persistence_barcode(&manifold)
}

// ── RoPE precompute parity tests ──────────────────────────────────────
//
// The cached path must produce bit-identical results to the per-call
// trig path (mod the rounding of `theta.powf` vs the precomputed freq).
// These tests guard the wave-22 split-a Fix C contract: rope_neox_cached
// is a drop-in replacement for rope_neox.
#[cfg(test)]
mod rope_precompute_tests {
    use super::*;

    fn assert_close(a: &[f32], b: &[f32], eps: f32, label: &str) {
        assert_eq!(a.len(), b.len(), "{}: length mismatch", label);
        for (i, (&x, &y)) in a.iter().zip(b.iter()).enumerate() {
            let d = (x - y).abs();
            assert!(
                d < eps,
                "{}: idx {} differs |{} - {}| = {} > {}",
                label,
                i,
                x,
                y,
                d,
                eps
            );
        }
    }

    #[test]
    fn precompute_table_shape_and_p0_identity() {
        // Position 0: cos(0)=1, sin(0)=0 for every dim-pair.
        let head_dim = 8;
        let max_seq = 4;
        let table = precompute_rope_table(max_seq, head_dim, 10000.0);
        assert_eq!(table.len(), max_seq * head_dim);
        for i in 0..head_dim / 2 {
            assert!(
                (table[i * 2] - 1.0).abs() < 1e-6,
                "cos at pos 0 must be 1.0"
            );
            assert!(table[i * 2 + 1].abs() < 1e-6, "sin at pos 0 must be 0.0");
        }
    }

    #[test]
    fn cached_matches_uncached_full_rotation() {
        // Gemma4 sliding-layer-ish shape: head_dim=64 (small for test speed),
        // theta=10000, multiple heads, multiple positions.
        let head_dim = 64;
        let num_heads = 8;
        let num_kv_heads = 4;
        let theta = 10000.0_f32;
        let max_seq = 16;
        let table = precompute_rope_table(max_seq, head_dim, theta);

        for pos in 0..max_seq {
            // Deterministic input.
            let mut q_a: Vec<f32> = (0..num_heads * head_dim)
                .map(|i| (i as f32 * 0.013 - 0.5).sin())
                .collect();
            let mut k_a: Vec<f32> = (0..num_kv_heads * head_dim)
                .map(|i| (i as f32 * 0.017 + 0.25).cos())
                .collect();
            let mut q_b = q_a.clone();
            let mut k_b = k_a.clone();

            rope_neox(
                &mut q_a,
                &mut k_a,
                pos,
                num_heads,
                num_kv_heads,
                head_dim,
                theta,
            );
            rope_neox_cached(
                &mut q_b,
                &mut k_b,
                pos,
                num_heads,
                num_kv_heads,
                head_dim,
                &table,
            );
            assert_close(&q_a, &q_b, 1e-5, &format!("Q parity @ pos={}", pos));
            assert_close(&k_a, &k_b, 1e-5, &format!("K parity @ pos={}", pos));
        }
    }

    #[test]
    fn cached_partial_matches_uncached_partial() {
        // Gemma4 global-layer-ish shape: head_dim=64, n_rot=16 (1/4 partial),
        // theta=1_000_000.
        let head_dim = 64;
        let n_rot = 16;
        let num_heads = 4;
        let num_kv_heads = 2;
        let theta = 1_000_000.0_f32;
        let max_seq = 8;
        let table = precompute_rope_table(max_seq, head_dim, theta);

        for pos in 0..max_seq {
            let mut q_a: Vec<f32> = (0..num_heads * head_dim)
                .map(|i| (i as f32 * 0.011 - 0.7).sin())
                .collect();
            let mut k_a: Vec<f32> = (0..num_kv_heads * head_dim)
                .map(|i| (i as f32 * 0.019 + 0.33).cos())
                .collect();
            let mut q_b = q_a.clone();
            let mut k_b = k_a.clone();

            rope_neox_partial(
                &mut q_a,
                &mut k_a,
                pos,
                num_heads,
                num_kv_heads,
                head_dim,
                n_rot,
                theta,
            );
            rope_neox_partial_cached(
                &mut q_b,
                &mut k_b,
                pos,
                num_heads,
                num_kv_heads,
                head_dim,
                n_rot,
                &table,
            );
            assert_close(&q_a, &q_b, 1e-5, &format!("Q partial @ pos={}", pos));
            assert_close(&k_a, &k_b, 1e-5, &format!("K partial @ pos={}", pos));
        }
    }
}

