// ─────────────────────────────────────────────────────────────────────────
// Q8_0 mat_vec parity tests
// ─────────────────────────────────────────────────────────────────────────
#[cfg(test)]
mod q8_0_matvec_tests {
    use super::*;

    fn synth_q8_0_rows(rows: usize, cols: usize, seed: u32) -> Vec<u8> {
        let blocks_per_row = cols.div_ceil(32);
        let mut buf = vec![0u8; rows * blocks_per_row * 34];
        for row in 0..rows {
            for block in 0..blocks_per_row {
                let off = (row * blocks_per_row + block) * 34;
                let scale_f16: u16 = 0x2c00; // 0.0625 in IEEE 754 binary16
                buf[off] = (scale_f16 & 0xff) as u8;
                buf[off + 1] = (scale_f16 >> 8) as u8;
                for i in 0..32 {
                    let raw = seed
                        .wrapping_add(row as u32 * 37)
                        .wrapping_add(block as u32 * 19)
                        .wrapping_add(i as u32 * 11);
                    buf[off + 2 + i] = ((raw % 255) as i16 - 127) as i8 as u8;
                }
            }
        }
        buf
    }

    fn reference_mat_vec_q8_0(out: &mut [f32], x: &[f32], w: &[u8], n: usize, d: usize) {
        let mut row_buf = vec![0.0f32; d];
        for i in 0..n {
            dequantize_q8_0_row(&mut row_buf, w, i, d);
            out[i] = row_buf
                .iter()
                .zip(x.iter())
                .map(|(a, b)| a * b)
                .sum::<f32>();
        }
    }

    #[test]
    fn mat_vec_q8_0_matches_dequant_then_dot_reference() {
        let n = 130;
        let d = 384;
        let w = synth_q8_0_rows(n, d, 0x51f1_7a9b);
        let x: Vec<f32> = (0..d).map(|i| ((i as f32) * 0.017 - 0.41).sin()).collect();

        let mut out_dispatch = vec![0.0f32; n];
        let mut out_reference = vec![0.0f32; n];
        mat_vec_q8_0(&mut out_dispatch, &x, &w, n, d);
        reference_mat_vec_q8_0(&mut out_reference, &x, &w, n, d);

        for i in 0..n {
            let diff = (out_dispatch[i] - out_reference[i]).abs();
            assert!(
                diff < 1e-3,
                "row {}: dispatch={} reference={} |delta|={}",
                i,
                out_dispatch[i],
                out_reference[i],
                diff
            );
        }
    }
}

// ─────────────────────────────────────────────────────────────────────────
// Q6_K mat_vec parity tests
// ─────────────────────────────────────────────────────────────────────────
//
// Per-target parity guard for `mat_vec_q6k_row`. The wasm32 SIMD branch
// was previously broken (2026-04-27 revert) — this module ensures any
// future SIMD attempt is byte-equivalent to the dequant-then-dot reference
// path. Runs on whatever target cargo test compiles for: scalar fallback
// on x86_64, NEON on aarch64. The wasm32 SIMD branch is exercised by the
// downstream cobordism worker integration test, but compiles via
// `cargo build --target wasm32-unknown-unknown` — failing to compile here
// catches the most common port bug (intrinsic mis-import).
#[cfg(test)]
mod q6k_matvec_tests {
    use super::*;

    /// Synthesise one Q6_K block's worth of bytes (210 bytes per block,
    /// 256 elements per block) with a deterministic per-element pattern.
    /// Guarantees the full 6-bit quant range gets exercised.
    fn synth_q6k_blocks(n_blocks: usize, seed: u32) -> Vec<u8> {
        let mut buf = vec![0u8; n_blocks * 210];
        for b in 0..n_blocks {
            let off = b * 210;
            // ql: 128 bytes — pack two 4-bit nibbles per byte across the
            // 256 element low-bits. Pattern deterministic in (b, byte).
            for i in 0..128 {
                let lo = ((seed.wrapping_add(b as u32 * 31).wrapping_add(i as u32)) & 0x0f) as u8;
                let hi =
                    ((seed.wrapping_add(b as u32 * 17).wrapping_add(i as u32 * 3)) & 0x0f) as u8;
                buf[off + i] = (hi << 4) | lo;
            }
            // qh: 64 bytes — pack four 2-bit pairs per byte across the
            // 256 element high-bits.
            for i in 0..64 {
                let v = (seed
                    .wrapping_mul(7)
                    .wrapping_add(b as u32)
                    .wrapping_add(i as u32 * 5))
                    & 0xff;
                buf[off + 128 + i] = v as u8;
            }
            // sc: 16 signed sub-scales. Use a small-magnitude pattern so
            // d_val * sc * q stays in the f32 representable range.
            for i in 0..16 {
                let s = ((seed.wrapping_add(b as u32 * 11).wrapping_add(i as u32 * 13)) & 0x1f)
                    as i8
                    - 16;
                buf[off + 192 + i] = s as u8;
            }
            // d: f16 super-scale. Use a fixed small value (0.0625 = 0x2400)
            // so the per-row sum stays bounded for any reasonable n_blocks.
            let d_f16: u16 = 0x2400; // 0.0625 in IEEE 754 binary16
            buf[off + 208] = (d_f16 & 0xff) as u8;
            buf[off + 209] = (d_f16 >> 8) as u8;
        }
        buf
    }

    /// Reference: dequantise each row to f32 then scalar dot-product.
    fn reference_mat_vec_q6k(out: &mut [f32], x: &[f32], w: &[u8], n: usize, d: usize) {
        let mut row_buf = vec![0.0f32; d];
        for i in 0..n {
            dequantize_q6k_row(&mut row_buf, w, i, d);
            let mut acc = 0.0f32;
            for h in 0..d {
                acc += x[h] * row_buf[h];
            }
            out[i] = acc;
        }
    }

    #[test]
    fn mat_vec_q6k_matches_dequant_then_dot_reference() {
        // Single-block-per-row case (d = 256).
        let n = 32;
        let d = 256;
        let bpr = d / 256;
        let w = synth_q6k_blocks(n * bpr, 0xabcd1234);
        let x: Vec<f32> = (0..d).map(|i| ((i as f32) * 0.013 - 0.7).sin()).collect();

        let mut out_dispatch = vec![0.0f32; n];
        let mut out_reference = vec![0.0f32; n];
        mat_vec_q6k(&mut out_dispatch, &x, &w, n, d);
        reference_mat_vec_q6k(&mut out_reference, &x, &w, n, d);

        for i in 0..n {
            let diff = (out_dispatch[i] - out_reference[i]).abs();
            // f32 dot-product accumulation tolerance — well under the
            // signal magnitude here (out values land in roughly [-2, 2]).
            assert!(
                diff < 1e-4,
                "row {}: dispatch={} reference={} |Δ|={}",
                i,
                out_dispatch[i],
                out_reference[i],
                diff
            );
        }
    }

    fn synth_q5k_blocks(n_blocks: usize, seed: u32) -> Vec<u8> {
        // Q5_K block (176 B / 256 elems): d f16 @0, dmin f16 @2, scales[12]
        // @4 (Q4_K 6-bit packing), qh[32] @16, ql[128] @48.
        let mut buf = vec![0u8; n_blocks * 176];
        for b in 0..n_blocks {
            let off = b * 176;
            buf[off..off + 2].copy_from_slice(&0x3c00u16.to_le_bytes()); // d = 1.0
            buf[off + 2..off + 4].copy_from_slice(&0x3800u16.to_le_bytes()); // dmin = 0.5
            for i in 0..12 {
                buf[off + 4 + i] =
                    ((seed.wrapping_add(b as u32 * 11).wrapping_add(i as u32 * 13)) & 0x3f) as u8;
            }
            for i in 0..32 {
                buf[off + 16 + i] =
                    (seed.wrapping_mul(7).wrapping_add(b as u32).wrapping_add(i as u32 * 5) & 0xff)
                        as u8;
            }
            for i in 0..128 {
                let lo = ((seed.wrapping_add(b as u32 * 31).wrapping_add(i as u32)) & 0x0f) as u8;
                let hi =
                    ((seed.wrapping_add(b as u32 * 17).wrapping_add(i as u32 * 3)) & 0x0f) as u8;
                buf[off + 48 + i] = (hi << 4) | lo;
            }
        }
        buf
    }

    #[test]
    fn mat_vec_q5k_matches_dequant_then_dot_reference() {
        // `dequantize_q5k_row` is the numeric source of truth; the fused
        // NEON row kernel (and the parallel dequant+dot fallback) must match
        // it through both the serial (n <= RAYON_THRESHOLD) and rayon arms.
        for &(n, d) in &[(32usize, 256usize), (16, 512), (300, 256)] {
            let bpr = d / 256;
            let w = synth_q5k_blocks(n * bpr, 0x5c0ffee5);
            let x: Vec<f32> = (0..d).map(|i| ((i as f32) * 0.011 - 0.4).sin()).collect();

            let mut out_kernel = vec![0.0f32; n];
            mat_vec_q5k(&mut out_kernel, &x, &w, n, d);

            let mut row_buf = vec![0.0f32; d];
            for i in 0..n {
                dequantize_q5k_row(&mut row_buf, &w, i, d);
                let reference: f32 = row_buf.iter().zip(&x).map(|(a, b)| a * b).sum();
                let diff = (out_kernel[i] - reference).abs();
                // Relative gate: the synthetic scales make |out| land in the
                // tens of thousands, so an absolute epsilon is meaningless.
                assert!(
                    diff < 1e-5 * reference.abs().max(1.0),
                    "n={n} d={d} row {i}: kernel={} reference={} |Δ|={}",
                    out_kernel[i],
                    reference,
                    diff
                );
            }
        }
    }

    /// Run explicitly: `cargo test --release q5k_fused_vs_serial_microbench -- --ignored --nocapture`
    #[test]
    #[ignore]
    fn q5k_fused_vs_serial_microbench() {
        // Old dispatch path: SERIAL dequantize_q5k_row + dot per row.
        let (n, d) = (896usize, 4864usize);
        let w = synth_q5k_blocks(n * d / 256, 0x5eed);
        let x: Vec<f32> = (0..d).map(|i| ((i as f32) * 0.011 - 0.4).sin()).collect();
        let mut out = vec![0.0f32; n];
        let iters = 10;

        let t = std::time::Instant::now();
        for _ in 0..iters {
            let mut row_buf = vec![0.0f32; d];
            for i in 0..n {
                dequantize_q5k_row(&mut row_buf, &w, i, d);
                out[i] = dot_product(&row_buf, &x);
            }
        }
        let serial = t.elapsed();
        let t = std::time::Instant::now();
        for _ in 0..iters {
            mat_vec_q5k(&mut out, &x, &w, n, d);
        }
        let fused = t.elapsed();
        println!(
            "q5k serial dequant+dot: {:.2} ms/call   mat_vec_q5k: {:.2} ms/call   speedup {:.1}x",
            serial.as_secs_f64() * 1e3 / iters as f64,
            fused.as_secs_f64() * 1e3 / iters as f64,
            serial.as_secs_f64() / fused.as_secs_f64()
        );
    }

    #[test]
    fn batch_kernels_match_single_row_reference() {
        // The dequant-once batch arms (n_batch >= BATCH_DEQUANT_ONCE_MIN)
        // must agree with the per-lane fused kernels they replaced.
        let d = 512usize;
        let n = 24usize;
        let n_batch = 6usize;
        let xs_owned: Vec<Vec<f32>> = (0..n_batch)
            .map(|t| {
                (0..d)
                    .map(|i| (((i + t * 41) as f32) * 0.009 - 0.3).cos())
                    .collect()
            })
            .collect();
        let xs: Vec<&[f32]> = xs_owned.iter().map(|v| v.as_slice()).collect();

        // Q6_K
        let w6 = synth_q6k_blocks(n * d / 256, 0x600dcafe);
        let mut outs: Vec<Vec<f32>> = vec![vec![0.0f32; n]; n_batch];
        {
            let mut out_refs: Vec<&mut [f32]> = outs.iter_mut().map(|v| v.as_mut_slice()).collect();
            mat_vec_q6k_batch(&mut out_refs, &xs, &w6, n, d);
        }
        for t in 0..n_batch {
            let mut single = vec![0.0f32; n];
            mat_vec_q6k(&mut single, xs[t], &w6, n, d);
            for i in 0..n {
                let diff = (outs[t][i] - single[i]).abs();
                assert!(diff < 1e-3, "q6k lane {t} row {i}: {} vs {}", outs[t][i], single[i]);
            }
        }

        // Q8_0
        let bpr8 = d.div_ceil(32);
        let mut w8 = vec![0u8; n * bpr8 * 34];
        for (block_idx, block) in w8.chunks_mut(34).enumerate() {
            block[0..2].copy_from_slice(&0x3c00u16.to_le_bytes());
            for (i, q) in block[2..34].iter_mut().enumerate() {
                *q = (i as u8).wrapping_mul(11).wrapping_add((block_idx % 127) as u8);
            }
        }
        let mut outs8: Vec<Vec<f32>> = vec![vec![0.0f32; n]; n_batch];
        {
            let mut out_refs: Vec<&mut [f32]> =
                outs8.iter_mut().map(|v| v.as_mut_slice()).collect();
            mat_vec_q8_0_batch(&mut out_refs, &xs, &w8, n, d);
        }
        for t in 0..n_batch {
            let mut single = vec![0.0f32; n];
            mat_vec_q8_0(&mut single, xs[t], &w8, n, d);
            for i in 0..n {
                let diff = (outs8[t][i] - single[i]).abs();
                assert!(diff < 1e-3, "q8_0 lane {t} row {i}: {} vs {}", outs8[t][i], single[i]);
            }
        }

        // Q5_0
        let bpr5 = d.div_ceil(32);
        let mut w5 = vec![0u8; n * bpr5 * 22];
        for (block_idx, block) in w5.chunks_mut(22).enumerate() {
            block[0..2].copy_from_slice(&0x3c00u16.to_le_bytes());
            let high =
                (0xa5a5_5a5au32 ^ (block_idx as u32).wrapping_mul(0x0101_0101)).to_le_bytes();
            block[2..6].copy_from_slice(&high);
            for (i, q) in block[6..22].iter_mut().enumerate() {
                *q = (i as u8).wrapping_mul(17).wrapping_add((block_idx % 251) as u8);
            }
        }
        let mut outs5: Vec<Vec<f32>> = vec![vec![0.0f32; n]; n_batch];
        {
            let mut out_refs: Vec<&mut [f32]> =
                outs5.iter_mut().map(|v| v.as_mut_slice()).collect();
            mat_vec_q5_0_batch(&mut out_refs, &xs, &w5, n, d);
        }
        for t in 0..n_batch {
            let mut single = vec![0.0f32; n];
            mat_vec_q5_0(&mut single, xs[t], &w5, n, d);
            for i in 0..n {
                let diff = (outs5[t][i] - single[i]).abs();
                assert!(diff < 1e-3, "q5_0 lane {t} row {i}: {} vs {}", outs5[t][i], single[i]);
            }
        }
    }

    #[test]
    fn mat_vec_q6k_matches_reference_qwen_lm_head_shape() {
        // qwen-coder-7b lm_head shape: hidden_dim=3584, single shard row count
        // sized small to keep the test fast (2 blocks per row × ~16 rows).
        let n = 16;
        let d = 512; // 2 blocks per row
        let bpr = d / 256;
        let w = synth_q6k_blocks(n * bpr, 0x9e3779b9);
        let x: Vec<f32> = (0..d).map(|i| ((i as f32) * 0.007 + 0.13).cos()).collect();

        let mut out_dispatch = vec![0.0f32; n];
        let mut out_reference = vec![0.0f32; n];
        mat_vec_q6k(&mut out_dispatch, &x, &w, n, d);
        reference_mat_vec_q6k(&mut out_reference, &x, &w, n, d);

        for i in 0..n {
            let diff = (out_dispatch[i] - out_reference[i]).abs();
            assert!(
                diff < 1e-3,
                "row {}: dispatch={} reference={} |Δ|={}",
                i,
                out_dispatch[i],
                out_reference[i],
                diff
            );
        }
    }
}

// ─────────────────────────────────────────────────────────────────────────
// Q5_0 mat_vec parity tests (Wave 12 AVX2 x86 FFN row)
// ─────────────────────────────────────────────────────────────────────────
#[cfg(test)]
mod q5_0_matvec_tests {
    use super::*;

    fn synth_q5_0_rows(rows: usize, cols: usize, seed: u32) -> Vec<u8> {
        let bpr = cols.div_ceil(32);
        let mut buf = vec![0u8; rows * bpr * 22];
        for row in 0..rows {
            for block in 0..bpr {
                let off = (row * bpr + block) * 22;
                let scale_f16: u16 = 0x2c00; // 0.0625
                buf[off] = (scale_f16 & 0xff) as u8;
                buf[off + 1] = (scale_f16 >> 8) as u8;
                // qh (4 bytes) + qs (16 bytes), pseudo-random
                for k in 0..20 {
                    let raw = seed
                        .wrapping_add(row as u32 * 131)
                        .wrapping_add(block as u32 * 71)
                        .wrapping_add(k as u32 * 17)
                        .wrapping_mul(2654435761);
                    buf[off + 2 + k] = (raw >> 13) as u8;
                }
            }
        }
        buf
    }

    fn reference_mat_vec_q5_0(out: &mut [f32], x: &[f32], w: &[u8], n: usize, d: usize) {
        let mut row = vec![0.0f32; d];
        for i in 0..n {
            dequantize_q5_0_row(&mut row, w, i, d);
            out[i] = row.iter().zip(x.iter()).map(|(a, b)| a * b).sum();
        }
    }

    // Pure-Rust model of the AVX2 lane mapping (chunk -> index -> qh bit), arch
    // independent so it validates the x86 AVX2 decode logic even on aarch64 hosts.
    fn model_avx2_q5_0(x: &[f32], w: &[u8], n: usize, d: usize) -> Vec<f32> {
        let bpr = d.div_ceil(32);
        let mut out = vec![0.0f32; n];
        for i in 0..n {
            let row_off = i * bpr * 22;
            let mut total = 0.0f32;
            for b in 0..bpr {
                let off = row_off + b * 22;
                let d_val = f16_to_f32(u16::from_le_bytes([w[off], w[off + 1]]));
                let qh = (w[off + 2] as u32)
                    | ((w[off + 3] as u32) << 8)
                    | ((w[off + 4] as u32) << 16)
                    | ((w[off + 5] as u32) << 24);
                let qs = &w[off + 6..off + 22];
                let xo = b * 32;
                if xo + 32 > d {
                    continue;
                }
                let mut acc = 0.0f32;
                // chunk0: idx 0..7 low nibbles bytes 0..7, qh bits 0..7
                // chunk1: idx 8..15 low nibbles bytes 8..15, qh bits 8..15
                // chunk2: idx 16..23 high nibbles bytes 0..7, qh bits 16..23
                // chunk3: idx 24..31 high nibbles bytes 8..15, qh bits 24..31
                for (base, byte_base, hi_nib) in
                    [(0usize, 0usize, false), (8, 8, false), (16, 0, true), (24, 8, true)]
                {
                    let qsh = qh >> base;
                    for lane in 0..8 {
                        let byte = qs[byte_base + lane];
                        let nib = if hi_nib { (byte >> 4) & 0x0f } else { byte & 0x0f } as i32;
                        let bit = ((qsh >> lane) & 1) as i32;
                        let q = nib + 16 * bit - 16;
                        acc += x[xo + base + lane] * q as f32;
                    }
                }
                total += d_val * acc;
            }
            out[i] = total;
        }
        out
    }

    #[test]
    fn mat_vec_q5_0_matches_dequant_then_dot_reference() {
        let (n, d) = (40usize, 128usize);
        let w = synth_q5_0_rows(n, d, 7);
        let x: Vec<f32> = (0..d).map(|i| ((i * 13 % 23) as f32 - 11.0) * 0.05).collect();
        let mut got = vec![0.0f32; n];
        let mut want = vec![0.0f32; n];
        mat_vec_q5_0(&mut got, &x, &w, n, d);
        reference_mat_vec_q5_0(&mut want, &x, &w, n, d);
        let dot: f32 = got.iter().zip(want.iter()).map(|(a, b)| a * b).sum();
        let na: f32 = got.iter().map(|a| a * a).sum::<f32>().sqrt();
        let nb: f32 = want.iter().map(|b| b * b).sum::<f32>().sqrt();
        let cos = dot / (na * nb + 1e-12);
        assert!(cos > 0.9999, "cosine {cos} too low (got vs dequant ref)");
    }

    #[test]
    fn avx2_lane_model_matches_scalar() {
        // Validates the AVX2 chunk/index/qh-bit mapping against the scalar path,
        // independent of the host SIMD ISA.
        let (n, d) = (32usize, 96usize);
        let w = synth_q5_0_rows(n, d, 99);
        let x: Vec<f32> = (0..d).map(|i| ((i * 7 % 19) as f32 - 9.0) * 0.1).collect();
        let mut scalar = vec![0.0f32; n];
        reference_mat_vec_q5_0(&mut scalar, &x, &w, n, d);
        let modeled = model_avx2_q5_0(&x, &w, n, d);
        for i in 0..n {
            assert!(
                (scalar[i] - modeled[i]).abs() < 1e-3,
                "row {i}: scalar={} avx2_model={}",
                scalar[i],
                modeled[i]
            );
        }
    }
}

#[cfg(test)]
mod gemma4_golden_diff_tests {
    //! Op-by-op golden diff of the gemma4 forward kernels against the
    //! Paris-producing TS reference `open-source/aether/src/gcp-layer-node.ts`.
    //! Each reference fn below is a faithful port of the corresponding aether
    //! routine; the test asserts the gnosis Rust kernel matches it on a fixed
    //! probe. The final test quantifies the attention-scale divergence that was
    //! the remaining gemma4-12b forward bug (scale=1.0 vs the golden
    //! 1/sqrt(head_dim)).
    use super::*;

    // aether SIMDFallback.rmsNorm: result[i] = (x[i]/rms)*weight[i]  (RAW weight)
    fn aether_rms_norm(x: &[f32], w: &[f32], eps: f32) -> Vec<f32> {
        let mut sum_sq = 0.0f32;
        for &v in x {
            sum_sq += v * v;
        }
        let rms = (sum_sq / x.len() as f32 + eps).sqrt();
        x.iter().zip(w).map(|(&xi, &wi)| (xi / rms) * wi).collect()
    }

    // aether gegluRmsNorm activation: gelu_tanh(gate) * up
    fn aether_geglu(gate: f32, up: f32) -> f32 {
        let c = (2.0f32 / std::f32::consts::PI).sqrt();
        let gelu = 0.5 * gate * (1.0 + (c * (gate + 0.044715 * gate * gate * gate)).tanh());
        gelu * up
    }

    #[test]
    fn rmsnorm_raw_weight_matches_aether() {
        // gemma4 (arch != "gemma3") uses RAW weight — same as aether.
        let x = [0.5f32, -1.2, 3.0, 0.1, -0.7, 2.2, -0.3, 1.1];
        let w = [1.02f32, 0.98, 1.10, 0.90, 1.05, 0.95, 1.00, 1.07];
        let eps = 1e-6;
        let mut got = vec![0.0f32; x.len()];
        gemma_rms_norm(&mut got, &x, &w, eps, /*shift_by_one=*/ false);
        let want = aether_rms_norm(&x, &w, eps);
        for (i, (&g, &r)) in got.iter().zip(&want).enumerate() {
            assert!((g - r).abs() < 1e-6, "rmsnorm idx {i}: {g} vs {r}");
        }
    }

    #[test]
    fn geglu_matches_aether_gelu_tanh() {
        let gate = [0.3f32, -1.5, 2.0, 0.0, -0.2, 4.0];
        let up = [1.1f32, 0.5, -0.7, 2.0, 1.0, -1.3];
        let mut g = gate;
        gelu_glu_inplace(&mut g, &up);
        for i in 0..gate.len() {
            let want = aether_geglu(gate[i], up[i]);
            assert!((g[i] - want).abs() < 1e-6, "geglu idx {i}: {} vs {want}", g[i]);
        }
    }

    #[test]
    fn softcap_is_monotonic_argmax_preserving() {
        // The reference omits the final logit softcap; gnosis applies tanh
        // cap=30. Because tanh(x/c)*c is strictly increasing, argmax is
        // identical — so the softcap can NOT explain the 45518/236xxx
        // oscillation. This guards that reasoning.
        let mut logits = [5.0f32, 31.0, -2.0, 29.9, 100.0, 30.1];
        let pre_argmax = logits
            .iter()
            .enumerate()
            .max_by(|a, b| a.1.partial_cmp(b.1).unwrap())
            .unwrap()
            .0;
        tanh_softcap(&mut logits, 30.0);
        let post_argmax = logits
            .iter()
            .enumerate()
            .max_by(|a, b| a.1.partial_cmp(b.1).unwrap())
            .unwrap()
            .0;
        assert_eq!(pre_argmax, post_argmax, "softcap must preserve argmax");
    }

    #[test]
    fn attn_scale_1p0_oversaturates_vs_golden_inv_sqrt_headdim() {
        // THE FIX. Build a tiny single-head attention over a few cached keys.
        // With the golden scale (1/sqrt(head_dim)) the softmax stays soft;
        // with the buggy scale=1.0 it collapses to ~one-hot. The over-sharp
        // distribution is what tipped the readout onto high-norm tied-embed
        // rows (236xxx), oscillating with the sane token.
        let head_dim = 256usize;
        // Post-q_norm/k_norm Q and K are ~unit-RMS per head, so per-element
        // values are O(1) and the raw Q·Kᵀ dot product is O(head_dim) — this
        // is exactly why the 1/sqrt(head_dim) temperature is required and why
        // omitting it (scale=1.0) over-sharpens. Use ~unit-RMS probes with a
        // small per-key alignment spread.
        let q: Vec<f32> = (0..head_dim).map(|i| ((i % 5) as f32 - 2.0) * 0.7).collect();
        let mk_key = |bias: f32| -> Vec<f32> {
            (0..head_dim)
                .map(|i| ((i % 5) as f32 - 2.0) * 0.7 * bias)
                .collect()
        };
        // Keys differ modestly in alignment with q (0.85..1.0).
        let keys = [mk_key(0.90), mk_key(0.95), mk_key(1.00), mk_key(0.85)];

        let scores_raw: Vec<f32> = keys.iter().map(|k| dot_product(&q, k)).collect();

        let golden_scale = 1.0 / (head_dim as f32).sqrt();
        let buggy_scale = 1.0f32;

        let mut golden: Vec<f32> = scores_raw.iter().map(|s| s * golden_scale).collect();
        let mut buggy: Vec<f32> = scores_raw.iter().map(|s| s * buggy_scale).collect();
        softmax(&mut golden);
        softmax(&mut buggy);

        let golden_max = golden.iter().cloned().fold(0.0f32, f32::max);
        let buggy_max = buggy.iter().cloned().fold(0.0f32, f32::max);

        // Golden distribution is soft (top weight well under 1); buggy is
        // saturated (top weight effectively one-hot).
        assert!(
            golden_max < 0.6,
            "golden softmax should stay soft, got top={golden_max}"
        );
        assert!(
            buggy_max > 0.95,
            "buggy scale=1.0 softmax should over-saturate, got top={buggy_max}"
        );
        // The fix multiplies scores by 1/sqrt(head_dim); confirm that is the
        // value now used by the kernel for a head_dim=256 layer.
        assert!((golden_scale - 0.0625).abs() < 1e-6);
    }

    // ── RoPE global-vs-local golden diff ─────────────────────────────────
    //
    // Faithful port of aether `applyRoPE` (gcp-layer-node.ts:1076, NEOX
    // branch) WITH the Gemma3/Gemma4 global-layer position scaling:
    //   scaledPosition = position / ropeScalingFactor   (line 1086)
    // applied with the per-layer factor from the call site (line 3110):
    //   layerScaling = isGemma3 && isGlobalLayer ? ropeScalingFactor : 1.0
    // i.e. GLOBAL layers divide the position by 8.0, LOCAL layers by 1.0.
    fn aether_apply_rope_neox(
        x: &[f32],
        position: usize,
        head_dim: usize,
        num_heads: usize,
        theta: f32,
        rope_scaling_factor: f32,
    ) -> Vec<f32> {
        let scaled_position = position as f32 / rope_scaling_factor;
        let half = head_dim / 2;
        let mut out = x.to_vec();
        // freqs[k] = 1 / theta^(2k/head_dim)
        for h in 0..num_heads {
            let head_start = h * head_dim;
            for k in 0..half {
                let freq = 1.0f32 / theta.powf((2 * k) as f32 / head_dim as f32);
                let angle = scaled_position * freq;
                let (sin, cos) = angle.sin_cos();
                let x0 = x[head_start + k];
                let x1 = x[head_start + k + half];
                out[head_start + k] = x0 * cos - x1 * sin;
                out[head_start + k + half] = x1 * cos + x0 * sin;
            }
        }
        out
    }

    // A probe Q/K vector with a deterministic per-element pattern.
    fn rope_probe(num_heads: usize, head_dim: usize) -> Vec<f32> {
        (0..num_heads * head_dim)
            .map(|i| ((i % 7) as f32 - 3.0) * 0.31 + 0.05)
            .collect()
    }

    #[test]
    fn rope_cached_matches_rope() {
        // The llama-interleaved cached path reads angles computed from the
        // same formula as the live-trig path. Empirically the two contexts
        // can differ by an ulp in the transcendental results (measured on
        // aarch64 at pos=31: last-digit-only diffs), so the gate is the
        // repo-standard tight relative tolerance, not bit equality.
        let (num_heads, num_kv_heads, head_dim) = (4usize, 2usize, 64usize);
        let theta = 10_000.0f32;
        let table = precompute_rope_table(128, head_dim, theta);
        let close = |a: f32, b: f32| (a - b).abs() <= 1e-6 * a.abs().max(b.abs()).max(1e-3);
        for &pos in &[0usize, 1, 7, 31, 127] {
            let mut q_a = rope_probe(num_heads, head_dim);
            let mut k_a = rope_probe(num_kv_heads, head_dim);
            let mut q_b = q_a.clone();
            let mut k_b = k_a.clone();
            rope(&mut q_a, &mut k_a, pos, num_heads, num_kv_heads, head_dim, theta);
            rope_cached(&mut q_b, &mut k_b, pos, num_heads, num_kv_heads, head_dim, &table);
            for i in 0..q_a.len() {
                assert!(close(q_a[i], q_b[i]), "q[{i}] at pos={pos}: {} vs {}", q_a[i], q_b[i]);
            }
            for i in 0..k_a.len() {
                assert!(close(k_a[i], k_b[i]), "k[{i}] at pos={pos}: {} vs {}", k_a[i], k_b[i]);
            }
        }
    }

    // AVX2 activation-kernel parity: certifies softmax/rms_norm/swiglu AVX2
    // arms against the scalar references. Compiled for x86_64 only (runs on
    // the Cloud Run / CI hosts these paths serve); the runtime dispatch in
    // each function picks the AVX2 arm there automatically.
    #[cfg(target_arch = "x86_64")]
    #[test]
    fn avx2_activation_kernels_match_scalar() {
        if !(is_x86_feature_detected!("avx2") && is_x86_feature_detected!("fma")) {
            return; // nothing to certify on pre-AVX2 hosts
        }
        let n = 1027usize; // odd length exercises every tail loop
        let src: Vec<f32> = (0..n).map(|i| ((i % 23) as f32 - 11.0) * 0.37).collect();

        // softmax
        let mut a = src.clone();
        unsafe { softmax_avx2(&mut a) };
        let mut b = src.clone();
        let m = b.iter().cloned().fold(f32::NEG_INFINITY, f32::max);
        let mut sum = 0.0f32;
        for v in b.iter_mut() {
            *v = (*v - m).exp();
            sum += *v;
        }
        for v in b.iter_mut() {
            *v /= sum;
        }
        for i in 0..n {
            assert!((a[i] - b[i]).abs() < 1e-6, "softmax lane {i}: {} vs {}", a[i], b[i]);
        }

        // rms_norm (dispatches to the AVX2 arms internally)
        let w: Vec<f32> = (0..n).map(|i| 1.0 + (i % 5) as f32 * 0.1).collect();
        let mut out_simd = vec![0.0f32; n];
        rms_norm(&mut out_simd, &src, &w, 1e-5);
        let sum_sq: f64 = src.iter().map(|&v| (v as f64) * (v as f64)).sum();
        let inv = 1.0 / ((sum_sq / n as f64) as f32 + 1e-5).sqrt();
        for i in 0..n {
            let reference = src[i] * inv * w[i];
            assert!(
                (out_simd[i] - reference).abs() < 1e-3 * reference.abs().max(1.0),
                "rms_norm lane {i}: {} vs {}",
                out_simd[i],
                reference
            );
        }

        // swiglu
        let up: Vec<f32> = (0..n).map(|i| ((i % 13) as f32 - 6.0) * 0.21).collect();
        let mut gate_simd = src.clone();
        unsafe { swiglu_avx2(&mut gate_simd, &up) };
        for i in 0..n {
            let x = src[i];
            let reference = (x / (1.0 + (-x).exp())) * up[i];
            assert!(
                (gate_simd[i] - reference).abs() < 1e-4 * reference.abs().max(1.0),
                "swiglu lane {i}: {} vs {}",
                gate_simd[i],
                reference
            );
        }
    }

    /// Run explicitly: `cargo test --release rope_cached_microbench -- --ignored --nocapture`
    #[test]
    #[ignore]
    fn rope_cached_microbench() {
        // Mistral-7B decode shape: 32 layers × (32 q heads + 8 kv heads),
        // head_dim 128 → 64 powf+sin_cos pairs per layer per token uncached.
        let (num_heads, num_kv_heads, head_dim) = (32usize, 8usize, 128usize);
        let theta = 10_000.0f32;
        let layers = 32usize;
        let tokens = 200usize;
        let table = precompute_rope_table(tokens, head_dim, theta);
        let mut q = rope_probe(num_heads, head_dim);
        let mut k = rope_probe(num_kv_heads, head_dim);

        let t = std::time::Instant::now();
        for pos in 0..tokens {
            for _ in 0..layers {
                rope(&mut q, &mut k, pos, num_heads, num_kv_heads, head_dim, theta);
            }
        }
        let live = t.elapsed();
        let t = std::time::Instant::now();
        for pos in 0..tokens {
            for _ in 0..layers {
                rope_cached(&mut q, &mut k, pos, num_heads, num_kv_heads, head_dim, &table);
            }
        }
        let cached = t.elapsed();
        println!(
            "rope live-trig: {:.1} us/token   rope_cached: {:.1} us/token   speedup {:.2}x",
            live.as_secs_f64() * 1e6 / tokens as f64,
            cached.as_secs_f64() * 1e6 / tokens as f64,
            live.as_secs_f64() / cached.as_secs_f64()
        );
        assert!(q.iter().all(|v| v.is_finite()));
    }

    #[test]
    fn rope_global_position_scaling_matches_aether_div8() {
        // Global gemma4 layer: head_dim=512, theta=1e6, ropeScalingFactor=8.0.
        // The Rust cached table is built via precompute_rope_table_scaled with
        // pos_scale=8.0, exactly the aether `position / ropeScalingFactor` op.
        let head_dim = 512usize;
        let num_heads = 2usize;
        let num_kv_heads = 1usize;
        let theta = 1_000_000.0f32;
        let scaling = 8.0f32;
        let max_seq = 64usize;

        let table = precompute_rope_table_scaled(max_seq, head_dim, theta, scaling);

        for &pos in &[0usize, 1, 7, 17, 50] {
            let q0 = rope_probe(num_heads, head_dim);
            let k0 = rope_probe(num_kv_heads, head_dim);
            let mut q = q0.clone();
            let mut k = k0.clone();
            rope_neox_cached(&mut q, &mut k, pos, num_heads, num_kv_heads, head_dim, &table);

            let want_q =
                aether_apply_rope_neox(&q0, pos, head_dim, num_heads, theta, scaling);
            let want_k =
                aether_apply_rope_neox(&k0, pos, head_dim, num_kv_heads, theta, scaling);
            for (i, (&g, &r)) in q.iter().zip(&want_q).enumerate() {
                assert!(
                    (g - r).abs() < 2e-4,
                    "global cached Q pos={pos} idx {i}: {g} vs {r}"
                );
            }
            for (i, (&g, &r)) in k.iter().zip(&want_k).enumerate() {
                assert!(
                    (g - r).abs() < 2e-4,
                    "global cached K pos={pos} idx {i}: {g} vs {r}"
                );
            }

            // The non-cached fallback (rope_neox_f at the scaled float pos)
            // must agree with the same reference.
            let mut qf = q0.clone();
            let mut kf = k0.clone();
            let pos_f = pos as f32 / scaling;
            rope_neox_f(&mut qf, &mut kf, pos_f, num_heads, num_kv_heads, head_dim, theta);
            for (i, (&g, &r)) in qf.iter().zip(&want_q).enumerate() {
                assert!(
                    (g - r).abs() < 2e-4,
                    "global float Q pos={pos} idx {i}: {g} vs {r}"
                );
            }
        }
    }

    #[test]
    fn rope_local_layer_uses_no_position_scaling() {
        // Local/sliding gemma4 layer: head_dim=256, theta=10_000, NO scaling
        // (factor 1.0). The local table is built with pos_scale=1.0.
        let head_dim = 256usize;
        let num_heads = 2usize;
        let num_kv_heads = 1usize;
        let theta = 10_000.0f32;
        let max_seq = 64usize;

        let table = precompute_rope_table(max_seq, head_dim, theta); // pos_scale=1.0
        for &pos in &[0usize, 3, 11, 40] {
            let q0 = rope_probe(num_heads, head_dim);
            let k0 = rope_probe(num_kv_heads, head_dim);
            let mut q = q0.clone();
            let mut k = k0.clone();
            rope_neox_cached(&mut q, &mut k, pos, num_heads, num_kv_heads, head_dim, &table);

            // Reference with ropeScalingFactor = 1.0 (local layer).
            let want_q = aether_apply_rope_neox(&q0, pos, head_dim, num_heads, theta, 1.0);
            for (i, (&g, &r)) in q.iter().zip(&want_q).enumerate() {
                assert!(
                    (g - r).abs() < 2e-4,
                    "local cached Q pos={pos} idx {i}: {g} vs {r}"
                );
            }
        }
    }

    #[test]
    fn rope_global_scaling_is_distinguishable_from_unscaled() {
        // Guard the BUG: if the global table is built WITHOUT the ÷8.0 scaling
        // (the pre-fix behaviour), it diverges sharply from the reference for
        // any non-trivial position. This is the divergence that collapsed
        // positional information and produced the single-token repetition loop.
        let head_dim = 512usize;
        let num_heads = 1usize;
        let theta = 1_000_000.0f32;
        let scaling = 8.0f32;
        let max_seq = 64usize;
        let pos = 40usize;

        let buggy_table = precompute_rope_table(max_seq, head_dim, theta); // NO scaling
        let q0 = rope_probe(num_heads, head_dim);
        let mut q = q0.clone();
        let mut k = vec![0f32; head_dim];
        rope_neox_cached(&mut q, &mut k, pos, num_heads, 0, head_dim, &buggy_table);

        let want = aether_apply_rope_neox(&q0, pos, head_dim, num_heads, theta, scaling);
        let max_dev = q
            .iter()
            .zip(&want)
            .map(|(&g, &r)| (g - r).abs())
            .fold(0.0f32, f32::max);
        assert!(
            max_dev > 0.1,
            "unscaled global RoPE must visibly diverge from the ÷8.0 reference; max_dev={max_dev}"
        );
    }

    // ── RoPE rotation-EXTENT (n_rot) golden diff ─────────────────────────
    //
    // The Paris-producing reference `open-source/aether/src/gcp-layer-node.ts`
    // applies RoPE over the FULL `headDim` on every gemma layer — sliding AND
    // global (applyRoPE rotates `head_dim/2` pairs for the whole head; the
    // attention path never consults `ropePartialFactor`). So for any gemma4
    // knot whose config reports a partial factor of 1.0 (full rotation), the
    // kernel must rotate ALL `head_dim` dims, i.e. `n_rot == head_dim`.
    //
    // This guards the bug fixed 2026-06-22 in `model_gemma4::layer_rope_n_rot`:
    // a `Some(1.0) → Some(0.25)` rewrite mis-rotated only the first 25% of each
    // global head, leaving 75% of the Q/K phase un-rotated. That collapsed
    // positional discrimination on the long-range (global) layers → flat
    // attention → input-blind / position-blind single-token repetition, and was
    // invariant to the attn_scale + ÷8 position-scaling fixes because the
    // rotation EXTENT (not the angle) was wrong.
    //
    // Pure port of the post-fix `layer_rope_n_rot` decision for a GLOBAL layer.
    fn n_rot_for_global(head_dim: usize, rope_partial_factor: Option<f32>) -> usize {
        match rope_partial_factor {
            Some(f) if f > 0.0 && f < 1.0 => {
                let n = ((head_dim as f32) * f) as usize;
                n & !1
            }
            _ => head_dim,
        }
    }

    #[test]
    fn rope_partial_factor_one_means_full_rotation_matches_aether() {
        // factor == 1.0 ⇒ rotate the whole head (matches aether's full-headDim
        // RoPE). The pre-fix code rewrote this to 0.25 and only rotated 128.
        let head_dim = 512usize;
        assert_eq!(
            n_rot_for_global(head_dim, Some(1.0)),
            head_dim,
            "rope_partial_factor=1.0 must rotate the FULL head_dim (aether parity)"
        );
        // None (no partial RoPE configured) ⇒ also full rotation.
        assert_eq!(n_rot_for_global(head_dim, None), head_dim);

        // The full-rotation cached kernel must agree with the aether reference
        // across the ENTIRE head_dim — including the dims (128..512) that the
        // buggy 0.25 partial rotation would have left untouched.
        let num_heads = 2usize;
        let num_kv_heads = 1usize;
        let theta = 1_000_000.0f32;
        let scaling = 8.0f32;
        let max_seq = 64usize;
        let pos = 17usize;
        let table = precompute_rope_table_scaled(max_seq, head_dim, theta, scaling);
        let q0 = rope_probe(num_heads, head_dim);
        let k0 = rope_probe(num_kv_heads, head_dim);
        let mut q = q0.clone();
        let mut k = k0.clone();
        rope_neox_cached(&mut q, &mut k, pos, num_heads, num_kv_heads, head_dim, &table);
        let want_q = aether_apply_rope_neox(&q0, pos, head_dim, num_heads, theta, scaling);
        // Assert on the TAIL dims a 0.25 partial rotation would have skipped.
        for h in 0..num_heads {
            for d in (head_dim / 4)..head_dim {
                let i = h * head_dim + d;
                assert!(
                    (q[i] - want_q[i]).abs() < 2e-4,
                    "full-rotation tail dim {d} (head {h}) must match aether: {} vs {}",
                    q[i],
                    want_q[i]
                );
            }
        }
    }

    #[test]
    fn rope_genuine_partial_factor_is_honored() {
        // A real sub-1.0 factor (a knot that truly rotates only part of the
        // head) is still respected — the fix removes the 1.0 rewrite, not the
        // partial-RoPE capability.
        assert_eq!(n_rot_for_global(512, Some(0.25)), 128);
        assert_eq!(n_rot_for_global(256, Some(0.5)), 128);
        // Odd products round DOWN to an even count (RoPE rotates pairs).
        assert_eq!(n_rot_for_global(250, Some(0.5)), 124);
    }

    #[test]
    fn rope_partial_rotation_leaves_tail_unrotated_proving_extent_matters() {
        // Demonstrate WHY the 1.0→0.25 rewrite broke the model: a 0.25 partial
        // rotation leaves dims [n_rot..head_dim) identical to the input, so they
        // carry NO positional phase. Over the global (long-range) layers this
        // erases position information — the mechanism behind the repetition loop.
        let head_dim = 512usize;
        let n_rot = n_rot_for_global(head_dim, Some(0.25));
        assert_eq!(n_rot, 128);
        // NEOX rotates pairs (k, k + head_dim/2) for k < n_rot/2. With n_rot=128
        // the rotated index set is {0..64} ∪ {256..320}; everything else is a
        // straight copy. Confirm a tail index (e.g. 200) is untouched by partial
        // rotation but WOULD be rotated under full rotation.
        // NEOX rotates pairs (k, k + head_dim/2) for k < n_rot/2. With n_rot=128
        // the rotated low-half index set is {0..64}; index k=80 (head_dim/4 +16)
        // is NOT rotated by the 0.25 partial path but IS under full rotation.
        // Use the LOCAL theta (10_000) + no position scaling so the k=80 angle is
        // large enough to move visibly: angle = pos / theta^(2k/head_dim).
        let theta = 10_000.0f32;
        let pos = 40usize;
        let q0 = rope_probe(1, head_dim);
        let k_idx = 80usize; // > n_rot/2 (64) ⇒ skipped by 0.25 partial rotation

        // Full rotation (factor 1.0, no scaling) moves dim k_idx.
        let full = aether_apply_rope_neox(&q0, pos, head_dim, 1, theta, 1.0);
        assert!(
            (full[k_idx] - q0[k_idx]).abs() > 1e-3,
            "full rotation must move dim {k_idx} (got {} vs {})",
            full[k_idx],
            q0[k_idx]
        );
    }
}

#[cfg(test)]
mod swiglu_simd_tests {
    use super::*;

    #[test]
    fn swiglu_inplace_matches_scalar() {
        let n = 14336usize;
        let mut s: u64 = 0xfeedface;
        let mut rng = || {
            s ^= s << 13;
            s ^= s >> 7;
            s ^= s << 17;
            ((s >> 32) as i32 as f32) / (i32::MAX as f32) * 8.0
        };
        let gate0: Vec<f32> = (0..n).map(|_| rng()).collect();
        let up: Vec<f32> = (0..n).map(|_| rng()).collect();
        // scalar reference
        let mut g_ref = gate0.clone();
        for i in 0..n {
            let x = g_ref[i];
            g_ref[i] = (x / (1.0 + (-x).exp())) * up[i];
        }
        // production (NEON on aarch64)
        let mut g = gate0.clone();
        swiglu_inplace(&mut g, &up);
        let (mut num, mut den) = (0.0f64, 0.0f64);
        for i in 0..n {
            let a = g_ref[i] as f64;
            num += (a - g[i] as f64).powi(2);
            den += a * a;
        }
        let rel = (num / den).sqrt();
        println!("[swiglu] rel-L2 NEON vs scalar = {rel:.2e}");
        assert!(rel < 1e-5, "swiglu SIMD must match scalar: rel={rel:.3e}");
    }
}

#[cfg(test)]
mod softmax_simd_tests {
    use super::*;
    use std::time::Instant;

    #[test]
    fn softmax_simd_matches_and_times() {
        let n = 1024usize; // attention over a 1024-key KV cache
        let mut s: u64 = 0xc0ffee;
        let mut rng = || {
            s ^= s << 13;
            s ^= s >> 7;
            s ^= s << 17;
            ((s >> 32) as i32 as f32) / (i32::MAX as f32) * 10.0
        };
        let base: Vec<f32> = (0..n).map(|_| rng()).collect();

        // scalar reference
        let mut r = base.clone();
        {
            let mut mx = r[0];
            for &v in r.iter() { if v > mx { mx = v; } }
            let mut sum = 0.0f32;
            for v in r.iter_mut() { let e = (*v - mx).exp(); *v = e; sum += e; }
            let inv = 1.0 / sum;
            for v in r.iter_mut() { *v *= inv; }
        }
        let mut y = base.clone();
        softmax(&mut y);
        let (mut num, mut den) = (0.0f64, 0.0f64);
        for i in 0..n { let a = r[i] as f64; num += (a - y[i] as f64).powi(2); den += a * a; }
        let rel = (num / den).sqrt();

        let reps = 20000u128;
        let scalar_softmax = |x: &mut [f32]| {
            let mut mx = x[0];
            for &v in x.iter() { if v > mx { mx = v; } }
            let mut sum = 0.0f32;
            for v in x.iter_mut() { let e = (*v - mx).exp(); *v = e; sum += e; }
            let inv = 1.0 / sum;
            for v in x.iter_mut() { *v *= inv; }
        };
        let mut z = base.clone();
        for _ in 0..50 { z.copy_from_slice(&base); softmax(&mut z); }
        let t = Instant::now();
        for _ in 0..reps { z.copy_from_slice(&base); scalar_softmax(&mut z); }
        let scal = t.elapsed().as_nanos() / reps;
        let t = Instant::now();
        for _ in 0..reps { z.copy_from_slice(&base); softmax(&mut z); }
        let neon = t.elapsed().as_nanos() / reps;
        println!(
            "[softmax] n={n} rel-L2={rel:.2e}  scalar {:.3}us  neon {:.3}us  speedup {:.2}x",
            scal as f64 / 1e3, neon as f64 / 1e3, scal as f64 / neon as f64
        );
        assert!(rel < 1e-5, "softmax SIMD must match scalar: rel={rel:.3e}");
    }
}

#[cfg(test)]
mod gelu_simd_tests {
    use super::*;
    use std::time::Instant;

    #[test]
    fn gelu_glu_matches_and_times() {
        const C: f32 = 0.7978845608028654;
        let n = 14336usize;
        let mut s: u64 = 0xbeef99;
        let mut rng = || { s ^= s << 13; s ^= s >> 7; s ^= s << 17; ((s >> 32) as i32 as f32) / (i32::MAX as f32) * 6.0 };
        let g0: Vec<f32> = (0..n).map(|_| rng()).collect();
        let up: Vec<f32> = (0..n).map(|_| rng()).collect();
        let scalar = |gate: &mut [f32], up: &[f32]| {
            for i in 0..gate.len() {
                let x = gate[i];
                let inner = C * (x + 0.044715 * x * x * x);
                gate[i] = (0.5 * x * (1.0 + inner.tanh())) * up[i];
            }
        };
        let mut r = g0.clone(); scalar(&mut r, &up);
        let mut y = g0.clone(); gelu_glu_inplace(&mut y, &up);
        let (mut num, mut den) = (0.0f64, 0.0f64);
        for i in 0..n { let a = r[i] as f64; num += (a - y[i] as f64).powi(2); den += a * a; }
        let rel = (num / den).sqrt();
        let reps = 4000u128;
        let mut z = g0.clone();
        for _ in 0..50 { z.copy_from_slice(&g0); gelu_glu_inplace(&mut z, &up); }
        let t = Instant::now();
        for _ in 0..reps { z.copy_from_slice(&g0); scalar(&mut z, &up); }
        let sc = t.elapsed().as_nanos() / reps;
        let t = Instant::now();
        for _ in 0..reps { z.copy_from_slice(&g0); gelu_glu_inplace(&mut z, &up); }
        let ne = t.elapsed().as_nanos() / reps;
        println!("[gelu] n={n} rel-L2={rel:.2e}  scalar {:.2}us  neon {:.2}us  speedup {:.2}x", sc as f64/1e3, ne as f64/1e3, sc as f64/ne as f64);
        assert!(rel < 1e-4, "gelu SIMD must match scalar: rel={rel:.3e}");
    }
}

#[cfg(test)]
mod rmsnorm_simd_tests {
    use super::*;
    #[test]
    fn rms_norm_matches_scalar() {
        for n in [4096usize, 3840, 2048, 100] {
            let mut s: u64 = 0xaa11 + n as u64;
            let mut rng = || { s ^= s << 13; s ^= s >> 7; s ^= s << 17; ((s >> 32) as i32 as f32) / (i32::MAX as f32) };
            let x: Vec<f32> = (0..n).map(|_| rng()).collect();
            let w: Vec<f32> = (0..n).map(|_| rng()).collect();
            let eps = 1e-5f32;
            // scalar reference
            let mut ss = 0.0f32;
            for &v in &x { ss += v * v; }
            let inv = 1.0 / (ss / n as f32 + eps).sqrt();
            let r: Vec<f32> = (0..n).map(|i| x[i] * inv * w[i]).collect();
            let mut o = vec![0.0f32; n];
            rms_norm(&mut o, &x, &w, eps);
            let (mut num, mut den) = (0.0f64, 0.0f64);
            for i in 0..n { let a = r[i] as f64; num += (a - o[i] as f64).powi(2); den += a * a; }
            let rel = (num / den).sqrt();
            assert!(rel < 1e-5, "rms_norm n={n} rel={rel:.3e}");
        }
        println!("[rms_norm] all sizes match scalar < 1e-5");
    }
}

#[cfg(test)]
mod norm_cluster_tests {
    use super::*;
    fn rng_vec(n: usize, seed: u64) -> Vec<f32> {
        let mut s = seed;
        (0..n).map(|_| { s ^= s << 13; s ^= s >> 7; s ^= s << 17; ((s >> 32) as i32 as f32) / (i32::MAX as f32) }).collect()
    }
    #[test]
    fn gemma_and_layernorm_match_scalar() {
        for &n in &[3840usize, 2048, 256, 73] {
            let x = rng_vec(n, 0x11 + n as u64);
            let w = rng_vec(n, 0x22 + n as u64);
            let b = rng_vec(n, 0x33 + n as u64);
            let eps = 1e-6f32;
            // gemma shifted ref
            let mut ss = 0.0f32; for &v in &x { ss += v*v; }
            let inv = 1.0/(ss/n as f32 + eps).sqrt();
            let gref: Vec<f32> = (0..n).map(|i| x[i]*inv*(1.0+w[i])).collect();
            let mut g = vec![0.0f32; n]; gemma_rms_norm(&mut g, &x, &w, eps, true);
            let rel_g = rel_l2(&gref, &g);
            // layernorm ref
            let mean: f32 = x.iter().sum::<f32>() / n as f32;
            let var: f32 = x.iter().map(|v| (v-mean)*(v-mean)).sum::<f32>() / n as f32;
            let li = 1.0/(var+eps).sqrt();
            let lref: Vec<f32> = (0..n).map(|i| (x[i]-mean)*li*w[i]+b[i]).collect();
            let mut l = vec![0.0f32; n]; layer_norm(&mut l, &x, &w, &b, eps);
            let rel_l = rel_l2(&lref, &l);
            assert!(rel_g < 1e-5, "gemma n={n} rel={rel_g:.3e}");
            assert!(rel_l < 1e-5, "layernorm n={n} rel={rel_l:.3e}");
        }
        println!("[norm-cluster] gemma_rms_norm + layer_norm match scalar < 1e-5 (4-acc)");
    }
    fn rel_l2(r: &[f32], y: &[f32]) -> f64 {
        let (mut num, mut den) = (0.0f64, 0.0f64);
        for i in 0..r.len() { let a = r[i] as f64; num += (a - y[i] as f64).powi(2); den += a*a; }
        (num/den.max(1e-30)).sqrt()
    }
}
